INSERT INTO "Character" ("id", "slug", "name", "characterType", "ownerUserId", "createdByUserId", "className", "race", "alignment", "background", "level", "portraitUrl", "archivedAt", "data", "createdAt", "updatedAt") VALUES ('aros', 'aros', 'Aros', 'PG', 'user_player_luigi_l', NULL, 'Guerriero', 'Umano', 'Caotico buono', 'Soldato', 5, 'public/portraits/aros.png', NULL, '{"slug":"aros","characterType":"pg","basicInfo":{"characterName":"Aros","class":"Guerriero","level":5,"background":"Soldato","playerName":"Luigi","race":"Umano","alignment":"Caotico buono","experiencePoints":0,"portraitUrl":"public/portraits/aros.png"},"abilityScores":{"strength":18,"dexterity":14,"constitution":16,"intelligence":11,"wisdom":14,"charisma":9},"combatStats":{"armorClass":21,"initiative":2,"speed":9,"hitPointMaximum":65,"currentHitPoints":65,"temporaryHitPoints":0,"hitDice":"1d10","deathSaves":{"successes":1,"failures":2},"spellSlots":{"1":[],"2":[],"3":[],"4":[],"5":[],"6":[],"7":[],"8":[{"id":1,"active":false},{"id":2,"active":false},{"id":3,"active":false},{"id":4,"active":false}],"9":[],"10":[],"11":[],"12":[]}},"proficiencies":{"savingThrows":["Forza","Costituzione"],"languages":["Comune","Nanico"],"skills":[{"name":"Acrobazia","ability":"dexterity","proficient":true},{"name":"Addestrare Animali","ability":"wisdom","proficient":false},{"name":"Arcano","ability":"intelligence","proficient":false},{"name":"Atletica","ability":"strength","proficient":true},{"name":"Inganno","ability":"charisma","proficient":false},{"name":"Storia","ability":"intelligence","proficient":false},{"name":"Intuizione","ability":"wisdom","proficient":false},{"name":"Intimidire","ability":"charisma","proficient":true},{"name":"Indagare","ability":"intelligence","proficient":false},{"name":"Medicina","ability":"wisdom","proficient":false},{"name":"Natura","ability":"intelligence","proficient":false},{"name":"Percezione","ability":"wisdom","proficient":true},{"name":"Intrattenere","ability":"charisma","proficient":false},{"name":"Persuasione","ability":"charisma","proficient":false},{"name":"Religione","ability":"intelligence","proficient":false},{"name":"Rapidità di Mano","ability":"dexterity","proficient":false},{"name":"Furtività","ability":"dexterity","proficient":false},{"name":"Sopravvivenza","ability":"wisdom","proficient":false}]},"equipment":{"attacks":[{"name":"Spada lunga","attackBonus":2,"damageType":"1d8 taglienti","equipped":false},{"name":"Pugnale","attackBonus":0,"damageType":"1d4 perforante","equipped":false},{"name":"Spada Lunga del Legame Sepolcrale","attackBonus":1,"damageDice":"1d8+1","damageType":"tagliente","hands":"1","category":"melee","equipped":true,"skillsByType":{"riposoLungo":[{"name":"Una volta per lungo riposo, se stai per scendere a 0 PF mentre impugni la spada, invece rimani a 1 PF.","used":false}]}},{"name":"Arco Lungo","attackBonus":0,"damageDice":"1d8","damageType":"perforante","category":"ranged","range":"45/180","equipped":true}],"coins":{"cp":0,"sp":50,"ep":0,"gp":53,"pp":0},"items":[{"type":"consumable","name":"Pozione Cura","quantity":2,"subtype":"potion","dice":"2d4+2"},{"type":"consumable","name":"Quadrelli","quantity":20,"subtype":"generic","dice":"2d4+2"},{"type":"consumable","name":"Frecce","quantity":20,"subtype":"generic","dice":"2d4+2"},{"type":"object","name":"Dotazione avventuriero","description":"Zaino - Piede di porco - Martello - 10 chiodi - 10 torce - Acciarino - Pietra focaia - Otre - 15m di corda","equippable":false},{"type":"object","name":"Ciondolo d''argento corroso","description":"Un semplice ciondolo d''argento molto vecchio.","equippable":false},{"type":"object","name":"1d12","description":"Pietra a 12 facce che sembra modificare l''ambiente circostante.","equippable":false},{"type":"object","name":"Guanto e anello","description":"Guanto e anello col simbolo del ragno.","equippable":false},{"type":"object","name":"Scudo borchiato","description":"CA: +2","equippable":true,"equipped":true},{"type":"object","name":"Cotta di maglia","description":"CA: 16","equippable":true,"equipped":false},{"type":"object","name":"Armatura completa","description":"CA: 18, svantaggio prove di destrezza","equippable":true,"equipped":true},{"type":"object","name":"1di8 (gear grinder)","description":"Comprendo che ha un funzionamento s8mike al d20 ma in qualche modo è più potente. Non si applica a consumabili, ma a armi e armature, ha durata 24 ore, lo si utilizza su un solo oggetto.","equippable":false,"equipped":false},{"type":"consumable","name":"Kit del guaritore","quantity":10,"subtype":"potion"}]},"features":[{"name":"Attacco Adescante (guerriero, Lv 0)","description":"Livello 0 · Manovra\nTempo di lancio: N/A (quando colpisci con un attacco)\nGittata: Bersaglio colpito\nComponenti: -\nDurata: Fino alla fine del tuo prossimo turno\n\nQuando il guerriero colpisce una\ncreatura con un attacco con un''arma, può spendere un\ndado di superiorità per indurre il bersaglio ad attaccarlo.\nIl guerriero aggiunge il dado di superiorità al tiro per i danni\ndell''attacco, e il bersaglio deve effettuare un tiro salvezza\nsu Saggezza. Se lo fallisce, il bersaglio subisce svantaggio\na tutti i tiri per colpire contro bersagli diversi dal guerriero\nfino alla fine del turno successivo del guerriero.\n\nUso: 1 dado di superiorità"},{"name":"Incoraggiamento (guerriero, Lv 0)","description":"Livello 0 · Manovra\nTempo di lancio: Azione bonus\nGittata: Alleato che ti vede o ti sente\nComponenti: -\nDurata: Istantanea\n\nNel proprio turno, il guerriero può\nusare un''azione bonus e spendere un dado di superiorità\nper incitare uno dei suoi compagni. Quando lo fa, sceglie\nuna creatura amica che sia in grado di vederlo o di sentirlo.\nQuella creatura ottiene un ammontare di punti ferita\ntemporanei pari al risultato del tiro del dado di superiorità\n+ il modificatore di Carisma del guerriero.\n\nUso: 1 dado di superiorità"},{"name":"Parata (guerriero, Lv 0)","description":"Livello 0 · Manovra\nTempo di lancio: Reazione (quando subisci danni da un attacco in mischia)\nGittata: Se stesso\nComponenti: -\nDurata: Istantanea\n\nQuando un''altra creatura infligge danni al\nguerriero con un attacco in mischia, il guerriero può usare\nla sua reazione e spendere un dado di superiorità per\nridurre i danni del numero ottenuto con il tiro del suo dado\ndi superiorità + il suo modificatore di Destrezza.\n\nUso: 1 dado di superiorità"}],"spells":[],"personalityTraits":"","ideals":"","bonds":"","flaws":"","backstory":"","capabilities":[{"name":"Azione Impetuosa","kind":"active","shortDescription":"Nel suo turno può effettuare un''azione aggiuntiva e una possibile azione bonus.","description":"A partire dal 2° livello, un guerriero può spingersi oltre i suoi normali limiti per un istante. Nel suo turno può effettuare un''azione aggiuntiva e una possibile azione bonus.\nUna volta utilizzato questo privilegio, il guerriero non può più utilizzarlo finché non completa un riposo breve o lungo. A partire dal 17° livello, il guerriero può utilizzare questo privilegio due volte prima di un riposo, ma soltanto una volta nello stesso turno.","usage":{"resetOn":"shortRest","used":[false]}},{"name":"Attacco Extra","kind":"passive","shortDescription":"Può attaccare 2 volte nel suo turno. Ulteriori attacchi extra all''11° e 20° livello.","description":"A partire dal 5° livello, un guerriero può attaccare due volte anziché una, ogni volta che effettua l''azione Attacco nel proprio turno.\nIl numero di attacchi aumenta a tre quando il guerriero arriva all''11° livello e a quattro quando arriva al 20° livello."},{"name":"Recuperare Energie","kind":"active","shortDescription":"Nel suo turno può usare un''azione bonus per recuperare un ammontare di punti ferita pari a 1d10 + il suo livello da guerriero.","description":"Un guerriero possiede una riserva limitata di resistenza fisica a cui può attingere per proteggersi dai danni. Nel suo turno può usare un''azione bonus per recuperare un ammontare di punti ferita pari a 1d10 + il suo livello da guerriero. Una volta utilizzato questo privilegio, il guerriero non può più utilizzarlo finché non completa un riposo breve o lungo.","usage":{"resetOn":"shortRest","used":[false]}}]}', '2026-03-30T12:19:16.121Z', '2026-03-30T14:16:43.527Z');
INSERT INTO "Character" ("id", "slug", "name", "characterType", "ownerUserId", "createdByUserId", "className", "race", "alignment", "background", "level", "portraitUrl", "archivedAt", "data", "createdAt", "updatedAt") VALUES ('narak', 'narak', 'Narak', 'PG', 'user_player_roberto', NULL, 'Bardo', 'Mezzelfo', 'Caotico neutrale', 'Ciarlatano', 5, '/portraits/narak-1774001008783.png', NULL, '{"slug":"narak","characterType":"pg","basicInfo":{"characterName":"Narak","class":"Bardo","level":5,"background":"Ciarlatano","playerName":"Roberto","race":"Mezzelfo","alignment":"Caotico neutrale","experiencePoints":0,"portraitUrl":"/portraits/narak-1774001008783.png"},"abilityScores":{"strength":12,"dexterity":14,"constitution":14,"intelligence":11,"wisdom":10,"charisma":18},"combatStats":{"armorClass":13,"initiative":5,"speed":9,"hitPointMaximum":50,"currentHitPoints":50,"temporaryHitPoints":0,"hitDice":"1d8","deathSaves":{"successes":0,"failures":0},"spellSlots":{"1":[{"id":1,"active":false},{"id":2,"active":false},{"id":3,"active":false},{"id":4,"active":false}],"2":[{"id":1,"active":false},{"id":2,"active":false},{"id":3,"active":false}],"3":[{"id":1,"active":false},{"id":2,"active":false}],"4":[],"5":[],"6":[],"7":[],"8":[],"9":[],"10":[],"11":[],"12":[]}},"proficiencies":{"savingThrows":["Destrezza","Carisma"],"languages":["Comune","Elfico","Abissale"],"skills":[{"name":"Acrobazia","ability":"dexterity","proficient":true},{"name":"Addestrare Animali","ability":"wisdom","proficient":false},{"name":"Arcano","ability":"intelligence","proficient":false},{"name":"Atletica","ability":"strength","proficient":false},{"name":"Inganno","ability":"charisma","proficient":true},{"name":"Storia","ability":"intelligence","proficient":false},{"name":"Intuizione","ability":"wisdom","proficient":false},{"name":"Intimidire","ability":"charisma","proficient":true},{"name":"Indagare","ability":"intelligence","proficient":false},{"name":"Medicina","ability":"wisdom","proficient":false},{"name":"Natura","ability":"intelligence","proficient":false},{"name":"Percezione","ability":"wisdom","proficient":false},{"name":"Intrattenere","ability":"charisma","proficient":true},{"name":"Persuasione","ability":"charisma","proficient":true},{"name":"Religione","ability":"intelligence","proficient":false},{"name":"Rapidità di Mano","ability":"dexterity","proficient":true},{"name":"Furtività","ability":"dexterity","proficient":true},{"name":"Sopravvivenza","ability":"wisdom","proficient":false}]},"equipment":{"attacks":[{"name":"Spada lunga","attackBonus":0,"damageDice":"1d8","damageType":"tagliente","category":"melee","hands":"versatile","equipped":false},{"name":"Pugnale","attackBonus":0,"damageDice":"1d4","damageType":"perforante","category":"melee","hands":"1","equipped":false},{"name":"Spada lunga (versatile)","attackBonus":2,"damageDice":"1d8","damageType":"tagliente","category":"melee","hands":"versatile","equipped":false},{"name":"Spada corta","attackBonus":0,"damageDice":"1d6","damageType":"perforante","category":"melee","hands":"1","equipped":false},{"name":"Arco corto","attackBonus":0,"damageDice":"1d6","damageType":"perforante","category":"ranged","range":"24/96 m","equipped":false},{"name":"Ascia bipenne","attackBonus":0,"damageDice":"1d12","damageType":"tagliente","category":"melee","hands":"2","equipped":true}],"equipment":["Spada lunga","Flauto","Armatura di cuoio","Pugnale","5 dardi avvelenati","Spada lunga (versatile)","Spada corta","Arco corto","Pozione","Violino del Cantore Sepolto","Collegio bardico del valore","Maestria","Oggetti del ragno","Ascia bipenne"],"coins":{"cp":0,"sp":50,"ep":0,"gp":10,"pp":0},"items":[{"type":"object","name":"Armatura di cuoio","description":"CA: 11 + DES","equippable":true,"equipped":true},{"type":"consumable","name":"Dardi avvelenati","quantity":5,"subtype":"potion","dice":"Gittata 6/18 m. Danno 1d4 perforante. Veleno base: TS COS CD 10 o +1d4 veleno (0 al successo)."},{"type":"object","name":"Flauto","description":"Strumento musicale.","equippable":false,"equipped":false},{"type":"object","name":"Violino del Cantore Sepolto","description":"Lo strumento emette un suono cupo e malinconico, come un lamento distante.","equippable":true,"equipped":true,"skillsByType":{"riposoLungo":[{"name":"Una volta per lungo riposo, quando usi Ispirazione Bardica, il beneficiario ottiene anche PF temporanei pari al dado di ispirazione.","used":false},{"name":"Una volta per lungo riposo, se scendi a 0 PF, invece rimani a 1 PF.","used":false}]}},{"type":"object","name":"Oggetti del ragno","description":"- Guanto con ragno ricamato sopra\n- Anello di “maestro” del ragno","equippable":true,"equipped":true},{"type":"consumable","name":"Oggetti incantesimo per bardo","quantity":10,"subtype":"generic"},{"type":"object","name":"Anello di Resistenza all’Acqua ","description":"Un semplice anello di bronzo con una goccia di turchese incastonata; emana un fresco costante al tatto.","equippable":true,"equipped":true,"skillsByType":{"volonta":[{"name":"Vantaggio alle prove di Forza (Atletica) per nuotare e resistenza a condizioni ambientali acquatiche (correnti forti, tempeste in mare, ecc.).","used":false},{"name":"Resistenza ai danni da freddo (mezzi danni da attacchi/incantesimi freddo).","used":false}]}},{"type":"consumable","name":"Grimaldello","quantity":15,"subtype":"generic"},{"type":"object","name":"Occhiali di Rodin","equippable":false,"equipped":false}]},"features":[{"name":"Parola Guaritrice (bardo, Lv 1)","description":"Livello 1 · Evocazione\nTempo di lancio: 1 azione bonus\nGittata: 18 m\nComponenti: V\nDurata: Istantanea\n\nUna creatura entro gittata recupera 1d4 + il tuo modificatore da incantatore PF.\n\nUso: Rialzare compagni a terra senza usare l’azione principale."},{"name":"Individuazione del Magico (bardo, Lv 1)","description":"Livello 1 · Divinazione (Rituale) · Concentrazione · Rituale\nTempo di lancio: 1 azione (10 minuti se rituale)\nGittata: Sé\nComponenti: V, S\nDurata: Concentrazione, fino a 10 minuti\n\nPercepisci la presenza di magia entro 9 m da te e puoi vedere l’aura e la scuola di magia degli oggetti o effetti.\n\nUso: Scovare trappole magiche, porte segrete mistiche, oggetti incantati."},{"name":"Frantumare (bardo, Lv 2)","description":"Livello 2 · Invocazione\nTempo di lancio: 1 azione\nGittata: 18 metri\nComponenti: V, S, M (un frammento di metallo)\nDurata: Istantanea\n\nUn forte squillo, molto intenso, erutta da un punto a gittata di tua scelta. Ogni creatura in una sfera di 3 metri di raggio centrata su quel punto deve effettuare un tiro salvezza su Costituzione. Una creatura subisce 3d8 danni da tuono se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Una creatura composta di materiale inorganico, come pietra, cristallo o metallo, ha svantaggio sul tiro salvezza. Un oggetto non magico che non è indossato né trasportato subisce anch’esso danni se si trova nell’area dell’incantesimo.\n"},{"name":"Sussurri Dissonanti (bardo, Lv 1)","description":"Livello 1 · Ammaliamento\nTempo di lancio: 1 azione\nGittata: 18 m\nComponenti: V\nDurata: Istantanea\n\nL''incantatore sussurra una melodia dissonante che soltanto una creatura a sua scelta e situata entro gittata è in grado di udire; quella creatura sarà scossa da un dolore lancinante. Il bersaglio deve effettuare un tiro salvezza su Saggezza. Se lo fallisce, subisce 3d6 danni psichici e. se disponibile, deve usare immediatamente la sua reazione per muoversi fin dove la sua velocità glielo consente, allontanandosi dall''incantatore. La creatura non si muove su terreno palesemente pericoloso come un incendio o una fossa. Se invece supera il tiro salvezza, il bersaglio subisce soltanto la metà di quei danni e non deve muoversi per allontanarsi. Una creatura assordata supera automaticamente il tiro salvezza. Ai Livelli Superiori. Quando l''incantatore lancia questo incantesimo usando uno slot incantesimo di 2° livello o superiore, i danni aumentano di ld6 per ogni slot di livello superiore al 1°.\n\nUso: Forzare disimpegno, rompere concentrazione, togliere nemici dal corpo a corpo."},{"name":"Prestidigitazione (bardo, Lv 0)","description":"Livello 0 · Trasmutazione\nTempo di lancio: 1 azione\nGittata: 3 metri\nComponenti: V, S\nDurata: Massimo 1 ora\n\nQuesto incantesimo è un trucco magico minore che gli incantatori novizi impiegano per fare pratica. Crei a gittata uno dei seguenti effetti magici:\nCrei un effetto sensoriale innocuo e istantaneo come una pioggia di scintille, un soffio di vento, una debole nota musicale o uno strano odore. Illumini o spegni istantaneamente una candela, una torcia o piccolo fuoco da campo. Ripulisci o insozzi istantaneamente un oggetto non più grosso di 0,03 metri cubi. Raffreddi, riscaldi o insapori per 1 ora fino a 0,03 metri cubi di materiale non vivente. Fai comparire per 1 ora un colore, un piccolo segno o un simbolo su di un oggetto o una superficie. Crei un ninnolo non magico o un’immagine illusoria che entri nella tua mano e che resta fino al termine del tuo prossimo turno.\nSe lanci questo incantesimo più volte, puoi tenere attivi fino a tre effetti non istantanei alla volta, e puoi interrompere uno di questi effetti con un’azione.\n"},{"name":"Illusione Minore (bardo, Lv 0)","description":"Livello 0 · Illusione\nTempo di lancio: 1 azione\nGittata: 9 metri\nComponenti: S, M (un pezzo di vello)\nDurata: 1 minuto\n\nCrei l’immagine di un oggetto o un suono a gittata per la durata dell’incantesimo. L’illusione ha termine se la interrompi con un’azione o lanci di nuovo questo incantesimo.\nSe crei un suono, il suo volume può variare da quello di un bisbiglio a un urlo. Può essere la tua voce, la voce di qualcun altro, il ruggito di un leone, un battito di tamburi, o qualsiasi altro suono tu scelga. Il suono continua incessante per tutta la durata, oppure puoi produrre suoni diversi in momenti diversi prima del termine dell’incantesimo.\nSe crei l’immagine di un oggetto (come una sedia, un’impronta fangosa o un piccolo forziere) non può essere più grande di un cubo di 1,5 metri di spigolo. L’immagine non può produrre suoni, luci, odori o qualsiasi altro effetto sensoriale. L’interazione fisica con l’oggetto lo rivela come illusione, perché le cose lo possono attraversare.\nUna creatura che usa la sua azione per esaminare il suono o l’immagine può determinare che si tratta di un’illusione con una prova riuscita di Intelligenza (Indagare) contro la CD del tiro salvezza del tuo incantesimo. Se una creatura riconosce l’illusione per quello che è, per lei l’illusione sbiadisce.\n"},{"name":"Individuazione dei Pensieri (bardo, Lv 2)","description":"Livello 2 · Divinazione · Concentrazione\nTempo di lancio: 1 azione\nGittata: Incantatore\nComponenti: V, S, M (un pezzo di rame)\nDurata: Concentrazione, massimo 1 minuto\n\nPer la durata, puoi leggere i pensieri di certe creature. Quando lanci questo incantesimo e come tua azione in ciascun turno successivo sino al termine dell’incantesimo, puoi concentrare la tua mente su qualsiasi creatura che tu possa vedere e si trovi entro 9 metri da te. Se la creatura che hai scelto ha un punteggio di Intelligenza 3 o meno o non parla nessun linguaggio, la creatura ignora l’effetto. Inizialmente, apprendi solo i pensieri di superficie della creatura: quelli più ricorrenti. Con un’azione, puoi o spostare la tua attenzione sui pensieri di un’altra creatura o tentare di sondare più a fondo la mente della stessa creatura. Se sondi più a fondo, il bersaglio deve effettuare un tiro salvezza su Saggezza. Se lo fallisce, ottieni una percezione dei suoi ragionamenti (se ve ne sono), del suo stato emotivo, e di ogni cosa abbia prevalenza nei suoi pensieri (come una preoccupazione, l’amore, o l’odio). Se supera il tiro salvezza, l’incantesimo termina. A ogni modo, il bersaglio sa che stai sondando la sua mente e, a meno che non sposti la tua attenzione verso la mente di un’altra creatura, nel suo turno la creatura può usare la propria azione per effettuare una prova di Intelligenza contesa dalla tua prova di Intelligenza; se la vince, l’incantesimo termina. Le domande poste verbalmente alla creatura bersaglio, ovviamente, modellano il corso dei suoi pensieri, cosicché questo incantesimo risulta particolarmente efficace negli interrogatori. Puoi anche usare questo incantesimo per individuare la presenza di creature pensanti che non puoi vedere. Quando lanci questo incantesimo o come tua azione nella sua durata, puoi cercare pensieri entro 9 metri da te. L’incantesimo può penetrare le barriere, ma è bloccato da 60 centimetri di pietra, 5 centimetri di metallo che non sia il piombo, o un sottile foglio di piombo. Non puoi individuare una creatura con Intelligenza 3 o meno, o una creatura che non parla alcun linguaggio. Una volta individuata in questo modo la presenza di una creatura, puoi leggerne i pensieri per la durata dell’incantesimo finché resta nella gittata, come descritto sopra, anche se non puoi vederla.\n"},{"name":"Beffa Crudele (bardo, Lv 0)","description":"Livello 0 · Ammaliamento\nTempo di lancio: 1 azione\nGittata: 18 metri\nComponenti: V\nDurata: Istantanea\n\nScateni una serie di insulti avvolti da una subdola malia contro una creatura a gittata e che puoi vedere. Se il bersaglio ti può udire (sebbene non sia necessario che ti comprenda), deve superare un tiro salvezza su Saggezza o subire 1d4 danni psichici e avere svantaggio al prossimo tiro per colpire che effettuerà prima del termine del suo prossimo turno. Il danno dell’incantesimo aumenta di 1d4 quando raggiungi il 5° livello (2d4), 11° livello (3d4) e 17° livello (4d4).\n"},{"name":"Riscaldare il Metallo (bardo, Lv 2)","description":"Livello 2 · Trasmutazione · Concentrazione\nTempo di lancio: 1 azione\nGittata: 18 metri\nComponenti: V, S, M (un pezzo di ferro e una fiamma)\nDurata: Concentrazione, massimo 1 minuto\n\nScegli un manufatto di metallo, come un’arma di metallo o un’armatura di metallo media o pesante, a gittata e che puoi vedere. Fai sì che l’oggetto risplenda di rosso per il calore. Qualsiasi creatura in contatto fisico con l’oggetto subisce 2d8 danni da fuoco quando lanci questo incantesimo. Fino al termine dell’incantesimo, puoi usare un’azione bonus per infliggere di nuovo questo danno nei tuoi turni successivi. Se una creatura sta impugnando o indossando l’oggetto e subisce danno da esso, la creatura deve superare un tiro salvezza su Costituzione o gettare l’oggetto se ne è in grado. Se non getta l’oggetto, ha svantaggio ai tiri per colpire e le prove di caratteristica fino all’inizio del suo prossimo turno.\n"},{"name":"Dissolvi Magie (bardo, Lv 3)","description":"Livello 3 · Abiurazione\nTempo di lancio: 1 azione\nGittata: 36 metri\nComponenti: V, S\nDurata: Istantanea\n\nScegli una creatura, oggetto o effetto magico a gittata. Qualsiasi incantesimo di 3° livello o più basso sul bersaglio ha fine. Per ogni incantesimo di 4° livello o più alto sul bersaglio, effettua una prova di caratteristica usando la tua caratteristica da incantatore. La CD della prova è uguale a 10 + il livello dell’incantesimo da dissolvere. Se superi la prova, l’incantesimo ha termine.\n"},{"name":"Trama Ipnotica (bardo, Lv 3)","description":"Livello 3 · Illusione · Concentrazione\nTempo di lancio: 1 azione\nGittata: 36 metri\nComponenti: S, M (un bastoncino luminoso di incenso o una fiala di cristallo piena di materiale fosforescente)\nDurata: Concentrazione, massimo 1 minuto\n\nCrei a gittata una trama contorta di colori che si muove nell’aria all’interno di un cubo di 9 metri di spigolo. La trama appare per un momento e poi svanisce. Ogni creatura nell’area che veda la trama deve effettuare un tiro salvezza su Saggezza. Se fallisce il tiro salvezza, una creatura rimane affascinata per la durata. Mentre è affascinata da questo incantesimo, la creatura è inabile e ha velocità 0.\nL’incantesimo termina per la creatura soggetta, qualora questa subisca danni o se qualcuno usa un’azione per scuoterla dal suo stato confusionale.\n"}],"spells":[],"personalityTraits":"Non cerco la gloria, cerco la prova. Ogni battaglia mi dice chi sono davvero, non posso voltare le spalle a chi è più debole, sarebbe come tradire me stesso.","ideals":"Protezione: ''La mia spada vale qualcosa solo se difende chi non può brandirne una.'' Crescita: ''Ogni sfida, ogni ferita, ogni duello è un passo per diventare più forte di ieri.''","bonds":"Porta con sé la vecchia spada scheggiata che usò nel suo primo vero combattimento: simbolo del momento in cui ha scelto la sua strada.","flaws":"Non riesce a resistere al richiamo di una sfida: il rischio di superare se stesso lo spinge anche quando dovrebbe fermarsi.","backstory":"","capabilities":[{"name":"Ispirazione Bardica","kind":"active","shortDescription":"Concede un dado bonus (d8) a un alleato entro 18 metri, usabile entro 10 minuti.","description":"Un bardo può ispirare gli altri tramite il lirismo delle sue parole o della sua musica. Per farlo usa un''azione bonus nel suo turno per scegliere una creatura diversa da se stesso, situata entro 18 metri da lui e in grado di sentirlo. Quella creatura ottiene un dado di Ispirazione Bardica, un d6.\nUna volta entro i 10 minuti successivi, quella creatura può tirare il dado e aggiungere il risultato ottenuto a una prova di caratteristica, un tiro per colpire o un tiro salvezza da essa effettuato. La creatura può aspettare di avere tirato il d20 prima di decidere se utilizzare il dado di Ispirazione Bardica, ma deve decidere se utilizzarlo prima che il GM dichiari se il tiro ha avuto successo o meno. Una volta tirato il dado di Ispirazione Bardica, quel dado è perduto. Una creatura può possedere un solo dado di Ispirazione Bardica alla volta.\nIl bardo può utilizzare questo privilegio un numero di volte pari al suo modificatore di Carisma (minimo di una volta). Recupera tutti gli utilizzi spesi quando completa un riposo lungo.\nIl dado di Ispirazione Bardica cambia quando vengono raggiunti determinati livelli in questa classe. Il dado diventa un d8 al 5° livello, un d10 al 10° livello e un d12 al 15° livello.","usage":{"resetOn":"shortRest","used":[false,false,false,false]}},{"name":"Factotum","kind":"passive","shortDescription":"Aggiungi metà del bonus di competenza su prove in cui non sei competente.","description":"A partire dal 2° livello, un bardo può aggiungere metà del suo bonus di competenza, arrotondato per difetto, a ogni prova di caratteristica da lui effettuata che non includa già il suo bonus di competenza."},{"name":"Collegio Bardico del Valore","kind":"passive","shortDescription":"- Competenza in armature medie negli scudi e nelle armi da guerra\n- Posso ispirare gli altri\n- Al livello 6 posso attaccare 2 volte","category":"Sottoclasse"},{"name":"Maestria","kind":"passive","shortDescription":"- Al 3 livello un bardo sceglie due tra le sue competenze nelle abilità. Il suo bonus di competenza raddoppia in ogni prova di caratteristica effettuata usando una delle competenze scelte.\n- Al 10 livello un bardo può scegliere altre due competenze nelle abilità per ottenere questo beneficio.","category":"Bardo"}]}', '2026-03-20T23:51:19.650Z', '2026-03-30T14:16:47.654Z');
INSERT INTO "Character" ("id", "slug", "name", "characterType", "ownerUserId", "createdByUserId", "className", "race", "alignment", "background", "level", "portraitUrl", "archivedAt", "data", "createdAt", "updatedAt") VALUES ('valthor', 'valthor', 'Valthor', 'PG', 'user_player_luigi_f', NULL, 'Warlock', 'Tiefling', 'Neutrale buono', 'Nobile Decaduto', 5, 'public/portraits/valthor.png', NULL, '{"slug":"valthor","characterType":"pg","basicInfo":{"characterName":"Valthor","class":"Warlock","level":5,"background":"Nobile Decaduto","playerName":"Luigi","race":"Tiefling","alignment":"Neutrale buono","experiencePoints":0,"portraitUrl":"public/portraits/valthor.png"},"abilityScores":{"strength":10,"dexterity":11,"constitution":12,"intelligence":16,"wisdom":10,"charisma":18},"combatStats":{"armorClass":11,"initiative":0,"speed":9,"hitPointMaximum":45,"currentHitPoints":45,"temporaryHitPoints":4,"hitDice":"1d8","deathSaves":{"successes":0,"failures":0},"spellSlots":{"1":[],"2":[],"3":[{"id":1,"active":false},{"id":2,"active":false}],"4":[],"5":[],"6":[],"7":[],"8":[],"9":[],"10":[],"11":[],"12":[]}},"proficiencies":{"savingThrows":["Saggezza","Carisma"],"languages":["Comune","Infernale","Draconico"],"skills":[{"name":"Acrobazia","ability":"dexterity","proficient":false},{"name":"Addestrare Animali","ability":"wisdom","proficient":false},{"name":"Arcano","ability":"intelligence","proficient":true},{"name":"Atletica","ability":"strength","proficient":false},{"name":"Inganno","ability":"charisma","proficient":false},{"name":"Storia","ability":"intelligence","proficient":true},{"name":"Intuizione","ability":"wisdom","proficient":false},{"name":"Intimidire","ability":"charisma","proficient":false},{"name":"Indagare","ability":"intelligence","proficient":false},{"name":"Medicina","ability":"wisdom","proficient":false},{"name":"Natura","ability":"intelligence","proficient":true},{"name":"Percezione","ability":"wisdom","proficient":false},{"name":"Intrattenere","ability":"charisma","proficient":false},{"name":"Persuasione","ability":"charisma","proficient":true},{"name":"Religione","ability":"intelligence","proficient":false},{"name":"Rapidità di Mano","ability":"dexterity","proficient":false},{"name":"Furtività","ability":"dexterity","proficient":false},{"name":"Sopravvivenza","ability":"wisdom","proficient":false}]},"equipment":{"attacks":[{"name":"Spada corta","attackBonus":0,"damageDice":"1d6","damageType":"perforante","category":"melee","hands":"1","equipped":true},{"name":"Arco corto","attackBonus":0,"damageDice":"1d6","damageType":"perforante","category":"ranged","range":"24/96 m","equipped":true}],"equipment":["Explorer''s pack"],"coins":{"cp":0,"sp":30,"ep":0,"gp":34,"pp":0},"items":[{"type":"object","name":"Armatura di cuoio","description":"CA: 11 + DES","equippable":true,"equipped":true},{"type":"object","name":"Dotazione da Esploratore","description":"Zaino - Giaciglio - Gavetta - Acciarino - Pietra Focaia - 10 Torce - Otre - 15m di corda","equippable":true,"equipped":false},{"type":"object","name":"Anello della Vita Sepolcrale","description":"L’anello è d’argento annerito, decorato con un piccolo teschio.","equippable":true,"equipped":true,"skillsByType":{"volonta":[{"name":"Ogni volta che recuperi PF tramite magia, ottieni +2 PF extra.","used":false}],"riposoLungo":[{"name":"Una volta per lungo riposo, se scendi a 0 PF, invece rimani a 1 PF.","used":false}]}},{"type":"consumable","name":"Pozione di Cura","quantity":1,"subtype":"potion","dice":"2d4+2"},{"type":"consumable","name":"Componenti Arcani","quantity":12,"subtype":"generic"},{"type":"object","name":"Pietra Misteriosa d20","description":"Pietra Misteriosa a 20 facce che può modificare dei consumabili in modo casuale","equippable":false,"equipped":false},{"type":"object","name":"Amuleto di Piume","description":"Amuleto di legno a forma di penna di gufo, legato con un cordino di cuoio.","equippable":true,"equipped":true,"skillsByType":{"riposoLungo":[{"name":"Riduce a 0 i danni da caduta.","used":false}]}}]},"features":[{"name":"Deflagrazione Occulta (warlock, Lv 0)","description":"Livello 0 · null · Concentrazione\nTempo di lancio: 1 azione\nGittata: 36\nComponenti: V, S\nDurata: Istantanea\n\nUn raggio di energia crepitante sfreccia verso una creatura entro gittata. L''incantatore effettua un attacco a distanza con questo incantesimo contro il bersaglio. Se lo colpisce, il bersaglio subisce ldlO danni da forza. Quando l''incantatore arriva ai livelli superiori, l''incantesimo crea più raggi: due raggi al 5° livello, tre raggi all''ll'' livello e quattro raggi al 17. livello. Vincantatore può indirizzare i raggi contro lo stesso bersaglio o contro bersagli diversi, effettuando un tiro per colpire separato per ogni raggio.\n"},{"name":"Spruzzo Velenoso (warlock, Lv 0)","description":"Livello 0 · Evocazione\nTempo di lancio: 1 azione\nGittata: 3 metri\nComponenti: V, S\nDurata: Istantanea\n\nStendi la mano verso una creatura a gittata e che puoi vedere, e proietti una nube di gas velenoso dal tuo palmo. La creatura deve superare un tiro salvezza su Costituzione o subire 1d12 danni da veleno. Il danno dell’incantesimo aumenta di 1d12 quando raggiungi il 5° livello (2d12), 11° livello (3d12) e 17° livello (4d12).\n"},{"name":"Mani Brucianti (mago, Lv 1)","description":"Livello 1 · Invocazione\nTempo di lancio: 1 azione\nGittata: Incantatore (cono di 4,5 metri)\nComponenti: V, S\nDurata: Istantanea\n\nMentre tieni le mani con i pollici che si toccano e le dita tese, un sottile fiotto di fiamme parte da ciascuna delle punta delle tue dita. Ogni creatura in un cono di 4,5 metri deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 3d6 danni da fuoco se fallisce il tiro salvezza, o la metà se lo supera. Il fuoco incendia gli oggetti infiammabili nell’area che non siano indossati o trasportati.\n"},{"name":"Vita Falsata (mago, Lv 1)","description":"Livello 1 · Necromanzia\nTempo di lancio: 1 azione\nGittata: Incantatore\nComponenti: V, S, M (un piccolo ammontare di alcool o spirito distillato)\nDurata: 1 ora\n\nPotenziandoti con una parvenza necromantica di vitalità, ottieni 1d4 + 4 punti ferita temporanei per la durata.\n"},{"name":"Ritirata Rapida (warlock, Lv 1)","description":"Livello 1 · Trasmutazione · Concentrazione\nTempo di lancio: 1 azione bonus\nGittata: Incantatore\nComponenti: V, S\nDurata: Concentrazione, massimo 10 minuti\n\nQuesto incantesimo ti permette di muoverti a un’andatura incredibile. Quando lanci questo incantesimo, e poi con un’azione bonus durante ciascun tuo turno fino al termine dell’incantesimo, puoi effettuare l’azione Scattare.\n"},{"name":"Nube di Pugnali (warlock, Lv 2)","description":"Livello 2 · Evocazione · Concentrazione\nTempo di lancio: 1 azione\nGittata: 18 metri\nComponenti: V, S, M (una scheggia di vetro)\nDurata: Fino a 1 minuto\n\nCrei una nube di pugnali che riempie un cubo di 1,5 metri di lato, centrato su un punto a gittata che puoi vedere. Una creatura subisce 4d4 danni taglienti quando entra per la prima volta in un turno nell’area dell’incantesimo o quando inizia il suo turno lì.\n"},{"name":"Sortilegio (warlock, Lv 1)","description":"Livello 1 · Ammaliamento · Concentrazione · Rituale\nTempo di lancio: 1 azione bonus\nGittata: 27 metri\nComponenti: V, S, M (l''occhio pietrificato di un girino)\nDurata: 1 ora\n\nL''incantatore scaglia una maledizione su una creatura entro gittata e che egli sia in grado di vedere. Finché l''incantesimo non termina, l''incantatore infligge ld6 danni necrotici extra al bersaglio ogni volta che lo colpisce con un attacco. Inoltre, quando l''incantatore lancia l''incantesimo, sceglie una caratteristica. Il bersaglio subisce svantaggio alle prove di caratteristica effettuate con la caratteristica scelta. Se il bersaglio scende a O punti ferita prima che questo incantesimo termini, l''incantatore può usare un''azione bonus in un suo turno successivo per maledire una nuova creatura. Un incantesimo rimuovi maledizione lanciato sul bersaglio termina questo incantesimo prematuramente. Al Livelll Superiori. Quando l''incantatore lancia questo incantesimo usando uno slot incantesimo di 3a o 4 livello. può mantenere la concentrazione sull''incantesimo fino a un massimo di 8 ore. Quando usa uno slot incantesimo di s􀁍 livello o superiore, può mantenere la concentrazione sull''incantesimo fino a un massimo di 24 ore.\n"},{"name":"Blocca Persone (warlock, Lv 2)","description":"Livello 2 · Ammaliamento · Concentrazione\nTempo di lancio: 1 azione\nGittata: 18 metri\nComponenti: V, S, M (un piccolo pezzo dritto di ferro)\nDurata: Concentrazione, massimo 1 minuto\n\nScegli un umanoide a gittata e che puoi vedere. Il bersaglio deve superare un tiro salvezza su Saggezza o restare paralizzato per la durata. Al termine di ciascun suo turno, il bersaglio può effettuare un altro tiro salvezza su Saggezza. Se lo supera, per quel bersaglio l’incantesimo ha termine.\n"},{"name":"Mano Magica (warlock, Lv 0)","description":"Livello 0 · Evocazione\nTempo di lancio: 1 azione\nGittata: 9 metri\nComponenti: V, S\nDurata: 1 minuto\n\nUna mano spettrale fluttuante compare in un punto a gittata, scelto da te. La mano resta per la durata dell’incantesimo o finché non viene interrotta con un’azione. La mano svanisce se si dovesse trovare a più di 9 metri da te o se lanci nuovamente l’incantesimo. Puoi usare la tua azione per controllare la mano. Puoi usare la mano per manipolare un oggetto, aprire una porta o un contenitore non chiusi a chiave, inserire o recuperare un oggetto da un contenitore aperto, o versare fuori i contenuti di una fiala. Puoi muovere la mano di 9 metri ogni volta che la usi. La mano non può attaccare, attivare oggetti magici o trasportare più di 5 chili.\n"},{"name":"Palla di Fuoco (stregone, Lv 3)","description":"Livello 3 · Invocazione\nTempo di lancio: 1 azione\nGittata: 45 metri\nComponenti: V, S, M (una minuscola palla di guano di pipistrello e zolfo)\nDurata: Istantanea\n\nUn fascio di luce gialla parte dal tuo dito puntato verso un punto a gittata scelto da te, e poi esplode con un boato sommesso e si trasforma in un getto di fiamme. Ogni creatura in una sfera di 6 metri di raggio centrata in quel punto deve effettuare un tiro salvezza su Destrezza. Una creatura subisce 8d6 danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo supera. Il fuoco si propaga intorno agli angoli. Il fuoco incendia gli oggetti infiammabili nell’area che non sono indossati o trasportati.\n"}],"spells":[],"personalityTraits":"Non cerco la gloria, cerco la prova. Ogni battaglia mi dice chi sono davvero, non posso voltare le spalle a chi è più debole, sarebbe come tradire me stesso.","ideals":"Protezione: ''La mia spada vale qualcosa solo se difende chi non può brandirne una.'' Crescita: ''Ogni sfida, ogni ferita, ogni duello è un passo per diventare più forte di ieri.''","bonds":"Porta con sé la vecchia spada scheggiata che usò nel suo primo vero combattimento: simbolo del momento in cui ha scelto la sua strada.","flaws":"Non riesce a resistere al richiamo di una sfida: il rischio di superare se stesso lo spinge anche quando dovrebbe fermarsi.","backstory":"","capabilities":[{"name":"Deflagrazione Agonizzante","kind":"active","shortDescription":"Mod. CAR ai danni di Deflagrazione Occulta","category":"Supplica occulta","description":"Prerequisito: trucchetto Deflagrazione Occulta.\nEffetto: quando lanci Deflagrazione Occulta, aggiungi il tuo modificatore di Carisma ai danni di ogni raggio che colpisce.","usage":{"resetOn":"atWill","used":[]}},{"name":"Vigore immondo","kind":"active","shortDescription":"Vita Falsata (1°) a volontà","category":"Supplica Occulta","description":"Puoi lanciare Vita Falsata su te stesso a volontà come incantesimo di 1° livello, senza spendere slot incantesimo né componenti materiali.","usage":{"resetOn":"atWill","used":[]}},{"name":"Lama Assetata","kind":"passive","shortDescription":"Doppio attacco con la lama del patto","category":"Supplica Occulta","description":"Prerequisiti: 5° livello, privilegio Patto della Lama\nOgni volta che effettua l''azione Attacco nel suo turno, il warlock può attaccare con la sua arma del patto due volte anziché una."}]}', '2026-03-20T22:21:47.376Z', '2026-03-30T14:16:53.233Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('Z29ibGluLmpzb24', 'goblin', 'goblin', 'SRD', 'goblin.json', NULL, NULL, NULL, NULL, NULL, NULL, '{"name":"Goblin","size":"Small","type":"humanoid (goblinoid)","alignment":"neutral evil","armorClass":15,"hitPoints":7,"hitDice":"2d6","speed":{"walk":30},"abilityScores":{"strength":8,"dexterity":17,"constitution":10,"intelligence":10,"wisdom":8,"charisma":8},"skills":["Stealth +6"],"senses":["darkvision 60 ft.","passive Perception 9"],"languages":["Common","Goblin"],"challengeRating":"1/4","proficiencyBonus":2,"actions":[{"name":"Scimitar","description":"Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 5 (1d6 + 2) slashing damage."},{"name":"Shortbow","description":"Ranged Weapon Attack: +4 to hit, range 80/320 ft., one target. Hit: 5 (1d6 + 2) piercing damage."}],"specialAbilities":[{"name":"Nimble Escape","description":"The goblin can take the Disengage or Hide action as a bonus action on each of its turns."}]}', '2025-09-04T13:46:38.973Z', '2025-09-04T13:46:38.973Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hYm9sZXRoLmpzb24', 'aboleth', 'Aboleth', 'SRD', 'srd-extracted/aboleth.json', '10', 10, 5900, 'Grande', 'aberrazione', 'legale malvagio', '{"slug":"aboleth","general":{"name":"Aboleth","challengeRating":{"fraction":"10","decimal":10,"display":"10","xp":5900},"size":"Grande","creatureType":"aberrazione","subtype":"","typeLabel":"aberrazione","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":135,"formula":"18d10 + 36"},"speed":{"walk":"3 m","swim":"12 m"}},"abilities":{"strength":21,"dexterity":9,"constitution":15,"intelligence":18,"wisdom":15,"charisma":18},"details":{"savingThrows":[{"ability":"Costituzione","bonus":6},{"ability":"Intelligenza","bonus":8},{"ability":"Saggezza","bonus":6}],"skills":[{"name":"Percezione","bonus":10},{"name":"Storia","bonus":12}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 20"}],"languages":[{"name":"Parlata delle Profondità"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":4},"traits":[{"name":"Anfibio","usage":null,"description":"L''aboleth può respirare aria e acqua."},{"name":"Nube di Muco","usage":null,"description":"Mentre è sott''acqua, l''aboleth è avvolto da muco mutante. Una creatura che entri a contatto con l''aboleth, o che lo colpisca con un attacco da mischia mentre si trova entro 1,5 metri da esso, deve effettuare un tiro salvezza di Costituzione CD 14. Se lo fallisce, la creatura resta ammalata per 1d4 ore. La creatura ammalata può respirare solo sott''acqua."},{"name":"Sonda Telepatica","usage":null,"description":"Se una creatura comunica telepaticamente con l''aboleth, e l''aboleth può vederla, l''aboleth ne apprende i più grandi desideri."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''aboleth effettua tre attacchi con i tentacoli"},{"name":"Tentacolo","usage":null,"description":"Attacco con arma da mischia: +9 a colpire, portata 3 m, un bersaglio. Colpisce: 12 (2d6 + 5) danni contundenti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Costituzione CD 14 o divenire ammalato. La malattia non produce alcun effetto per 1 minuto e può essere rimossa da qualsiasi magia che curi le malattie. Dopo 1 minuto, la pelle della creatura ammalata diventa trasparente e viscida, la creatura non può recuperare punti ferita a meno che non sia sott''acqua, e la malattia può essere rimossa solo da guarire o un altro incantesimo cura malattie di 6° livello o più alto. Quando la creatura si trova al di fuori di un corpo d''acqua, subisce 6 (1d12) danni da acido ogni 10 minuti a meno che la sua pelle non venga bagnata prima che siano passati questi 10 minuti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +9 a colpire, portata 3 m, un bersaglio. Colpisce: 15 (3d6 + 5) danni contundenti."},{"name":"Schiavizzare","usage":"3/Giorno","description":"L''aboleth prende a bersaglio una creatura che può vedere entro 9 metri da esso. Il bersaglio deve riuscire un tiro salvezza di Saggezza CD 14 o restare affascinato magicamente dall''aboleth finché l''aboleth muore o i due si trovano su piani di esistenza differenti. Il bersaglio affascinato è sotto il controllo dell''aboleth e non può effettuare reazioni. L''aboleth e il bersaglio possono comunicare telepaticamente tra di loro a qualsiasi distanza. Ogniqualvolta il bersaglio affascinato subisce danni, può ripetere il tiro salvezza. Se lo riesce, l''effetto termina. Non più di una volta ogni 24 ore, può ripetere il tiro salvezza quando si trova almeno a 1,5 chilometri di distanza dall''aboleth."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"L''aboleth può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. L''aboleth recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Individuare","description":"L''aboleth effettua una prova di Saggezza (Percezione).","cost":1},{"name":"Risucchio Psichico","description":"Una creatura affascinata dall''aboleth subisce 10 (3d6) danni psichici, e l''aboleth recupera un numero di punti ferita pari al danno subito dalla creatura.","cost":2},{"name":"Spazzata di Coda","description":"L''aboleth effettua un attacco di coda.","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Aboleth\nGrande aberrazione, legale malvagio\nFORZA 21 (+5)\nDESTREZZA 9 (-1)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 18 (+4)\nSAGGEZZA 15 (+2)\nCARISMA 18 (+4)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 135 (18d10 + 36)\nVelocità 3 m, nuoto 12 m\nTiri Salvezza Costituzione +6, Intelligenza +8, Saggezza +6\nAbilità Percezione +10, Storia +12\nSensi scurovisione 36 m, Percezione passiva 20\nLinguaggi Parlata delle Profondità, telepatia 36 m\nSfida 10 (5.900 PE)\nAnfibio. L''aboleth può respirare aria e acqua.\nNube di Muco. Mentre è sott''acqua, l''aboleth è avvolto da muco\nmutante. Una creatura che entri a contatto con l''aboleth, o che lo\ncolpisca con un attacco da mischia mentre si trova entro 1,5\nmetri da esso, deve effettuare un tiro salvezza di Costituzione\nCD 14. Se lo fallisce, la creatura resta ammalata per 1d4 ore. La\ncreatura ammalata può respirare solo sott''acqua.\nSonda Telepatica. Se una creatura comunica telepaticamente con\nl''aboleth, e l''aboleth può vederla, l''aboleth ne apprende i più\ngrandi desideri.\nAzioni\nMultiattacco. L''aboleth effettua tre attacchi con i tentacoli\nTentacolo. Attacco con arma da mischia: +9 a colpire, portata 3\nm, un bersaglio.\nColpisce: 12 (2d6 + 5) danni contundenti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Costituzione CD 14 o\ndivenire ammalato. La malattia non produce alcun effetto per 1\nminuto e può essere rimossa da qualsiasi magia che curi le\nmalattie. Dopo 1 minuto, la pelle della creatura ammalata diventa\ntrasparente e viscida, la creatura non può recuperare punti ferita a\nmeno che non sia sott''acqua, e la malattia può essere rimossa\nsolo da guarire o un altro incantesimo cura malattie di 6° livello\no più alto. Quando la creatura si trova al di fuori di un corpo\nd''acqua, subisce 6 (1d12) danni da acido ogni 10 minuti a meno\nche la sua pelle non venga bagnata prima che siano passati questi\n10 minuti.\nCoda. Attacco con arma da mischia: +9 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 15 (3d6 + 5) danni contundenti.\nSchiavizzare (3/Giorno). L''aboleth prende a bersaglio una\ncreatura che può vedere entro 9 metri da esso. Il bersaglio deve\nriuscire un tiro salvezza di Saggezza CD 14 o restare affascinato\nmagicamente dall''aboleth finché l''aboleth muore o i due si\ntrovano su piani di esistenza differenti. Il bersaglio affascinato è\nsotto il controllo dell''aboleth e non può effettuare reazioni.\nL''aboleth e il bersaglio possono comunicare telepaticamente tra\ndi loro a qualsiasi distanza.\nOgniqualvolta il bersaglio affascinato subisce danni, può ripetere\nil tiro salvezza. Se lo riesce, l''effetto termina. Non più di una\nvolta ogni 24 ore, può ripetere il tiro salvezza quando si trova\nalmeno a 1,5 chilometri di distanza dall''aboleth.\nAzioni Leggendarie\nL''aboleth può effettuare 3 azioni leggendarie, scelte tra le\nopzioni seguenti. Può usare solo un''opzione leggendaria alla\nvolta e solo al termine del turno di un''altra creatura. L''aboleth\nrecupera le azioni leggendarie spese all''inizio del proprio turno.\nIndividuare. L''aboleth effettua una prova di Saggezza (Percezione).\nRisucchio Psichico (Costa 2 Azioni). Una creatura affascinata\ndall''aboleth subisce 10 (3d6) danni psichici, e l''aboleth recupera un\nnumero di punti ferita pari al danno subito dalla creatura.\nSpazzata di Coda. L''aboleth effettua un attacco di coda."}}', '2026-03-30T16:00:32.222Z', '2026-03-30T16:00:32.222Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbGJlcm8tcmlzdmVnbGlhdG8uanNvbg', 'albero-risvegliato', 'Albero Risvegliato', 'SRD', 'srd-extracted/albero-risvegliato.json', '2', 2, 450, NULL, NULL, NULL, '{"slug":"albero-risvegliato","general":{"name":"Albero Risvegliato","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":59,"formula":"7d12 + 14"},"speed":{"walk":"6 m"}},"abilities":{"strength":19,"dexterity":6,"constitution":15,"intelligence":10,"wisdom":10,"charisma":7},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":["fuoco"],"damageResistances":["contundente","perforante"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Falso Aspetto","usage":null,"description":"Mentre l''albero rimane immobile, è indistinguibile da un normale albero."}],"actions":[{"name":"Schianto","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 3 m, un bersaglio. Colpisce: 14 (3d6 + 4) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Albero Risvegliato\nL''albero risvegliato è un normale albero fornito dalla\nmagia di capacità senziente e mobilità.\nEnorme pianta, disallineato\nFORZA 19 (+4)\nDESTREZZA 6 (-2)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 7 (-2)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 59 (7d12 + 14)\nVelocità 6 m\nVulnerabilità al Danno fuoco\nResistenze al Danno contundente, perforante\nSensi Percezione passiva 10\nLingue una lingua conosciuta dal suo creatore\nSfida 2 (450 PE)\nFalso Aspetto. Mentre l''albero rimane immobile, è\nindistinguibile da un normale albero.\nAzioni\nSchianto. Attacco con Arma da Mischia: +6 a colpire, portata 3\nm, un bersaglio.\nColpisce: 14 (3d6 + 4) danni contundenti."}}', '2026-03-30T16:00:32.406Z', '2026-03-30T16:00:32.407Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbGNlLWdpZ2FudGUuanNvbg', 'alce-gigante', 'Alce Gigante', 'SRD', 'srd-extracted/alce-gigante.json', '2', 2, 450, 'Enorme', 'bestia', 'disallineato', '{"slug":"alce-gigante","general":{"name":"Alce Gigante","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Enorme","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":42,"formula":"5d12 + 10"},"speed":{"walk":"18 m"}},"abilities":{"strength":19,"dexterity":16,"constitution":14,"intelligence":7,"wisdom":14,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 14"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":null,"description":"Se l''alce si muove di almeno 6 metri diretto verso il bersaglio e lo colpisce con un attacco di rostro durante lo stesso turno, il bersaglio subisce 7 (2d6) danni contundenti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di"},{"name":"Forza CD 14 o cadere prono","usage":null,"description":""}],"actions":[{"name":"Rostro","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 3 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni perforanti."},{"name":"Zoccoli","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, una creatura prona. Colpisce: 22 (4d4 + 4) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Alce Gigante\nEnorme bestia, disallineato\nFORZA 19 (+4)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 14 (+2)\nCARISMA 10 (+0)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 42 (5d12 + 10)\nVelocità 18 m\nAbilità Percezione +4\nSensi Percezione passiva 14\nLingue Alce Gigante, comprende il Comune, l''Elfico e il\nSilvano ma non può parlarli\nSfida 2 (450 PE)\nCarica. Se l''alce si muove di almeno 6 metri diretto verso il\nbersaglio e lo colpisce con un attacco di rostro durante lo stesso\nturno, il bersaglio subisce 7 (2d6) danni contundenti aggiuntivi.\nSe il bersaglio è una creatura, deve riuscire un tiro salvezza di\nForza CD 14 o cadere prono.\nAzioni\nRostro. Attacco con Arma da Mischia: +6 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 11 (2d6 + 4) danni perforanti.\nZoccoli. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, una creatura prona.\nColpisce: 22 (4d4 + 4) danni contundenti."}}', '2026-03-30T16:00:32.408Z', '2026-03-30T16:00:32.408Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbGNlLmpzb24', 'alce', 'Alce', 'SRD', 'srd-extracted/alce.json', '1/4', 0.25, 50, 'Grande', 'bestia', 'disallineato', '{"slug":"alce","general":{"name":"Alce","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":13,"formula":"2d10 + 2"},"speed":{"walk":"15 m"}},"abilities":{"strength":16,"dexterity":10,"constitution":12,"intelligence":2,"wisdom":10,"charisma":6},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":null,"description":"Se l''alce si muove di almeno 6 metri diretto verso il bersaglio e lo colpisce con un attacco di rostro durante lo stesso turno, il bersaglio subisce 7 (2d6) danni contundenti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di"},{"name":"Forza CD 13 o cadere prono","usage":null,"description":""}],"actions":[{"name":"Rostro","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni contundenti."},{"name":"Zoccoli","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, una creatura prona. Colpisce: 8 (2d4 + 3) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Alce\nGrande bestia, disallineato\nFORZA 16 (+3)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 10 (+0)\nCARISMA 6 (-2)\nClasse Armatura 10\nPunti Ferita 13 (2d10 + 2)\nVelocità 15 m\nSensi Percezione passiva 10\nLingue -\nSfida 1/4 (50 PE)\nCarica. Se l''alce si muove di almeno 6 metri diretto verso il\nbersaglio e lo colpisce con un attacco di rostro durante lo stesso\nturno, il bersaglio subisce 7 (2d6) danni contundenti aggiuntivi.\nSe il bersaglio è una creatura, deve riuscire un tiro salvezza di\nForza CD 13 o cadere prono.\nAzioni\nRostro. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d6 + 3) danni contundenti.\nZoccoli. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, una creatura prona.\nColpisce: 8 (2d4 + 3) danni contundenti."}}', '2026-03-30T16:00:32.407Z', '2026-03-30T16:00:32.408Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbWViYS1wYWdsaWVyaW5hLmpzb24', 'ameba-paglierina', 'Ameba Paglierina', 'SRD', 'srd-extracted/ameba-paglierina.json', '2', 2, 450, 'Grande', 'melma', 'disallineato', '{"slug":"ameba-paglierina","general":{"name":"Ameba Paglierina","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"melma","subtype":"","typeLabel":"melma","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":8,"note":""},"hitPoints":{"average":45,"formula":"6d10 + 12"},"speed":{"walk":"3 m","climb":"3 m"}},"abilities":{"strength":15,"dexterity":6,"constitution":14,"intelligence":2,"wisdom":6,"charisma":1},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["acido"],"damageImmunities":["fulmine","tagliente"],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieca oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Amorfo","usage":null,"description":"L''ameba può muoversi attraverso uno spazio fino a 2,5 centimetri di larghezza senza doversi stringere."},{"name":"Natura di Melma","usage":null,"description":"L''ameba non necessita di dormire."},{"name":"Scalare come Ragno","usage":null,"description":"L''ameba può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."}],"actions":[{"name":"Pseudopodo","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 9 (2d6 + 2) danni contundenti più 3 (1d6) danni da acido."}],"bonusActions":[],"reactions":[{"name":"Divisione","usage":null,"description":"Quando un''ameba Media o più grande subisce danni da fulmine o taglienti, si divide in due nuove amebe che hanno almeno 10 punti ferita. Ogni nuova ameba ha un numero di punti ferita pari alla metà dell''ameba originale, arrotondati per difetto. Le nuove amebe sono di una taglia più piccola di quella originale."}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ameba Paglierina\nGrande melma, disallineato\nFORZA 15 (+2)\nDESTREZZA 6 (-2)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 6 (-2)\nCARISMA 1 (-5)\nClasse Armatura 8\nPunti Ferita 45 (6d10 + 12)\nVelocità 3 m, scalata 3 m\nResistenze al Danno acido\nImmunità al Danno fulmine, tagliente\nImmunità alle Condizioni accecato, affascinato, assordato,\nprono, sfinimento, spaventato\nSensi vista cieca 18 m (cieca oltre questo raggio), Percezione\npassiva 8\nLinguaggi -\nSfida 2 (450 PE)\nAmorfo. L''ameba può muoversi attraverso uno spazio fino a 2,5\ncentimetri di larghezza senza doversi stringere.\nNatura di Melma. L''ameba non necessita di dormire.\nScalare come Ragno. L''ameba può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nAzioni\nPseudopodo. Attacco con arma da mischia: +4 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 9 (2d6 + 2) danni contundenti più 3 (1d6) danni da acido.\nReazioni\nDivisione. Quando un''ameba Media o più grande subisce danni da\nfulmine o taglienti, si divide in due nuove amebe che hanno almeno\n10 punti ferita. Ogni nuova ameba ha un numero di punti ferita pari\nalla metà dell''ameba originale, arrotondati per difetto. Le nuove\namebe sono di una taglia più piccola di quella originale."}}', '2026-03-30T16:00:32.352Z', '2026-03-30T16:00:32.353Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbmRyb3NmaW5nZS5qc29u', 'androsfinge', 'Androsfinge', 'SRD', 'srd-extracted/androsfinge.json', '17', 17, 18000, 'Grande', 'mostruosità', 'legale neutrale', '{"slug":"androsfinge","general":{"name":"Androsfinge","challengeRating":{"fraction":"17","decimal":17,"display":"17","xp":18000},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"legale neutrale","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":199,"formula":"19d10 + 95"},"speed":{"walk":"12 m","fly":"18 m"}},"abilities":{"strength":22,"dexterity":10,"constitution":20,"intelligence":16,"wisdom":18,"charisma":23},"details":{"savingThrows":[{"ability":"Destrezza","bonus":6},{"ability":"Costituzione","bonus":11},{"ability":"Intelligenza","bonus":9}],"skills":[{"name":"Arcano","bonus":9},{"name":"Percezione","bonus":10},{"name":"Religione","bonus":15}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["psichico; contundente","perforante e"],"conditionImmunities":["affascinato","spaventato"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 20"}],"languages":[{"name":"Comune"},{"name":"Sfinge"}],"proficiencyBonus":6},"traits":[{"name":"Armi Magiche","usage":null,"description":"Gli attacchi con armi della sfinge sono magici."},{"name":"Imperscrutabile","usage":null,"description":"La sfinge è immune a qualsiasi effetto in grado di percepirne le emozioni o leggerne i pensieri, oltre che a qualsiasi incantesimo di divinazione che rifiuti. Le prove di Saggezza (Intuizione) per discernere le intenzioni o la sincerità della sfinge hanno svantaggio."},{"name":"Incantesimi","usage":null,"description":"La sfinge è un incantatore di 12° livello. La sua caratteristica da incantatore è la Saggezza (CD del tiro salvezza degli incantesimi 18, +10 a colpire con attacchi con incantesimo). Non ha bisogno di componenti materiali per lanciare i suoi incantesimi. La sfinge tiene preparati i seguenti incantesimi da chierico: Trucchetti (a volontà): fiamma sacra, salvare i morenti, taumaturgia 1° livello (4 slot): comando, individuazione del magico, individuare male e bene 2° livello (3 slot): ristorare inferiore, zona di verità 3° livello (3 slot): dissolvi magie, linguaggi 4° livello (3 slot): esilio, libertà di movimento 5° livello (2 slot): colpo infuocato, ristorare superiore 6° livello (1 slot): banchetto degli eroi"}],"actions":[{"name":"Multiattacco","usage":null,"description":"La sfinge può effettuare due attacchi di artiglio."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +12 a colpire, portata 1,5 m, un bersaglio. Colpisce: 17 (2d6 + 10) danni taglienti."},{"name":"Ruggito","usage":"3/Giorno","description":"La sfinge emette un ruggito magico. Ogni volta che ruggisce prima di terminare un riposo lungo, il ruggito è più forte e l''effetto è diverso, come dettagliato di seguito. Ogni creatura entro 150 metri dalla sfinge e capace di udirne il ruggito deve effettuare un tiro salvezza."},{"name":"Primo Ruggito","usage":null,"description":"Ogni creatura che fallisce un tiro salvezza di"},{"name":"Saggezza CD 18 resta spaventata per 1 minuto","usage":null,"description":"Una creatura spaventata può ripetere il tiro salvezza al termine di ciascun suo turno, terminandone l''effetto per sé, se lo riesce."},{"name":"Secondo Ruggito","usage":null,"description":"Ogni creatura che fallisce un tiro salvezza di"},{"name":"Saggezza CD 18 resta assordata e spaventata per 1 minuto","usage":null,"description":"Una creatura spaventata è paralizzata e può ripetere il tiro salvezza al termine di ciascun suo turno, terminandone l''effetto per sé, se lo riesce."},{"name":"Terzo Ruggito","usage":null,"description":"Ogni creatura effettua un tiro salvezza di"},{"name":"Costituzione CD 18","usage":null,"description":"Chi fallisce il tiro salvezza subisce 44 (8d10) danni da tuono ed è gettato prono. Se il tiro salvezza riesce, la creatura subisce la metà di questi danni e non viene gettata prona."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"La sfinge può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. La sfinge recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Attacco di Artiglio","description":"La sfinge effettua un attacco di artiglio.","cost":1},{"name":"Eseguire un Incantesimo","description":"La sfinge lancia un incantesimo dalla lista degli incantesimi preparati, utilizzando uno slot incantesimo come di norma.","cost":3},{"name":"Teletrasporto","description":"La sfinge si teletrasporta magicamente, insieme a tutto l''equipaggiamento che sta indossando o trasportando, in uno spazio non occupato che possa vedere, fino a 36 metri di distanza.","cost":2}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Androsfinge\nGrande mostruosità, legale neutrale\nFORZA 22 (+6)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 20 (+5)\nINTELLIGENZA 16 (+3)\nSAGGEZZA 18 (+4)\nCARISMA 23 (+6)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 199 (19d10 + 95)\nVelocità 12 m, volo 18 m\nTiri Salvezza Destrezza +6, Costituzione +11, Intelligenza +9,\nSaggezza +10\nAbilità Arcano +9, Percezione +10, Religione +15\nImmunità al Danno psichico; contundente, perforante e\ntagliente di attacchi non magici\nImmunità alle Condizioni affascinato, spaventato\nSensi visione del vero 36 m, Percezione passiva 20\nLinguaggi Comune, Sfinge\nSfida 17 (18.000 PE)\nArmi Magiche. Gli attacchi con armi della sfinge sono magici.\nImperscrutabile. La sfinge è immune a qualsiasi effetto in grado\ndi percepirne le emozioni o leggerne i pensieri, oltre che a\nqualsiasi incantesimo di divinazione che rifiuti. Le prove di\nSaggezza (Intuizione) per discernere le intenzioni o la sincerità\ndella sfinge hanno svantaggio.\nIncantesimi. La sfinge è un incantatore di 12° livello. La sua\ncaratteristica da incantatore è la Saggezza (CD del tiro salvezza\ndegli incantesimi 18, +10 a colpire con attacchi con\nincantesimo). Non ha bisogno di componenti materiali per\nlanciare i suoi incantesimi. La sfinge tiene preparati i seguenti\nincantesimi da chierico:\nTrucchetti (a volontà): fiamma sacra, salvare i morenti,\ntaumaturgia\n1° livello (4 slot): comando, individuazione del magico,\nindividuare male e bene\n2° livello (3 slot): ristorare inferiore, zona di verità\n3° livello (3 slot): dissolvi magie, linguaggi\n4° livello (3 slot): esilio, libertà di movimento\n5° livello (2 slot): colpo infuocato, ristorare superiore\n6° livello (1 slot): banchetto degli eroi\nAzioni\nMultiattacco. La sfinge può effettuare due attacchi di artiglio.\nArtiglio. Attacco con arma da mischia: +12 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 17 (2d6 + 10) danni taglienti.\nRuggito (3/Giorno). La sfinge emette un ruggito magico. Ogni\nvolta che ruggisce prima di terminare un riposo lungo, il ruggito\nè più forte e l''effetto è diverso, come dettagliato di seguito. Ogni\ncreatura entro 150 metri dalla sfinge e capace di udirne il ruggito\ndeve effettuare un tiro salvezza.\nPrimo Ruggito. Ogni creatura che fallisce un tiro salvezza di\nSaggezza CD 18 resta spaventata per 1 minuto. Una creatura\nspaventata può ripetere il tiro salvezza al termine di ciascun suo\nturno, terminandone l''effetto per sé, se lo riesce.\nSecondo Ruggito. Ogni creatura che fallisce un tiro salvezza di\nSaggezza CD 18 resta assordata e spaventata per 1 minuto. Una\ncreatura spaventata è paralizzata e può ripetere il tiro salvezza al\ntermine di ciascun suo turno, terminandone l''effetto per sé, se lo\nriesce.\nTerzo Ruggito. Ogni creatura effettua un tiro salvezza di\nCostituzione CD 18. Chi fallisce il tiro salvezza subisce 44\n(8d10) danni da tuono ed è gettato prono. Se il tiro salvezza\nriesce, la creatura subisce la metà di questi danni e non viene\ngettata prona.\nAzioni Leggendarie\nLa sfinge può effettuare 3 azioni leggendarie, scelte tra le\nopzioni seguenti. Può usare solo un''opzione leggendaria alla\nvolta e solo al termine del turno di un''altra creatura. La sfinge\nrecupera le azioni leggendarie spese all''inizio del proprio turno.\nAttacco di Artiglio. La sfinge effettua un attacco di artiglio.\nEseguire un Incantesimo (Costa 3 Azioni). La sfinge lancia un\nincantesimo dalla lista degli incantesimi preparati, utilizzando\nuno slot incantesimo come di norma.\nTeletrasporto (Costa 2 Azioni). La sfinge si teletrasporta\nmagicamente, insieme a tutto l''equipaggiamento che sta\nindossando o trasportando, in uno spazio non occupato che possa\nvedere, fino a 36 metri di distanza."}}', '2026-03-30T16:00:32.383Z', '2026-03-30T16:00:32.383Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbmdlbG8tZGV2YS5qc29u', 'angelo-deva', 'Angelo Deva', 'SRD', 'srd-extracted/angelo-deva.json', '10', 10, 5900, 'Medio', 'celestiale', 'legale buono', '{"slug":"angelo-deva","general":{"name":"Angelo Deva","challengeRating":{"fraction":"10","decimal":10,"display":"10","xp":5900},"size":"Medio","creatureType":"celestiale","subtype":"","typeLabel":"celestiale","alignment":"legale buono","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":136,"formula":"16d8 + 64"},"speed":{"walk":"9 m","fly":"27 m"}},"abilities":{"strength":18,"dexterity":18,"constitution":18,"intelligence":17,"wisdom":20,"charisma":20},"details":{"savingThrows":[{"ability":"Saggezza","bonus":9},{"ability":"Carisma","bonus":9}],"skills":[{"name":"Intuizione","bonus":9},{"name":"Percezione","bonus":9}],"damageVulnerabilities":[],"damageResistances":["radiante; contundente","perforante e tagliente"],"damageImmunities":[],"conditionImmunities":["affascinato","sfinimento","spaventato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 19"}],"languages":[{"name":"tutte"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":4},"traits":[{"name":"Armi Angeliche","usage":null,"description":"Gli attacchi con arma del deva sono magici. Quando il deva colpisce con qualsiasi arma, l''arma infligge 4d8 danni radianti aggiuntivi (già compresi nell''attacco)."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del deva è il Carisma (CD 17 per i tiri salvezza degli incantesimi). Il deva può lanciare in maniera innata i seguenti incantesimi, con l''uso delle sole componenti verbali: A volontà: individuazione del bene e del male 1/giorno: comunione, rianimare morti"},{"name":"Resistenza alla Magia","usage":null,"description":"Il deva ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il deva effettua due attacchi da mischia."},{"name":"Mazza","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d6 + 4) danni contundenti più 18 (4d8) danni radianti."},{"name":"Tocco Guaritore","usage":"3/Giorno","description":"Il deva entra a contatto con un''altra creatura. Il bersaglio recupera magicamente 20 (4d8 + 2) punti ferita ed è libero da qualsiasi cecità, malattia, maledizione, sordità o veleno."},{"name":"Mutare Forma","usage":null,"description":"Il deva può trasformarsi magicamente in un umanoide o bestia il cui grado di sfida sia pari o inferiore al proprio, o tornare alla sua vera forma. Alla morte ritorna alla sua vera forma. Qualsiasi equipaggiamento stia indossando o trasportando viene assorbito o trasportato nella nuova forma (a scelta del deva). Nella nuova forma, il deva mantiene le sue statistiche di gioco e la facoltà di parlare, ma la sua CA, metodi di movimento, Forza, Destrezza e sensi speciali vengono rimpiazzati da quelli della nuova forma, e ottiene qualsiasi statistica o capacità (eccetto i privilegi di classe, azioni leggendarie e azioni da tana) possedute dalla sua nuova forma e non dalla sua originale."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Angelo Deva\nMedio celestiale, legale buono\nFORZA 18 (+4)\nDESTREZZA 18 (+4)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 17 (+3)\nSAGGEZZA 20 (+5)\nCARISMA 20 (+5)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 136 (16d8 + 64)\nVelocità 9 m, volo 27 m\nTiri Salvezza Saggezza +9, Carisma +9\nAbilità Intuizione +9, Percezione +9\nResistenze ai Danni radiante; contundente, perforante e tagliente\ndi attacchi non magici\nImmunità alle Condizioni affascinato, sfinimento, spaventato\nSensi scurovisione 36 m, Percezione passiva 19\nLinguaggi tutte, telepatia 36 m\nSfida 10 (5.900 PE)\nArmi Angeliche. Gli attacchi con arma del deva sono magici.\nQuando il deva colpisce con qualsiasi arma, l''arma infligge 4d8\ndanni radianti aggiuntivi (già compresi nell''attacco).\nIncantesimi Innati. La caratteristica da incantatore innato del\ndeva è il Carisma (CD 17 per i tiri salvezza degli incantesimi). Il\ndeva può lanciare in maniera innata i seguenti incantesimi, con\nl''uso delle sole componenti verbali:\nA volontà: individuazione del bene e del male\n1/giorno: comunione, rianimare morti\nResistenza alla Magia. Il deva ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. Il deva effettua due attacchi da mischia.\nMazza. Attacco con arma da mischia: +8 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 7 (1d6 + 4) danni contundenti più 18 (4d8) danni radianti.\nTocco Guaritore (3/Giorno). Il deva entra a contatto con un''altra\ncreatura. Il bersaglio recupera magicamente 20 (4d8 + 2) punti\nferita ed è libero da qualsiasi cecità, malattia, maledizione,\nsordità o veleno.\nMutare Forma. Il deva può trasformarsi magicamente in un\numanoide o bestia il cui grado di sfida sia pari o inferiore al proprio,\no tornare alla sua vera forma. Alla morte ritorna alla sua vera forma.\nQualsiasi equipaggiamento stia indossando o trasportando viene\nassorbito o trasportato nella nuova forma (a scelta del deva).\nNella nuova forma, il deva mantiene le sue statistiche di gioco e la\nfacoltà di parlare, ma la sua CA, metodi di movimento, Forza,\nDestrezza e sensi speciali vengono rimpiazzati da quelli della nuova\nforma, e ottiene qualsiasi statistica o capacità (eccetto i privilegi di\nclasse, azioni leggendarie e azioni da tana) possedute dalla sua nuova\nforma e non dalla sua originale."}}', '2026-03-30T16:00:32.223Z', '2026-03-30T16:00:32.229Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbmdlbG8tcGxhbmV0YXIuanNvbg', 'angelo-planetar', 'Angelo Planetar', 'SRD', 'srd-extracted/angelo-planetar.json', '16', 16, 15000, 'Grande', 'celestiale', 'legale buono', '{"slug":"angelo-planetar","general":{"name":"Angelo Planetar","challengeRating":{"fraction":"16","decimal":16,"display":"16","xp":15000},"size":"Grande","creatureType":"celestiale","subtype":"","typeLabel":"celestiale","alignment":"legale buono","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":200,"formula":"16d10 + 112"},"speed":{"walk":"12 m","fly":"36 m"}},"abilities":{"strength":24,"dexterity":20,"constitution":24,"intelligence":19,"wisdom":22,"charisma":25},"details":{"savingThrows":[{"ability":"Costituzione","bonus":12},{"ability":"Saggezza","bonus":11},{"ability":"Carisma","bonus":12}],"skills":[{"name":"Percezione","bonus":11}],"damageVulnerabilities":[],"damageResistances":["radiante; contundente","perforante e tagliente"],"damageImmunities":[],"conditionImmunities":["affascinato","sfinimento","spaventato"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 21"}],"languages":[{"name":"tutte"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":5},"traits":[{"name":"Armi Angeliche","usage":null,"description":"Gli attacchi con arma del planetar sono magici. Quando colpisce con qualsiasi arma, l''arma infligge 5d8 danni radianti aggiuntivi (già compresi nell''attacco)."},{"name":"Consapevolezza Divina","usage":null,"description":"Il planetar riconosce immediatamente le bugie."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del planetario è il Carisma (CD 20 per i tiri salvezza degli incantesimi). Il planetario può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti materiali: A volontà: individuazione del bene e del male, invisibilità (solo personale) 3/giorno: barriera di lame, colpo infuocato, dissolvi il bene e il male, rianimare morti 1/giorno: comunione, controllare tempo atmosferico, piaga degli insetti"},{"name":"Resistenza alla Magia","usage":null,"description":"Il planetar ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il planetar effettua due attacchi da mischia."},{"name":"Spadone","usage":null,"description":"Attacco con arma da mischia: +12 a colpire, portata 1,5 m, un bersaglio. Colpisce: 21 (4d6 + 7) danni taglienti più 22 (5d8) danni radianti."},{"name":"Tocco Guaritore","usage":"4/Giorno","description":"Il planetar entra a contatto con un''altra creatura. Il bersaglio recupera magicamente 30 (6d8 + 3) punti ferita ed è libero da qualsiasi cecità, malattia, maledizione, sordità o veleno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Angelo Planetar\nGrande celestiale, legale buono\nFORZA 24 (+7)\nDESTREZZA 20 (+5)\nCOSTITUZIONE 24 (+7)\nINTELLIGENZA 19 (+4)\nSAGGEZZA 22 (+6)\nCARISMA 25 (+7)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 200 (16d10 + 112)\nVelocità 12 m, volo 36 m\nTiri Salvezza Costituzione +12, Saggezza +11, Carisma +12\nAbilità Percezione +11\nResistenze ai Danni radiante; contundente, perforante e tagliente\ndi attacchi non magici\nImmunità alle Condizioni affascinato, sfinimento, spaventato\nSensi visione del vero 36 m, Percezione passiva 21\nLinguaggi tutte, telepatia 36 m\nSfida 16 (15.000 PE)\nArmi Angeliche. Gli attacchi con arma del planetar sono magici.\nQuando colpisce con qualsiasi arma, l''arma infligge 5d8 danni\nradianti aggiuntivi (già compresi nell''attacco).\nConsapevolezza Divina. Il planetar riconosce immediatamente le\nbugie.\nIncantesimi Innati. La caratteristica da incantatore innato del\nplanetario è il Carisma (CD 20 per i tiri salvezza degli\nincantesimi). Il planetario può lanciare in maniera innata i\nseguenti incantesimi, senza bisogno di componenti materiali:\nA volontà: individuazione del bene e del male, invisibilità (solo\npersonale)\n3/giorno: barriera di lame, colpo infuocato, dissolvi il bene e il\nmale, rianimare morti\n1/giorno: comunione, controllare tempo atmosferico, piaga degli\ninsetti\nResistenza alla Magia. Il planetar ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. Il planetar effettua due attacchi da mischia.\nSpadone. Attacco con arma da mischia: +12 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 21 (4d6 + 7) danni taglienti più 22 (5d8) danni radianti.\nTocco Guaritore (4/Giorno). Il planetar entra a contatto con\nun''altra creatura. Il bersaglio recupera magicamente 30 (6d8 + 3)\npunti ferita ed è libero da qualsiasi cecità, malattia, maledizione,\nsordità o veleno."}}', '2026-03-30T16:00:32.230Z', '2026-03-30T16:00:32.230Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbmdlbG8tc29sYXIuanNvbg', 'angelo-solar', 'Angelo Solar', 'SRD', 'srd-extracted/angelo-solar.json', '21', 21, 33000, 'Grande', 'celestiale', 'legale buono', '{"slug":"angelo-solar","general":{"name":"Angelo Solar","challengeRating":{"fraction":"21","decimal":21,"display":"21","xp":33000},"size":"Grande","creatureType":"celestiale","subtype":"","typeLabel":"celestiale","alignment":"legale buono","environments":[]},"combat":{"armorClass":{"value":21,"note":"armatura naturale"},"hitPoints":{"average":243,"formula":"18d10 + 144"},"speed":{"walk":"15 m","fly":"45 m"}},"abilities":{"strength":26,"dexterity":22,"constitution":26,"intelligence":25,"wisdom":25,"charisma":30},"details":{"savingThrows":[{"ability":"Intelligenza","bonus":14},{"ability":"Saggezza","bonus":14},{"ability":"Carisma","bonus":17}],"skills":[{"name":"Percezione","bonus":14}],"damageVulnerabilities":[],"damageResistances":["radiante; contundente","perforante e tagliente"],"damageImmunities":["necrotico","veleno"],"conditionImmunities":["affascinato","avvelenato","sfinimento"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 24"}],"languages":[{"name":"tutte"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":7},"traits":[{"name":"Armi Angeliche","usage":null,"description":"Gli attacchi con arma del solar sono magici. Quando colpisce con qualsiasi arma, l''arma infligge 6d8 danni radianti aggiuntivi (già compresi nell''attacco)."},{"name":"Consapevolezza Divina","usage":null,"description":"Il solar riconosce immediatamente le bugie."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del solar è il Carisma (CD 25 per i tiri salvezza degli incantesimi). Il solar può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti materiali: A volontà: individuazione del bene e del male, invisibilità (solo personale) 3/giorno: barriera di lame, colpo infuocato, dissolvi il bene e il male, resurrezione 1/giorno: comunione, controllare tempo atmosferico"},{"name":"Resistenza alla Magia","usage":null,"description":"Il solar ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il solar effettua due attacchi con lo spadone."},{"name":"Spadone","usage":null,"description":"Attacco con arma da mischia: +15 a colpire, portata 1,5 m, un bersaglio. Colpisce: 22 (4d6 + 8) danni taglienti più 27 (6d8) danni radianti."},{"name":"Arco Lungo dell''Uccisione","usage":null,"description":"Attacco con arma a distanza: +13 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 15 (2d8 + 6) danni perforanti più 27 (6d8) danni radianti. Se il bersaglio è una creatura con 100 punti ferita o meno, deve riuscire un tiro salvezza di Costituzione CD 15 o morire."},{"name":"Spada Volante","usage":null,"description":"Il solare libera il suo spadone perché fluttui magicamente in uno spazio non occupato entro 1,5 metri da lui. Se il solare può vedere la spada, con un''azione bonus le può ordinare mentalmente di volare per un massimo di 15 metri ed effettuare un attacco contro un bersaglio o ritornare nella mano del solare. Se la spada fluttuante è bersaglio di un effetto, si considera come se fosse impugnata dal solare. Se il solare muore, la spada fluttuante cade a terra."},{"name":"Tocco Guaritore","usage":"4/Giorno","description":"Il solare entra a contatto con un''altra creatura. Il bersaglio recupera magicamente 40 (8d8 + 4) punti ferita ed è libero da qualsiasi cecità, malattia, maledizione, sordità o veleno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"Il solare può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. Il solare recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Esplosione Incandescente","description":"Il solare emette energia magica divina. Ogni creatura di sua scelta, in un raggio di 3 metri, deve effettuare un tiro salvezza di Destrezza CD 23, subendo 14 (4d6) danni da fuoco più 14 (4d6) danni radianti se fallisce il tiro salvezza, o la metà se lo riesce.","cost":2},{"name":"Sguardo Accecante","description":"Il solare prende a bersaglio una creatura entro 9 metri e che possa vedere. Se il bersaglio può vedere il solare, il bersaglio deve riuscire un tiro salvezza di Costituzione CD 15 o restare accecato finché un incantesimo come ristorare inferiore non rimuoverà la cecità.","cost":3},{"name":"Teletrasporto","description":"Il solare si teletrasporta magicamente fino a 36 metri di distanza, insieme a tutto l''equipaggiamento che sta indossando o trasportando, in uno spazio non occupato e che può vedere.","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Angelo Solar\nGrande celestiale, legale buono\nFORZA 26 (+8)\nDESTREZZA 22 (+6)\nCOSTITUZIONE 26 (+8)\nINTELLIGENZA 25 (+7)\nSAGGEZZA 25 (+7)\nCARISMA 30 (+10)\nClasse Armatura 21 (armatura naturale)\nPunti Ferita 243 (18d10 + 144)\nVelocità 15 m, volo 45 m\nTiri Salvezza Intelligenza +14, Saggezza +14, Carisma +17\nAbilità Percezione +14\nResistenze ai Danni radiante; contundente, perforante e tagliente\ndi attacchi non magici\nImmunità ai Danni necrotico, veleno\nImmunità alle Condizioni affascinato, avvelenato, sfinimento,\nspaventato\nSensi visione del vero 36 m, Percezione passiva 24\nLinguaggi tutte, telepatia 36 m\nSfida 21 (33.000 PE)\nArmi Angeliche. Gli attacchi con arma del solar sono magici.\nQuando colpisce con qualsiasi arma, l''arma infligge 6d8 danni\nradianti aggiuntivi (già compresi nell''attacco).\nConsapevolezza Divina. Il solar riconosce immediatamente le\nbugie.\nIncantesimi Innati. La caratteristica da incantatore innato del\nsolar è il Carisma (CD 25 per i tiri salvezza degli incantesimi). Il\nsolar può lanciare in maniera innata i seguenti incantesimi, senza\nbisogno di componenti materiali:\nA volontà: individuazione del bene e del male, invisibilità (solo\npersonale)\n3/giorno: barriera di lame, colpo infuocato, dissolvi il bene e il\nmale, resurrezione\n1/giorno: comunione, controllare tempo atmosferico\nResistenza alla Magia. Il solar ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. Il solar effettua due attacchi con lo spadone.\nSpadone. Attacco con arma da mischia: +15 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 22 (4d6 + 8) danni taglienti più 27 (6d8) danni radianti.\nArco Lungo dell''Uccisione. Attacco con arma a distanza: +13 a\ncolpire, gittata 45/180 m, un bersaglio.\nColpisce: 15 (2d8 + 6) danni perforanti più 27 (6d8) danni radianti.\nSe il bersaglio è una creatura con 100 punti ferita o meno, deve\nriuscire un tiro salvezza di Costituzione CD 15 o morire.\nSpada Volante. Il solare libera il suo spadone perché fluttui\nmagicamente in uno spazio non occupato entro 1,5 metri da lui.\nSe il solare può vedere la spada, con un''azione bonus le può\nordinare mentalmente di volare per un massimo di 15 metri ed\neffettuare un attacco contro un bersaglio o ritornare nella mano\ndel solare. Se la spada fluttuante è bersaglio di un effetto, si\nconsidera come se fosse impugnata dal solare. Se il solare muore,\nla spada fluttuante cade a terra.\nTocco Guaritore (4/Giorno). Il solare entra a contatto con\nun''altra creatura. Il bersaglio recupera magicamente 40 (8d8 + 4)\npunti ferita ed è libero da qualsiasi cecità, malattia, maledizione,\nsordità o veleno.\nAzioni Leggendarie\nIl solare può effettuare 3 azioni leggendarie, scelte tra le opzioni\nseguenti. Può usare solo un''opzione leggendaria alla volta e solo\nal termine del turno di un''altra creatura. Il solare recupera le\nazioni leggendarie spese all''inizio del proprio turno.\nEsplosione Incandescente (Costa 2 Azioni). Il solare emette\nenergia magica divina. Ogni creatura di sua scelta, in un raggio di 3\nmetri, deve effettuare un tiro salvezza di Destrezza CD 23, subendo\n14 (4d6) danni da fuoco più 14 (4d6) danni radianti se fallisce il tiro\nsalvezza, o la metà se lo riesce.\nSguardo Accecante (Costa 3 Azioni). Il solare prende a\nbersaglio una creatura entro 9 metri e che possa vedere. Se il\nbersaglio può vedere il solare, il bersaglio deve riuscire un tiro\nsalvezza di Costituzione CD 15 o restare accecato finché un\nincantesimo come ristorare inferiore non rimuoverà la cecità.\nTeletrasporto. Il solare si teletrasporta magicamente fino a 36 metri\ndi distanza, insieme a tutto l''equipaggiamento che sta indossando o\ntrasportando, in uno spazio non occupato e che può vedere."}}', '2026-03-30T16:00:32.231Z', '2026-03-30T16:00:32.231Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hbmtoZWcuanNvbg', 'ankheg', 'Ankheg', 'SRD', 'srd-extracted/ankheg.json', '2', 2, 450, 'Grande', 'mostruosità', 'disallineato', '{"slug":"ankheg","general":{"name":"Ankheg","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":0,"note":""},"hitPoints":{"average":39,"formula":"6d10 + 6"},"speed":{"walk":"9 m","burrow":"3 m"}},"abilities":{"strength":17,"dexterity":11,"constitution":13,"intelligence":1,"wisdom":13,"charisma":6},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"percezione tellurica","value":"18 m"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni taglienti più 3 (1d6) danni da acido. Se il bersaglio è una creatura di taglia Grande o inferiore, è afferrata (CD 13 per fuggire). Fino al termine dell''afferrare, l''ankheg può mordere solo la creatura afferrata e ha vantaggio ai tiri di attacco contro di essa."},{"name":"Spruzzo Acido","usage":"Ricarica 6","description":"L''ankheg sputa acido in una linea lunga 9 metri e larga 1,5 metri, purché non stia afferrando nessuna creatura. Ogni creatura su quella linea deve effettuare un tiro salvezza di Destrezza CD 13, e subire 10 (3d6) danni da acido se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Ankheg\nGrande mostruosità, disallineato\nFORZA 17 (+3)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 13 (+1)\nCARISMA 6 (-2)\nClasse Armatura 14 (armatura naturale), 11 mentre è prono\nPunti Ferita 39 (6d10 + 6)\nVelocità 9 m, scavo 3 m\nSensi scurovisione 18 m, percezione tellurica 18 m, Percezione\npassiva 11\nLinguaggi -\nSfida 2 (450 PE)\nAzioni\nMorso. Attacco con arma da mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni taglienti più 3 (1d6) danni da acido.\nSe il bersaglio è una creatura di taglia Grande o inferiore, è\nafferrata (CD 13 per fuggire). Fino al termine dell''afferrare,\nl''ankheg può mordere solo la creatura afferrata e ha vantaggio ai\ntiri di attacco contro di essa.\nSpruzzo Acido (Ricarica 6). L''ankheg sputa acido in una linea\nlunga 9 metri e larga 1,5 metri, purché non stia afferrando\nnessuna creatura. Ogni creatura su quella linea deve effettuare un\ntiro salvezza di Destrezza CD 13, e subire 10 (3d6) danni da\nacido se fallisce il tiro salvezza, o la metà di questi danni se lo\nriesce."}}', '2026-03-30T16:00:32.232Z', '2026-03-30T16:00:32.232Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hcXVpbGEtZ2lnYW50ZS5qc29u', 'aquila-gigante', 'Aquila Gigante', 'SRD', 'srd-extracted/aquila-gigante.json', '1', 1, 200, NULL, NULL, NULL, '{"slug":"aquila-gigante","general":{"name":"Aquila Gigante","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":13,"note":""},"hitPoints":{"average":26,"formula":"4d10 + 4"},"speed":{"walk":"3 m","fly":"24 m"}},"abilities":{"strength":16,"dexterity":17,"constitution":13,"intelligence":8,"wisdom":14,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 14"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Vista Affinata","usage":null,"description":"L''aquila ha vantaggio nelle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''aquila effettua due attacchi: uno con il becco e uno con gli speroni."},{"name":"Becco","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni perforanti."},{"name":"Speroni","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Aquila Gigante\nL''aquila gigante è una nobile creatura che parla la\npropria lingua e comprende quella di altre razze.\nGrande bestia, neutrale buono\nFORZA 16 (+3)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 8 (-1)\nSAGGEZZA 14 (+2)\nCARISMA 10 (+0)\nClasse Armatura 13\nPunti Ferita 26 (4d10 + 4)\nVelocità 3 m, volo 24 m\nAbilità Percezione +4\nSensi Percezione passiva 14\nLingue Aquila Gigante, comprende il Comune e l''Aereo ma non\npuò parlarli\nSfida 1 (200 PE)\nVista Affinata. L''aquila ha vantaggio nelle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nMultiattacco. L''aquila effettua due attacchi: uno con il becco e\nuno con gli speroni.\nBecco. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d6 + 3) danni perforanti.\nSperoni. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni taglienti."}}', '2026-03-30T16:00:32.410Z', '2026-03-30T16:00:32.410Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hcXVpbGEuanNvbg', 'aquila', 'Aquila', 'SRD', 'srd-extracted/aquila.json', '0', 0, 10, 'Piccola', 'bestia', 'disallineato', '{"slug":"aquila","general":{"name":"Aquila","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Piccola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":3,"formula":"1d6"},"speed":{"walk":"3 m","fly":"18 m"}},"abilities":{"strength":6,"dexterity":15,"constitution":10,"intelligence":2,"wisdom":14,"charisma":7},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 14"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Vista Affinata","usage":null,"description":"L''aquila ha vantaggio nelle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Speroni","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Aquila\nPiccola bestia, disallineato\nFORZA 6 (-2)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 14 (+2)\nCARISMA 7 (-2)\nClasse Armatura 12\nPunti Ferita 3 (1d6)\nVelocità 3 m, volo 18 m\nAbilità Percezione +4\nSensi Percezione passiva 14\nLingue -\nSfida 0 (10 PE)\nVista Affinata. L''aquila ha vantaggio nelle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nSperoni. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d4 + 2) danni taglienti."}}', '2026-03-30T16:00:32.409Z', '2026-03-30T16:00:32.409Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hcmNpbWFnaW8uanNvbg', 'arcimagio', 'Arcimagio', 'SRD', 'srd-extracted/arcimagio.json', '12', 12, 8400, NULL, NULL, NULL, '{"slug":"arcimagio","general":{"name":"Arcimagio","challengeRating":{"fraction":"12","decimal":12,"display":"12","xp":8400},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"15 con armatura del magio"},"hitPoints":{"average":99,"formula":"18d8 + 18"},"speed":{"walk":"9 m"}},"abilities":{"strength":10,"dexterity":14,"constitution":12,"intelligence":20,"wisdom":15,"charisma":16},"details":{"savingThrows":[{"ability":"Intelligenza","bonus":9},{"ability":"Saggezza","bonus":6}],"skills":[{"name":"Arcano","bonus":13},{"name":"Storia","bonus":13}],"damageVulnerabilities":[],"damageResistances":["danno degli incantesimi; contundente"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 12"}],"languages":[],"proficiencyBonus":4},"traits":[{"name":"Incantesimi","usage":null,"description":"Il magio è un incantatore di 18° livello. La sua abilità da incantatore è l''Intelligenza (CD dei tiri salvezza degli incantesimi 17, +9 al colpire con attacchi con incantesimo). L''arcimagio può eseguire camuffare sé stesso e invisibilità a volontà e ha preparato i seguenti incantesimi da mago: Trucchetti (a volontà): dardo infuocato, luce, mano magica, prestidigitazione, stretta folgorante 1° livello (4 slot): armatura magica*, dardo incantato, identificare, individuare magia 2° livello (3 slot): immagine speculare, individuazione dei pensieri, passo velato 3° livello (3 slot): controincantesimo, fulmine 4° livello (3 slot): esilio, pelle di pietra*, scudo di fuoco 5° livello (3 slot): cono di freddo, muro di forza, scrutare 6° livello (1 slot): globo di invulnerabilità 7° livello (1 slot): teletrasporto 8° livello (1 slot): vuoto mentale* 9° livello (1 slot): fermare il tempo * L''arcimagio esegue questi incantesimi su di sé prima del combattimento."}],"actions":[{"name":"Pugnale","usage":null,"description":"Attacco con Arma da Mischia o a Gittata: +6 a colpire, portata 1,5 m o gittata 6/18 m, un bersaglio. Colpisce: 4 (1d4 + 2) danni perforanti. Sacerdoti I sacerdoti sono devoti di una divinità o una fede che si prendono cura di impartire gli insegnamenti divini al loro gregge."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Arcimagio\nUn mago molto potente (e anche molto anziano) che\nstudia i segreti del multiverso.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 10 (+0)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 20 (+5)\nSAGGEZZA 15 (+2)\nCARISMA 16 (+3)\nClasse Armatura 12 (15 con armatura del magio)\nPunti Ferita 99 (18d8 + 18)\nVelocità 9 m\nTiri Salvezza Intelligenza +9, Saggezza +6\nAbilità Arcano +13, Storia +13\nResistenze al Danno danno degli incantesimi; contundente,\nperforante e tagliente non magico (da pelle di pietra)\nSensi Percezione passiva 12\nLingue sei lingue qualsiasi\nSfida 12 (8.400 PE)\nIncantesimi. Il magio è un incantatore di 18° livello. La sua\nabilità da incantatore è l''Intelligenza (CD dei tiri salvezza degli\nincantesimi 17, +9 al colpire con attacchi con incantesimo).\nL''arcimagio può eseguire camuffare sé stesso e invisibilità a\nvolontà e ha preparato i seguenti incantesimi da mago:\nTrucchetti (a volontà): dardo infuocato, luce, mano magica,\nprestidigitazione, stretta folgorante\n1° livello (4 slot): armatura magica*, dardo incantato,\nidentificare, individuare magia\n2° livello (3 slot): immagine speculare, individuazione dei\npensieri, passo velato\n3° livello (3 slot): controincantesimo, fulmine\n4° livello (3 slot): esilio, pelle di pietra*, scudo di fuoco\n5° livello (3 slot): cono di freddo, muro di forza, scrutare\n6° livello (1 slot): globo di invulnerabilità\n7° livello (1 slot): teletrasporto\n8° livello (1 slot): vuoto mentale*\n9° livello (1 slot): fermare il tempo\n* L''arcimagio esegue questi incantesimi su di sé prima del\ncombattimento.\nAzioni\nPugnale. Attacco con Arma da Mischia o a Gittata: +6 a colpire,\nportata 1,5 m o gittata 6/18 m, un bersaglio.\nColpisce: 4 (1d4 + 2) danni perforanti.\nSacerdoti\nI sacerdoti sono devoti di una divinità o una fede che si\nprendono cura di impartire gli insegnamenti divini al loro\ngregge."}}', '2026-03-30T16:00:32.493Z', '2026-03-30T16:00:32.493Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hcm1hdHVyYS1hbmltYXRhLmpzb24', 'armatura-animata', 'Armatura Animata', 'SRD', 'srd-extracted/armatura-animata.json', '1', 1, 200, 'Media', 'costrutto', 'disallineato', '{"slug":"armatura-animata","general":{"name":"Armatura Animata","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Media","creatureType":"costrutto","subtype":"","typeLabel":"costrutto","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura naturale"},"hitPoints":{"average":33,"formula":"6d8 + 6"},"speed":{"walk":"5 m"}},"abilities":{"strength":14,"dexterity":11,"constitution":13,"intelligence":1,"wisdom":3,"charisma":1},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["psichico","veleno"],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieco oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Falso Aspetto","usage":null,"description":"Mentre l''armatura rimane immobile, è indistinguibile da una normale armatura."},{"name":"Suscettibilità all''Anti Magia","usage":null,"description":"L''armatura è inabile se si trova nell''area di un campo anti-magia. Se è bersaglio di dissolvi magie, l''armatura deve riuscire un tiro salvezza di Costituzione contro la CD del tiro salvezza dell''incantesimo o restare svenuta per 1 minuto."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''armatura effettua due attacchi da mischia."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Armatura Animata\nMedia costrutto, disallineato\nFORZA 14 (+2)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 3 (-4)\nCARISMA 1 (-5)\nClasse Armatura 18 (armatura naturale)\nPunti Ferita 33 (6d8 + 6)\nVelocità 7,5 m\nImmunità al Danno psichico, veleno\nImmunità alle Condizioni accecato, affascinato, assordato,\navvelenato, paralizzato, pietrificato, sfinimento, spaventato\nSensi vista cieca 18 m (cieco oltre questo raggio), Percezione\npassiva 6\nLinguaggi -\nSfida 1 (200 PE)\nFalso Aspetto. Mentre l''armatura rimane immobile, è\nindistinguibile da una normale armatura.\nSuscettibilità all''Anti Magia. L''armatura è inabile se si trova\nnell''area di un campo anti-magia. Se è bersaglio di dissolvi\nmagie, l''armatura deve riuscire un tiro salvezza di Costituzione\ncontro la CD del tiro salvezza dell''incantesimo o restare svenuta\nper 1 minuto.\nAzioni\nMultiattacco. L''armatura effettua due attacchi da mischia.\nSchianto. Attacco con arma da mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 5 (1d6 + 2) danni contundenti."}}', '2026-03-30T16:00:32.362Z', '2026-03-30T16:00:32.362Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hcnBpYS5qc29u', 'arpia', 'Arpia', 'SRD', 'srd-extracted/arpia.json', '1', 1, 200, 'Media', 'mostruosità', 'caotico malvagio', '{"slug":"arpia","general":{"name":"Arpia","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Media","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":11,"note":""},"hitPoints":{"average":38,"formula":"7d8 + 7"},"speed":{"walk":"6 m","fly":"12 m"}},"abilities":{"strength":12,"dexterity":13,"constitution":12,"intelligence":7,"wisdom":10,"charisma":13},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[{"name":"Comune"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"L''armatura effettua due attacchi: uno con gli artigli e uno con il randello."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (2d4 + 1) danni taglienti."},{"name":"Randello","usage":null,"description":"Attacco con arma da mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 3 (1d4 + 1) danni contundenti."},{"name":"Canto Ammaliatore","usage":null,"description":"L''arpia canta una melodia magica. Ogni umanoide e gigante entro 90 metri dall''arpia e che possa udire la canzone deve riuscire un tiro salvezza di Saggezza CD 11 o restare affascinato fino al termine della canzone. L''arpia deve effettuare un''azione bonus durante il suo prossimo turno per continuare a cantare. Può smettere di cantare in qualsiasi momento. Il canto ha termine se l''arpia è inabile. Mentre è affascinato dall''arpia, un bersaglio è inabile e ignora le canzoni di altre arpie. Se il bersaglio affascinato si trova a più di 1,5 metri dall''arpia, il bersaglio deve muoversi durante il proprio turno per dirigersi verso l''arpia usando la via più diretta. Egli non eviterà attacchi di opportunità, ma prima di muoversi in un terreno pericoloso, come lava o un pozzo, e prima di subire danno da qualsiasi fonte che non sia l''arpia, il bersaglio potrà ripetere il tiro salvezza. Una creatura può ripetere il tiro salvezza al termine di ciascun proprio turno. Se il tiro salvezza ha successo, l''effetto ha termine per quel bersaglio. Un bersaglio che riesce il tiro salvezza è immune al canto di quell''arpia per le successive 24 ore."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Arpia\nMedia mostruosità, caotico malvagio\nFORZA 12 (+1)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 10 (+0)\nCARISMA 13 (+1)\nClasse Armatura 11\nPunti Ferita 38 (7d8 + 7)\nVelocità 6 m, volo 12 m\nSensi Percezione passiva 10\nLinguaggi Comune\nSfida 1 (200 PE)\nAzioni\nMultiattacco. L''armatura effettua due attacchi: uno con gli\nartigli e uno con il randello.\nArtigli. Attacco con arma da mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (2d4 + 1) danni taglienti.\nRandello. Attacco con arma da mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 3 (1d4 + 1) danni contundenti.\nCanto Ammaliatore. L''arpia canta una melodia magica. Ogni\numanoide e gigante entro 90 metri dall''arpia e che possa udire la\ncanzone deve riuscire un tiro salvezza di Saggezza CD 11 o\nrestare affascinato fino al termine della canzone. L''arpia deve\neffettuare un''azione bonus durante il suo prossimo turno per\ncontinuare a cantare. Può smettere di cantare in qualsiasi\nmomento. Il canto ha termine se l''arpia è inabile.\nMentre è affascinato dall''arpia, un bersaglio è inabile e ignora le\ncanzoni di altre arpie. Se il bersaglio affascinato si trova a più di\n1,5 metri dall''arpia, il bersaglio deve muoversi durante il proprio\nturno per dirigersi verso l''arpia usando la via più diretta. Egli\nnon eviterà attacchi di opportunità, ma prima di muoversi in un\nterreno pericoloso, come lava o un pozzo, e prima di subire\ndanno da qualsiasi fonte che non sia l''arpia, il bersaglio potrà\nripetere il tiro salvezza. Una creatura può ripetere il tiro salvezza\nal termine di ciascun proprio turno. Se il tiro salvezza ha\nsuccesso, l''effetto ha termine per quel bersaglio.\nUn bersaglio che riesce il tiro salvezza è immune al canto di\nquell''arpia per le successive 24 ore."}}', '2026-03-30T16:00:32.233Z', '2026-03-30T16:00:32.233Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hdnZvbHRvaW8tZ2lnYW50ZS5qc29u', 'avvoltoio-gigante', 'Avvoltoio Gigante', 'SRD', 'srd-extracted/avvoltoio-gigante.json', '1', 1, 200, NULL, NULL, NULL, '{"slug":"avvoltoio-gigante","general":{"name":"Avvoltoio Gigante","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":22,"formula":"3d10 + 6"},"speed":{"walk":"3 m","fly":"18 m"}},"abilities":{"strength":15,"dexterity":10,"constitution":15,"intelligence":6,"wisdom":12,"charisma":7},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Olfatto e Vista Affinati","usage":null,"description":"L''avvoltoio ha vantaggio nelle prove di"},{"name":"Saggezza (Percezione) basate su olfatto o vista","usage":null,"description":""},{"name":"Tattiche di Branco","usage":null,"description":"L''avvoltoio ha vantaggio al tiro di attacco contro una creatura se almeno uno degli alleati dell''avvoltoio si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''avvoltoio effettua due attacchi: uno con il becco e uno con gli speroni."},{"name":"Becco","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (2d4 + 2) danni perforanti."},{"name":"Speroni","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 9 (2d6 + 2) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Avvoltoio Gigante\nL''avvoltoio gigante possiede un''intelligenza superiore e\nun''attitudine maligna.\nGrande bestia, neutrale malvagio\nFORZA 15 (+2)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 6 (-2)\nSAGGEZZA 12 (+1)\nCARISMA 7 (-2)\nClasse Armatura 10\nPunti Ferita 22 (3d10 + 6)\nVelocità 3 m, volo 18 m\nAbilità Percezione +3\nSensi Percezione passiva 13\nLingue comprende il Comune ma non può parlare\nSfida 1 (200 PE)\nOlfatto e Vista Affinati. L''avvoltoio ha vantaggio nelle prove di\nSaggezza (Percezione) basate su olfatto o vista.\nTattiche di Branco. L''avvoltoio ha vantaggio al tiro di attacco\ncontro una creatura se almeno uno degli alleati dell''avvoltoio si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMultiattacco. L''avvoltoio effettua due attacchi: uno con il becco\ne uno con gli speroni.\nBecco. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 7 (2d4 + 2) danni perforanti.\nSperoni. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 9 (2d6 + 2) danni taglienti."}}', '2026-03-30T16:00:32.412Z', '2026-03-30T16:00:32.412Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hdnZvbHRvaW8uanNvbg', 'avvoltoio', 'Avvoltoio', 'SRD', 'srd-extracted/avvoltoio.json', '0', 0, 10, 'Media', 'bestia', 'disallineato', '{"slug":"avvoltoio","general":{"name":"Avvoltoio","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Media","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":5,"formula":"1d8 + 1"},"speed":{"walk":"3 m","fly":"15 m"}},"abilities":{"strength":7,"dexterity":10,"constitution":13,"intelligence":2,"wisdom":12,"charisma":4},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Olfatto e Vista Affinati","usage":null,"description":"L''avvoltoio ha vantaggio nelle prove di"},{"name":"Saggezza (Percezione) basate su olfatto o vista","usage":null,"description":""},{"name":"Tattiche di Branco","usage":null,"description":"L''avvoltoio ha vantaggio al tiro di attacco contro una creatura se almeno uno degli alleati dell''avvoltoio si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Becco","usage":null,"description":"Attacco con Arma da Mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 2 (1d4) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Avvoltoio\nMedia bestia, disallineato\nFORZA 7 (-2)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 4 (-3)\nClasse Armatura 10\nPunti Ferita 5 (1d8 + 1)\nVelocità 3 m, volo 15 m\nAbilità Percezione +3\nSensi Percezione passiva 13\nLingue -\nSfida 0 (10 PE)\nOlfatto e Vista Affinati. L''avvoltoio ha vantaggio nelle prove di\nSaggezza (Percezione) basate su olfatto o vista.\nTattiche di Branco. L''avvoltoio ha vantaggio al tiro di attacco\ncontro una creatura se almeno uno degli alleati dell''avvoltoio si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nBecco. Attacco con Arma da Mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 2 (1d4) danni perforanti."}}', '2026-03-30T16:00:32.411Z', '2026-03-30T16:00:32.411Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9hemVyLmpzb24', 'azer', 'Azer', 'SRD', 'srd-extracted/azer.json', '2', 2, 450, 'Media', 'elementale', 'legale neutrale', '{"slug":"azer","general":{"name":"Azer","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Media","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"legale neutrale","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale, scudo"},"hitPoints":{"average":39,"formula":"6d8 + 12"},"speed":{"walk":"9 m"}},"abilities":{"strength":17,"dexterity":12,"constitution":15,"intelligence":12,"wisdom":13,"charisma":10},"details":{"savingThrows":[{"ability":"Costituzione","bonus":4}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"Percezione passiva 11"}],"languages":[{"name":"Ignan"}],"proficiencyBonus":2},"traits":[{"name":"Armi Riscaldate","usage":null,"description":"Quando l''azer colpisce con un''arma da mischia in metallo, infligge 3 (1d6) danni da fuoco aggiuntivi (già inclusi nell''attacco)."},{"name":"Corpo Riscaldato","usage":null,"description":"Una creatura che entri a contatto con l''azer o lo colpisca con un attacco da mischia mentre si trova entro 1,5 metri da lui subisce 5 (1d10) danni da fuoco."},{"name":"Fuoco Vivente","usage":null,"description":"Un azer non ha bisogno di cibo, bevande o di dormire."},{"name":"Illuminazione","usage":null,"description":"L''azer irradia luce intensa in un raggio di 3 metri e luce fioca per ulteriori 3 metri."}],"actions":[{"name":"Martello da Guerra","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d8 + 3) danni contundenti, o 8 (1d10 + 3) danni contundenti se usato a due mani per effettuare un attacco da mischia, più 3 (1d6) danni da fuoco."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Azer\nMedia elementale, legale neutrale\nFORZA 17 (+3)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 13 (+1)\nCARISMA 10 (+0)\nClasse Armatura 17 (armatura naturale, scudo)\nPunti Ferita 39 (6d8 + 12)\nVelocità 9 m\nTiri Salvezza Costituzione +4\nImmunità ai Danni fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi Percezione passiva 11\nLinguaggi Ignan\nSfida 2 (450 PE)\nArmi Riscaldate. Quando l''azer colpisce con un''arma da mischia\nin metallo, infligge 3 (1d6) danni da fuoco aggiuntivi (già inclusi\nnell''attacco).\nCorpo Riscaldato. Una creatura che entri a contatto con l''azer o\nlo colpisca con un attacco da mischia mentre si trova entro 1,5\nmetri da lui subisce 5 (1d10) danni da fuoco.\nFuoco Vivente. Un azer non ha bisogno di cibo, bevande o di\ndormire.\nIlluminazione. L''azer irradia luce intensa in un raggio di 3 metri\ne luce fioca per ulteriori 3 metri.\nAzioni\nMartello da Guerra. Attacco con arma da mischia: +5 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 7 (1d8 + 3) danni contundenti, o 8 (1d10 + 3) danni\ncontundenti se usato a due mani per effettuare un attacco da\nmischia, più 3 (1d6) danni da fuoco."}}', '2026-03-30T16:00:32.234Z', '2026-03-30T16:00:32.234Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iYWJidWluby5qc29u', 'babbuino', 'Babbuino', 'SRD', 'srd-extracted/babbuino.json', '0', 0, 10, 'Piccola', 'bestia', 'disallineato', '{"slug":"babbuino","general":{"name":"Babbuino","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Piccola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":3,"formula":"1d6"},"speed":{"walk":"9 m","climb":"9 m"}},"abilities":{"strength":8,"dexterity":14,"constitution":11,"intelligence":4,"wisdom":12,"charisma":6},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 11"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Tattiche di Branco","usage":null,"description":"Il babbuino ha vantaggio al tiro di attacco contro una creatura se almeno uno degli alleati del babbuino si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +1 a colpire, portata 1,5 m, un bersaglio. Colpisce: 1 (1d4 - 1) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Babbuino\nPiccola bestia, disallineato\nFORZA 8 (-1)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 4 (-3)\nSAGGEZZA 12 (+1)\nCARISMA 6 (-2)\nClasse Armatura 12\nPunti Ferita 3 (1d6)\nVelocità 9 m, scalata 9 m\nSensi Percezione passiva 11\nLingue -\nSfida 0 (10 PE)\nTattiche di Branco. Il babbuino ha vantaggio al tiro di attacco\ncontro una creatura se almeno uno degli alleati del babbuino si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con Arma da Mischia: +1 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 1 (1d4 - 1) danni perforanti."}}', '2026-03-30T16:00:32.412Z', '2026-03-30T16:00:32.412Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iYWxlbmEtYXNzYXNzaW5hLW9yY2EuanNvbg', 'balena-assassina-orca', 'Balena Assassina (Orca)', 'SRD', 'srd-extracted/balena-assassina-orca.json', '3', 3, 700, NULL, NULL, NULL, '{"slug":"balena-assassina-orca","general":{"name":"Balena Assassina (Orca)","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":90,"formula":"12d12 + 12"},"speed":{"walk":"0 m","swim":"18 m"}},"abilities":{"strength":19,"dexterity":10,"constitution":13,"intelligence":3,"wisdom":12,"charisma":7},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"36 m"},{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Ecolocazione","usage":null,"description":"La balena non può usare la vista cieca se assordata."},{"name":"Trattenere il Fiato","usage":null,"description":"La balena può trattenere il fiato per 30 minuti"},{"name":"Udito Affinato","usage":null,"description":"La balena ha vantaggio alle prove di Saggezza (Percezione) basate sull''udito."}],"actions":[{"name":"Becco","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Balena Assassina\n(Orca)\nEnorme bestia, disallineato\nFORZA 19 (+4)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 7 (-2)\nClasse Armatura 12 (armatura naturale)\nPunti Ferita 90 (12d12 + 12)\nVelocità 0 m, nuoto 18 m\nAbilità Percezione +3\nSensi vista cieca 36 m, Percezione passiva 13\nLingue -\nSfida 3 (700 PE)\nEcolocazione. La balena non può usare la vista cieca se\nassordata.\nTrattenere il Fiato. La balena può trattenere il fiato per 30\nminuti\nUdito Affinato. La balena ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''udito.\nAzioni\nMorso. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 21 (5d6 + 4) danni perforanti.\nBecco d''Ascia\nIl becco d''ascia è un grosso e slanciato volatile privo di\nali ma con potenti gambe, un becco a cuneo, e un\npessimo carattere.\nGrande bestia, disallineato\nFORZA 14 (+2)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 10 (+0)\nCARISMA 5 (-3)\nClasse Armatura 11\nPunti Ferita 19 (3d10 + 3)\nVelocità 15 m\nSensi Percezione passiva 10\nLingue -\nSfida 1/4 (50 PE)\nAzioni\nBecco. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d8 + 2) danni taglienti."}}', '2026-03-30T16:00:32.413Z', '2026-03-30T16:00:32.413Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iYWxvci5qc29u', 'balor', 'Balor', 'SRD', 'srd-extracted/balor.json', '19', 19, 22000, 'Enorme', 'immondo', 'caotico malvagio', '{"slug":"balor","general":{"name":"Balor","challengeRating":{"fraction":"19","decimal":19,"display":"19","xp":22000},"size":"Enorme","creatureType":"immondo","subtype":"demone","typeLabel":"immondo (demone)","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":262,"formula":"21d12 + 126"},"speed":{"walk":"12 m","fly":"24 m"}},"abilities":{"strength":26,"dexterity":15,"constitution":22,"intelligence":20,"wisdom":16,"charisma":22},"details":{"savingThrows":[{"ability":"Forza","bonus":14},{"ability":"Costituzione","bonus":12},{"ability":"Saggezza","bonus":9}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo","fulmine; contundente","perforante e"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 13"}],"languages":[{"name":"Abissale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":6},"traits":[{"name":"Armi Magiche","usage":null,"description":"Gli attacchi con arma del demone sono magici."},{"name":"Aura di Fuoco","usage":null,"description":"All''inizio di ciascun turno del demone, ciascuna creatura entro 1,5 metri da lui subisce 10 (3d6) danni da fuoco, e gli oggetti infiammabili che si trovano nell''aura e che non sono indossati o trasportati prendono fuoco. Una creatura che entri a contatto con il demone o lo colpisca con un attacco da mischia mentre si trova entro 1,5 metri da esso subisce 10 (3d6) danni da fuoco."},{"name":"Resistenza alla Magia","usage":null,"description":"Il demone ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."},{"name":"Spasmo Mortale","usage":null,"description":"Quando il demone muore, esplode; ciascuna creatura entro 9 metri da esso deve effettuare un tiro salvezza di Destrezza CD 20, subendo 70 (20d6) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce. L''esplosione appicca il fuoco agli oggetti infiammabili che non sono indossati o trasportati, e distrugge le armi del demone."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il demone effettua due attacchi: uno con la spada lunga e uno con la frusta."},{"name":"Frusta","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 9 m, un bersaglio. Colpisce: 15 (2d6 + 8) danni taglienti più 10 (3d6) danni da fuoco, e il bersaglio deve riuscire un tiro salvezza di Forza CD 20 o venire trascinato 7,5 metri verso il demone."},{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +14 a colpire, portata 3 m, un bersaglio. Colpisce: 21 (3d8 + 8) danni taglienti più 13 (3d8) danni da fulmine. Se il demone ottiene un colpo critico, tira il danno tre volte, invece che due."},{"name":"Teletrasporto","usage":null,"description":"Il demone si teletrasporta magicamente, insieme a tutto l''equipaggiamento che indossa o trasporta, in uno spazio non occupato e che può vedere entro 36 metri."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Balor\nEnorme immondo (demone), caotico malvagio\nFORZA 26 (+8)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 22 (+6)\nINTELLIGENZA 20 (+5)\nSAGGEZZA 16 (+3)\nCARISMA 22 (+6)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 262 (21d12 + 126)\nVelocità 12 m, volo 24 m\nTiri Salvezza Forza +14, Costituzione +12, Saggezza +9,\nCarisma +12\nResistenze al Danno freddo, fulmine; contundente, perforante e\ntagliente di attacchi non magici\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi visione del vero 36 m, Percezione passiva 13\nLinguaggi Abissale, telepatia 36 m\nSfida 19 (22.000 PE)\nArmi Magiche. Gli attacchi con arma del demone sono magici.\nAura di Fuoco. All''inizio di ciascun turno del demone, ciascuna\ncreatura entro 1,5 metri da lui subisce 10 (3d6) danni da fuoco, e\ngli oggetti infiammabili che si trovano nell''aura e che non sono\nindossati o trasportati prendono fuoco. Una creatura che entri a\ncontatto con il demone o lo colpisca con un attacco da mischia\nmentre si trova entro 1,5 metri da esso subisce 10 (3d6) danni da\nfuoco.\nResistenza alla Magia. Il demone ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nSpasmo Mortale. Quando il demone muore, esplode; ciascuna\ncreatura entro 9 metri da esso deve effettuare un tiro salvezza di\nDestrezza CD 20, subendo 70 (20d6) danni da fuoco se fallisce il\ntiro salvezza, o la metà di questi danni se lo riesce. L''esplosione\nappicca il fuoco agli oggetti infiammabili che non sono indossati\no trasportati, e distrugge le armi del demone.\nAzioni\nMultiattacco. Il demone effettua due attacchi: uno con la spada\nlunga e uno con la frusta.\nFrusta. Attacco con arma da mischia: +14 a colpire, portata 9 m,\nun bersaglio.\nColpisce: 15 (2d6 + 8) danni taglienti più 10 (3d6) danni da\nfuoco, e il bersaglio deve riuscire un tiro salvezza di Forza CD\n20 o venire trascinato 7,5 metri verso il demone.\nSpada Lunga. Attacco con arma da mischia: +14 a colpire,\nportata 3 m, un bersaglio.\nColpisce: 21 (3d8 + 8) danni taglienti più 13 (3d8) danni da\nfulmine. Se il demone ottiene un colpo critico, tira il danno tre\nvolte, invece che due.\nTeletrasporto. Il demone si teletrasporta magicamente, insieme a\ntutto l''equipaggiamento che indossa o trasporta, in uno spazio\nnon occupato e che può vedere entro 36 metri."}}', '2026-03-30T16:00:32.244Z', '2026-03-30T16:00:32.244Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iYW5kaXRvLXBpcmF0YS5qc29u', 'bandito-pirata', 'Bandito/Pirata', 'SRD', 'srd-extracted/bandito-pirata.json', '1/8', 0.125, 25, NULL, NULL, NULL, '{"slug":"bandito-pirata","general":{"name":"Bandito/Pirata","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura di cuoio"},"hitPoints":{"average":11,"formula":"2d8 + 2"},"speed":{"walk":"9 m"}},"abilities":{"strength":11,"dexterity":12,"constitution":12,"intelligence":10,"wisdom":10,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Intuizione","bonus":4},{"name":"Investigazione","bonus":5}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"La spia effettua due attacchi da mischia."},{"name":"Spada Corta","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."},{"name":"Balestrino","usage":null,"description":"Attacco con Arma a Gittata: +4 a colpire, gittata 9/36 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Bandito/Pirata\nChe siano uomini di strada o di mare (pirati) costoro\nguadagnano da vivere depredando il prossimo.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento non\nlegale\nFORZA 11 (+0)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 10 (+0)\nClasse Armatura 12 (armatura di cuoio)\nPunti Ferita 11 (2d8 + 2)\nVelocità 9 m\nSensi Percezione passiva 10\nLingue una qualsiasi lingua (di solito il Comune)\nSfida 1/8 (25 PE)\nAzioni\nScimitarra. Attacco con Arma da Mischia: +3 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 4 (1d6 + 1) danni taglienti.\nBalestra Leggera. Attacco con Arma a Gittata: +3 a colpire,\ngittata 24/96 metri, un bersaglio.\nColpisce: 5 (1d8 + 1) danni taglienti.\nSpia\nUna spia è un individuo addestramento nel reperire\nsegreti per conto di qualcuno, o a volte per rivenderli al\nmiglior offerente.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento\nFORZA 10 (+0)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 12 (+1)\nSAGGEZZA 14 (+2)\nCARISMA 16 (+3)\nClasse Armatura 12\nPunti Ferita 27 (6d8)\nVelocità 9 m\nAbilità Furtività +4, Intuizione +4, Investigazione +5,\nPercezione +6, Persuasione +5, Raggiro +5, Rapidità di Mano +4\nSensi Percezione passiva 16\nLingue due lingue qualsiasi\nSfida 1 (200 PE)\nAttacco Furtivo (1/Turno). La spia infligge 7 (2d6) danni aggiuntivi\nquando colpisce un bersaglio con un attacco con arma e ha vantaggio\nal tiro di attacco, o quando il bersaglio è entro 1,5 metri da un alleato\ndell''assassino che non è inabile e l''assassino non ha svantaggio al\ntiro di attacco.\nAzione Astuta. Durante ciascun suo turno, la spia può usare un''azione\nbonus per effettuare l''azione Disimpegnarsi, Nascondersi o Scattare.\nAzioni\nMultiattacco. La spia effettua due attacchi da mischia.\nSpada Corta. Attacco con Arma da Mischia: +4 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti.\nBalestrino. Attacco con Arma a Gittata: +4 a colpire, gittata 9/36\nm, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."}}', '2026-03-30T16:00:32.489Z', '2026-03-30T16:00:32.490Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iYXNpbGlzY28uanNvbg', 'basilisco', 'Basilisco', 'SRD', 'srd-extracted/basilisco.json', '3', 3, 700, 'Media', 'mostruosità', 'disallineato', '{"slug":"basilisco","general":{"name":"Basilisco","challengeRating":{"fraction":"3","decimal":3,"display":"3","xp":700},"size":"Media","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":52,"formula":"8d8 + 16"},"speed":{"walk":"6 m"}},"abilities":{"strength":16,"dexterity":8,"constitution":15,"intelligence":2,"wisdom":8,"charisma":7},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Sguardo Pietrificante","usage":null,"description":"Se una creatura comincia il suo turno entro 9 metri dal basilisco e i due si possono vedere vicendevolmente, se non è inabile il basilisco può obbligare la creatura ad effettuare un tiro salvezza di Costituzione CD 12. Se la creatura fallisce il tiro salvezza, inizia magicamente a trasformarsi in pietra ed è intralciata. La creatura deve ripetere il tiro salvezza al termine del suo prossimo turno. Se lo riesce, l''effetto termina. Se lo fallisce, la creatura è pietrificata finché non viene liberata dall''incantesimo ristorare superiore o altra magia. Una creatura che non sia sorpresa, può distogliere lo sguardo per evitare il tiro salvezza all''inizio del suo turno. In quel caso, non potrà vedere il basilisco fino all''inizio del suo prossimo turno, quando potrà distogliere nuovamente lo sguardo. Se nel frattempo dovesse guardare il basilisco, dovrebbe immediatamente effettuare il tiro salvezza. Se il basilisco si trova entro 9 metri dal suo riflesso a luce intensa e lo vede, lo scambia per un rivale e diventa il bersaglio del proprio sguardo."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni perforanti più 7 (2d6) danni da veleno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Basilisco\nMedia mostruosità, disallineato\nFORZA 16 (+3)\nDESTREZZA 8 (-1)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 8 (-1)\nCARISMA 7 (-2)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 52 (8d8 + 16)\nVelocità 6 m\nSensi scurovisione 18 m, Percezione passiva 9\nLinguaggi -\nSfida 3 (700 PE)\nSguardo Pietrificante. Se una creatura comincia il suo turno entro 9\nmetri dal basilisco e i due si possono vedere vicendevolmente, se non\nè inabile il basilisco può obbligare la creatura ad effettuare un tiro\nsalvezza di Costituzione CD 12. Se la creatura fallisce il tiro\nsalvezza, inizia magicamente a trasformarsi in pietra ed è intralciata.\nLa creatura deve ripetere il tiro salvezza al termine del suo prossimo\nturno. Se lo riesce, l''effetto termina. Se lo fallisce, la creatura è\npietrificata finché non viene liberata dall''incantesimo ristorare\nsuperiore o altra magia.\nUna creatura che non sia sorpresa, può distogliere lo sguardo per\nevitare il tiro salvezza all''inizio del suo turno. In quel caso, non\npotrà vedere il basilisco fino all''inizio del suo prossimo turno,\nquando potrà distogliere nuovamente lo sguardo. Se nel\nfrattempo dovesse guardare il basilisco, dovrebbe\nimmediatamente effettuare il tiro salvezza.\nSe il basilisco si trova entro 9 metri dal suo riflesso a luce intensa\ne lo vede, lo scambia per un rivale e diventa il bersaglio del\nproprio sguardo.\nAzioni\nMorso. Attacco con arma da mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni perforanti più 7 (2d6) danni da veleno."}}', '2026-03-30T16:00:32.235Z', '2026-03-30T16:00:32.235Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9iZWhpci5qc29u', 'behir', 'Behir', 'SRD', 'srd-extracted/behir.json', '11', 11, 7200, 'Enorme', 'mostruosità', 'neutrale malvagio', '{"slug":"behir","general":{"name":"Behir","challengeRating":{"fraction":"11","decimal":11,"display":"11","xp":7200},"size":"Enorme","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":168,"formula":"16d12 + 64"},"speed":{"walk":"15 m","climb":"12 m"}},"abilities":{"strength":23,"dexterity":16,"constitution":18,"intelligence":7,"wisdom":14,"charisma":12},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":7},{"name":"Percezione","bonus":6}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fulmine"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"27 m"},{"name":"Percezione passiva 16"}],"languages":[{"name":"Draconico"}],"proficiencyBonus":4},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"Il behir effettua due attacchi: uno con il morso e uno per stritolare."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 3 m, un bersaglio. Colpisce: 22 (3d10 + 6) danni perforanti."},{"name":"Stritolare","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, una creatura di taglia Grande o inferiore. Colpisce: 17 (2d10 + 6) danni contundenti più 17 (2d10 + 6) danni taglienti. Il bersaglio è afferrato (CD 16 per fuggire) Se il behir non sta già stritolando un''altra creatura, il bersaglio è afferrato e intralciato fino al termine dell''afferrare."},{"name":"Inghiottire","usage":null,"description":"Il behir effettua una attacco di morso contro un bersaglio di taglia Media o inferiore che sta afferrando. Se l''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha termine. Il bersaglio inghiottito è accecato e intralciato, ha copertura totale contro gli attacchi e altri effetti all''esterno del behir, e subisce 21 (6d6) danni da acido all''inizio di ciascun turno del behir. Il behir può inghiottire solo una creatura alla volta. Se il behir subisce 30 o più danni in un singolo turno da una creatura che ha inghiottito, deve riuscire un tiro salvezza di Costituzione CD 14 al termine di quel turno o vomitare la creatura, che ricade prona in uno spazio entro 3 metri dal behir. Se il behir muore, una creatura inghiottita non è più intralciata da esso e può uscire dal cadavere utilizzando 4,5 metri di movimento, uscendo prona."},{"name":"Soffio di Fulmine","usage":"Ricarica 5-6","description":"Il behir esala fulmini in una linea lunga 6 metri e larga 1,5 metri. Ogni creatura su quella linea deve effettuare un tiro salvezza di Destrezza CD 16 e subire 66 (12d10) danni da fulmine se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Behir\nEnorme mostruosità, neutrale malvagio\nFORZA 23 (+6)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 7 (-2)\nSAGGEZZA 14 (+2)\nCARISMA 12 (+1)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 168 (16d12 + 64)\nVelocità 15 m, scalata 12 m\nAbilità Furtività +7, Percezione +6\nImmunità al Danno fulmine\nSensi scurovisione 27 m, Percezione passiva 16\nLinguaggi Draconico\nSfida 11 (7.200 PE)\nAzioni\nMultiattacco. Il behir effettua due attacchi: uno con il morso e\nuno per stritolare.\nMorso. Attacco con arma da mischia: +10 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 22 (3d10 + 6) danni perforanti.\nStritolare. Attacco con arma da mischia: +10 a colpire, portata\n1,5 m, una creatura di taglia Grande o inferiore.\nColpisce: 17 (2d10 + 6) danni contundenti più 17 (2d10 + 6)\ndanni taglienti. Il bersaglio è afferrato (CD 16 per fuggire) Se il\nbehir non sta già stritolando un''altra creatura, il bersaglio è\nafferrato e intralciato fino al termine dell''afferrare.\nInghiottire. Il behir effettua una attacco di morso contro un\nbersaglio di taglia Media o inferiore che sta afferrando. Se\nl''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha\ntermine. Il bersaglio inghiottito è accecato e intralciato, ha\ncopertura totale contro gli attacchi e altri effetti all''esterno del\nbehir, e subisce 21 (6d6) danni da acido all''inizio di ciascun\nturno del behir. Il behir può inghiottire solo una creatura alla\nvolta.\nSe il behir subisce 30 o più danni in un singolo turno da una\ncreatura che ha inghiottito, deve riuscire un tiro salvezza di\nCostituzione CD 14 al termine di quel turno o vomitare la\ncreatura, che ricade prona in uno spazio entro 3 metri dal behir.\nSe il behir muore, una creatura inghiottita non è più intralciata da\nesso e può uscire dal cadavere utilizzando 4,5 metri di\nmovimento, uscendo prona.\nSoffio di Fulmine (Ricarica 5-6). Il behir esala fulmini in una\nlinea lunga 6 metri e larga 1,5 metri. Ogni creatura su quella\nlinea deve effettuare un tiro salvezza di Destrezza CD 16 e subire\n66 (12d10) danni da fulmine se fallisce il tiro salvezza, o la metà\ndi questi danni se lo riesce."}}', '2026-03-30T16:00:32.236Z', '2026-03-30T16:00:32.236Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9idWdiZWFyLmpzb24', 'bugbear', 'Bugbear', 'SRD', 'srd-extracted/bugbear.json', '1', 1, 200, 'Media', 'umanoide', 'caotico malvagio', '{"slug":"bugbear","general":{"name":"Bugbear","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Media","creatureType":"umanoide","subtype":"goblinoide","typeLabel":"umanoide (goblinoide)","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura di pelle, scudo"},"hitPoints":{"average":27,"formula":"5d8 + 5"},"speed":{"walk":"9 m"}},"abilities":{"strength":15,"dexterity":14,"constitution":13,"intelligence":8,"wisdom":11,"charisma":9},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":6},{"name":"Sopravvivenza","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Comune"},{"name":"Goblin"}],"proficiencyBonus":2},"traits":[{"name":"Attacco di Sorpresa","usage":null,"description":"Se il bugbear sorprende una creatura e la colpisce con un attacco durante il primo round di combattimento, il bersaglio subisce 7 (2d6) danni aggiuntivi dall''attacco."},{"name":"Bruto","usage":null,"description":"Un''arma da mischia infligge un dado aggiuntivo di danno quando il bugbear colpisce con essa (già incluso nell''attacco)."}],"actions":[{"name":"Mazza Chiodata","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d8 + 2) danni perforanti."},{"name":"Giavellotto","usage":null,"description":"Attacco con arma da mischia o a Distanza: +4 a colpire, portata 1,5 m o gittata 9/36 m, un bersaglio. Colpisce: 9 (2d6 + 2) danni perforanti in mischia o 5 (1d6 + 2) danni perforanti a gittata."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Bugbear\nMedia umanoide (goblinoide), caotico malvagio\nFORZA 15 (+2)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 8 (-1)\nSAGGEZZA 11 (+0)\nCARISMA 9 (-1)\nClasse Armatura 16 (armatura di pelle, scudo)\nPunti Ferita 27 (5d8 + 5)\nVelocità 9 m\nAbilità Furtività +6, Sopravvivenza +2\nSensi scurovisione 18 m, Percezione passiva 10\nLinguaggi Comune, Goblin\nSfida 1 (200 PE)\nAttacco di Sorpresa. Se il bugbear sorprende una creatura e la\ncolpisce con un attacco durante il primo round di combattimento,\nil bersaglio subisce 7 (2d6) danni aggiuntivi dall''attacco.\nBruto. Un''arma da mischia infligge un dado aggiuntivo di danno\nquando il bugbear colpisce con essa (già incluso nell''attacco).\nAzioni\nMazza Chiodata. Attacco con arma da mischia: +4 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 11 (2d8 + 2) danni perforanti.\nGiavellotto. Attacco con arma da mischia o a Distanza: +4 a\ncolpire, portata 1,5 m o gittata 9/36 m, un bersaglio.\nColpisce: 9 (2d6 + 2) danni perforanti in mischia o 5 (1d6 + 2)\ndanni perforanti a gittata."}}', '2026-03-30T16:00:32.238Z', '2026-03-30T16:00:32.238Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9idWxldHRlLmpzb24', 'bulette', 'Bulette', 'SRD', 'srd-extracted/bulette.json', '5', 5, 1800, 'Grande', 'mostruosità', 'disallineato', '{"slug":"bulette","general":{"name":"Bulette","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":94,"formula":"9d10 + 45"},"speed":{"walk":"12 m","burrow":"12 m"}},"abilities":{"strength":19,"dexterity":11,"constitution":21,"intelligence":2,"wisdom":10,"charisma":5},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":6}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"percezione tellurica","value":"18 m"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":3},"traits":[{"name":"Salto da Fermo","usage":null,"description":"Un bulette può saltare in lungo fino a 9 metri e in alto fino a 4,5 metri, con o senza la rincorsa."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 30 (4d12 + 4) danni perforanti."},{"name":"Salto Letale","usage":null,"description":"Se il bulette può saltare di almeno 4,5 metri come parte del suo movimento, può usare poi questa azione per atterrare in piedi in uno spazio che contiene una o più creature. Ciascuna di queste creature deve riuscire un tiro salvezza di Forza o Destrezza CD 16 (a scelta del bersaglio) o venire gettata prona e subire 14 (3d6 + 4) danni contundenti più 14 (3d6 + 4) danni taglienti. Se il tiro salvezza riesce, la creatura subisce solo la metà dei danni, non è gettata prona, e viene spinta di 1,5 metri fuori dello spazio del bulette in uno spazio non occupato a scelta della creatura. Se non ci sono spazi non occupati a gittata, la creatura cade prona nello spazio del bulette."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Bulette\nGrande mostruosità, disallineato\nFORZA 19 (+4)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 21 (+5)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 10 (+0)\nCARISMA 5 (-3)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 94 (9d10 + 45)\nVelocità 12 m, scavo 12 m\nAbilità Percezione +6\nSensi scurovisione 18 m, percezione tellurica 18 m, Percezione\npassiva 16\nLinguaggi -\nSfida 5 (1.800 PE)\nSalto da Fermo. Un bulette può saltare in lungo fino a 9 metri e\nin alto fino a 4,5 metri, con o senza la rincorsa.\nAzioni\nMorso. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 30 (4d12 + 4) danni perforanti.\nSalto Letale. Se il bulette può saltare di almeno 4,5 metri come\nparte del suo movimento, può usare poi questa azione per\natterrare in piedi in uno spazio che contiene una o più creature.\nCiascuna di queste creature deve riuscire un tiro salvezza di\nForza o Destrezza CD 16 (a scelta del bersaglio) o venire gettata\nprona e subire 14 (3d6 + 4) danni contundenti più 14 (3d6 + 4)\ndanni taglienti. Se il tiro salvezza riesce, la creatura subisce solo\nla metà dei danni, non è gettata prona, e viene spinta di 1,5 metri\nfuori dello spazio del bulette in uno spazio non occupato a scelta\ndella creatura. Se non ci sono spazi non occupati a gittata, la\ncreatura cade prona nello spazio del bulette."}}', '2026-03-30T16:00:32.238Z', '2026-03-30T16:00:32.239Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jYW1tZWxsby5qc29u', 'cammello', 'Cammello', 'SRD', 'srd-extracted/cammello.json', '1/8', 0.125, 25, 'Grande', 'bestia', 'disallineato', '{"slug":"cammello","general":{"name":"Cammello","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":9,"note":""},"hitPoints":{"average":15,"formula":"2d10 + 4"},"speed":{"walk":"15 m"}},"abilities":{"strength":16,"dexterity":8,"constitution":14,"intelligence":2,"wisdom":8,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 9"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 2 (1d4) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cammello\nGrande bestia, disallineato\nFORZA 16 (+3)\nDESTREZZA 8 (-1)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 8 (-1)\nCARISMA 5 (-3)\nClasse Armatura 9\nPunti Ferita 15 (2d10 + 4)\nVelocità 15 m\nSensi Percezione passiva 9\nLingue -\nSfida 1/8 (25 PE)\nAzioni\nMorso. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 2 (1d4) danni contundenti."}}', '2026-03-30T16:00:32.414Z', '2026-03-30T16:00:32.414Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jYW5lLWRlbGxhLW1vcnRlLmpzb24', 'cane-della-morte', 'Cane della Morte', 'SRD', 'srd-extracted/cane-della-morte.json', '1', 1, 200, NULL, NULL, NULL, '{"slug":"cane-della-morte","general":{"name":"Cane della Morte","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":39,"formula":"6d8 + 12"},"speed":{"walk":"12 m"}},"abilities":{"strength":15,"dexterity":14,"constitution":14,"intelligence":3,"wisdom":13,"charisma":6},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":5}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"36 m"},{"name":"Percezione passiva 15"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Bicefalo","usage":null,"description":"Il cane ha vantaggio nelle prove di Saggezza (Percezione) e nei tiri salvezza contro le condizioni accecato, affascinato, assordato, spaventato, stordito o svenuto."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d6 + 1) danni perforanti."},{"name":"Teletrasporto","usage":"Ricarica 4-6","description":"Il cane si teletrasporta magicamente, insieme a qualsiasi cosa stia indossando o trasportando, fino a 12 metri in uno spazio non occupato che possa vedere. Prima o dopo il teletrasporto, il cane può effettuare un attacco di morso."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cane della Morte\nIl cane della morte è un orribile segugio a due teste che\nsi aggira per pianure, deserti e sotterranei.\nMedia mostruosità, neutrale malvagio\nFORZA 15 (+2)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 13 (+1)\nCARISMA 6 (-2)\nClasse Armatura 12\nPunti Ferita 39 (6d8 + 12)\nVelocità 12 m\nAbilità Furtività +4, Percezione +5\nSensi visione al buio 36 m, Percezione passiva 15\nLingue -\nSfida 1 (200 PE)\nBicefalo. Il cane ha vantaggio nelle prove di Saggezza\n(Percezione) e nei tiri salvezza contro le condizioni accecato,\naffascinato, assordato, spaventato, stordito o svenuto.\nAzioni\nMultiattacco. Il cane effettua due attacchi di morso.\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Costituzione CD 12\ncontro la malattia o restare avvelenato finché la malattia non\nviene curata. Dopo ogni 24 ore, la creatura deve ripetere il tiro\nsalvezza, riducendo i suoi punti ferita massimi di 5 (1d10) in\ncaso di fallimento. Questa riduzione perdura finché la malattia\nnon viene curata. La creatura muore se la malattia riduce i suoi\npunti ferita massimi a 0.\n\n-- 114 of 151 --\n\nCane Intermittente\nIl cane intermittente deriva il nome dalla sua abilità di\nentrare e uscire dalla realtà, un talento che usa per\nattaccare ed evitare di essere attaccato.\nMedia fatato, legale buono\nFORZA 12 (+1)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 13 (+1)\nCARISMA 11 (+0)\nClasse Armatura 13\nPunti Ferita 22 (4d8 + 4)\nVelocità 12 m\nAbilità Furtività +5, Percezione +3\nSensi Percezione passiva 13\nLingue Cane Intermittente, comprende il Silvano ma non può\nparlarlo\nSfida 1/4 (50 PE)\nUdito e Olfatto Affinato. Il cane ha vantaggio nelle prove di\nSaggezza (Percezione) basate su udito o olfatto.\nAzioni\nMorso. Attacco con Arma da Mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d6 + 1) danni perforanti.\nTeletrasporto (Ricarica 4-6). Il cane si teletrasporta\nmagicamente, insieme a qualsiasi cosa stia indossando o\ntrasportando, fino a 12 metri in uno spazio non occupato che\npossa vedere. Prima o dopo il teletrasporto, il cane può effettuare\nun attacco di morso."}}', '2026-03-30T16:00:32.414Z', '2026-03-30T16:00:32.415Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jYXBpdGFuby1kZWktYmFuZGl0aS1waXJhdGEuanNvbg', 'capitano-dei-banditi-pirata', 'Capitano dei Banditi/Pirata', 'SRD', 'srd-extracted/capitano-dei-banditi-pirata.json', '2', 2, 450, NULL, NULL, NULL, '{"slug":"capitano-dei-banditi-pirata","general":{"name":"Capitano dei Banditi/Pirata","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura di cuoio borchiato"},"hitPoints":{"average":65,"formula":"10d8 + 8"},"speed":{"walk":"9 m"}},"abilities":{"strength":15,"dexterity":16,"constitution":14,"intelligence":14,"wisdom":11,"charisma":14},"details":{"savingThrows":[{"ability":"Forza","bonus":4},{"ability":"Destrezza","bonus":5},{"ability":"Saggezza","bonus":2}],"skills":[{"name":"Atletica","bonus":4},{"name":"Raggiro","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Bastone","usage":null,"description":"Attacco con Arma da Mischia: +1 a colpire, portata 1,5 m, un bersaglio. Colpisce: 3 (1d8 - 1) danni contundenti."}],"bonusActions":[],"reactions":[{"name":"Parata","usage":null,"description":"Il capitano somma 2 alla sua CA contro un attacco da mischia che lo colpirebbe. Per farlo, il capitano deve vedere l''attaccante e impugnare un''arma da mischia. Assassino Solitari o membri di una gilda, gli assassini sono pagati per eliminare, spesso in modo silenzioso e discreto, rivali e nemici dei loro datori di lavoro. Media umanoide (qualsiasi razza), qualsiasi allineamento non buono FORZA 11 (+0) DESTREZZA 16 (+3) COSTITUZIONE 14 (+2) INTELLIGENZA 13 (+1) SAGGEZZA 11 (+0) CARISMA 10 (+0) Classe Armatura 15 (armatura di cuoio borchiato) Punti Ferita 78 (12d8 + 24) Velocità 9 m Tiri Salvezza Destrezza +6, Intelligenza +4 Abilità Acrobazia +6, Furtività +9, Percezione +3, Raggiro +3 Sensi Percezione passiva 13 Lingue Gergo dei Ladri più due altre lingue"},{"name":"Sfida 8 (3","usage":null,"description":"900 PE)"},{"name":"Assassinare","usage":null,"description":"Durante il suo primo turno, l''assassino ha vantaggio ai tiri di attacco contro le creature che non hanno ancora svolto nessun turno. Qualsiasi colpo che l''assassino mandi a segno contro una creatura sorpresa, è un colpo critico."},{"name":"Attacco Furtivo","usage":"1/Turno","description":"L''assassino infligge 14 (4d6) danni aggiuntivi quando colpisce un bersaglio con un attacco con arma e ha vantaggio al tiro di attacco, o quando il bersaglio è entro 1,5 metri da un alleato dell''assassino che non è inabile e l''assassino non ha svantaggio al tiro di attacco."},{"name":"Evasione","usage":null,"description":"Se l''assassino è vittima di un effetto che permette di effettuare un tiro salvezza di Destrezza per dimezzare i danni, l''assassino non prende danni se riesce il tiro salvezza, e solo la metà se lo fallisce."}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Capitano dei Banditi/Pirata\nChe viva in terra o in mare, è un individuo munito di una\ngrande personalità che riesce a tenere in riga la\nmarmaglia che risponde ai suoi ordini.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento non\nlegale\nFORZA 15 (+2)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 14 (+2)\nSAGGEZZA 11 (+0)\nCARISMA 14 (+2)\nClasse Armatura 15 (armatura di cuoio borchiato)\nPunti Ferita 65 (10d8 + 8)\nVelocità 9 m\nTiri Salvezza Forza +4, Destrezza +5, Saggezza +2\nAbilità Atletica +4, Raggiro +4\nSensi Percezione passiva 10\nLingue due lingue qualsiasi\nSfida 2 (450 PE)\nAzioni\nMultiattacco. Il capitano effettua tre attacchi da mischia: due con\nla scimitarra e uno con il pugnale. Oppure il capitano effettua\ndue attacchi a gittata con i pugnali.\nScimitarra. Attacco con Arma da Mischia: +5 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni taglienti.\nPugnale. Attacco con Arma da Mischia o a Gittata: +5 a colpire,\nportata 1,5 m o gittata 6/18 metri, un bersaglio.\nColpisce: 5 (1d4 + 3) danni perforanti.\nReazioni\nParata. Il capitano somma 2 alla sua CA contro un attacco da\nmischia che lo colpirebbe. Per farlo, il capitano deve vedere\nl''attaccante e impugnare un''arma da mischia.\nAssassino\nSolitari o membri di una gilda, gli assassini sono pagati\nper eliminare, spesso in modo silenzioso e discreto,\nrivali e nemici dei loro datori di lavoro.\nMedia umanoide (qualsiasi razza), qualsiasi allineamento non\nbuono\nFORZA 11 (+0)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 13 (+1)\nSAGGEZZA 11 (+0)\nCARISMA 10 (+0)\nClasse Armatura 15 (armatura di cuoio borchiato)\nPunti Ferita 78 (12d8 + 24)\nVelocità 9 m\nTiri Salvezza Destrezza +6, Intelligenza +4\nAbilità Acrobazia +6, Furtività +9, Percezione +3, Raggiro +3\nSensi Percezione passiva 13\nLingue Gergo dei Ladri più due altre lingue\nSfida 8 (3.900 PE)\nAssassinare. Durante il suo primo turno, l''assassino ha\nvantaggio ai tiri di attacco contro le creature che non hanno\nancora svolto nessun turno. Qualsiasi colpo che l''assassino\nmandi a segno contro una creatura sorpresa, è un colpo critico.\nAttacco Furtivo (1/Turno). L''assassino infligge 14 (4d6) danni\naggiuntivi quando colpisce un bersaglio con un attacco con arma\ne ha vantaggio al tiro di attacco, o quando il bersaglio è entro 1,5\nmetri da un alleato dell''assassino che non è inabile e l''assassino\nnon ha svantaggio al tiro di attacco.\nEvasione. Se l''assassino è vittima di un effetto che permette di\neffettuare un tiro salvezza di Destrezza per dimezzare i danni,\nl''assassino non prende danni se riesce il tiro salvezza, e solo la\nmetà se lo fallisce.\nAzioni\nMultiattacco. L''assassino effettua due attacchi con le spade corte.\nSpada Corta. Attacco con Arma da Mischia: +6 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni perforanti, e il bersaglio deve effettuare un\ntiro salvezza di Costituzione CD 15, subendo 24 (7d6) danni da veleno se\nfallisce il tiro salvezza, o la metà di questi danni se lo riesce.\nBalestra Leggera. Attacco con Arma a Gittata: +6 a colpire,\ngittata 24/96 metri, un bersaglio.\nColpisce: 7 (1d8 + 3) danni perforanti, e il bersaglio deve effettuare un\ntiro salvezza di Costituzione CD 15, subendo 24 (7d6) danni da veleno se\nfallisce il tiro salvezza, o la metà di questi danni se lo riesce.\n\n-- 144 of 151 --\n\nMagi\nI magi trascorrono la vita nello studio e la pratica della\nmagia.\nVARIANTE: FAMIGLI\nQualsiasi incantatore che possa eseguire l''incantesimo trovare\nfamiglio (come un magio) è probabile che abbia un famiglio. Il\nfamiglio può essere una delle creature descritte nell''incantesimo\n(vedi le Regole Base) o qualche altro mostro Minuscolo, come\nun artiglio strisciante, un diavoletto, uno pseudodrago o un\ndemonietto.\nMagio Avventuriero\nUn magio novizio, che ha superato con successo le sue\nprime avventure e ha iniziato a stabilire una\nreputazione come nobile o famigerato avventuriero.\nMedia umanoide (qualsiasi razza), qualsiasi malvagio\nFORZA 9 (-1)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 17 (+3)\nSAGGEZZA 12 (+1)\nCARISMA 11 (+0)\nClasse Armatura 12\nPunti Ferita 22 (5d8)\nVelocità 9 m\nTiri Salvezza Intelligenza +5, Saggezza +3\nAbilità Arcano +5, Storia +5\nSensi Percezione passiva 11\nLingue quattro lingue qualsiasi\nSfida 1 (200 PE)\nIncantesimi. Il magio è un incantatore di 4° livello. La sua\nabilità da incantatore è l''Intelligenza (CD dei tiri salvezza degli\nincantesimi 13, +5 al colpire con attacchi con incantesimo). Il\nmagio ha preparato i seguenti incantesimi da mago:\nTrucchetti (a volontà): luce, mano magica, stretta folgorante\n1° livello (4 slot): charme su persone, dardo incantato\n2° livello (3 slot): bloccare persona, passo velato\nAzioni\nBastone. Attacco con Arma da Mischia: +1 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 3 (1d8 - 1) danni contundenti."}}', '2026-03-30T16:00:32.491Z', '2026-03-30T16:00:32.491Z');
