INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jaGltZXJhLmpzb24', 'chimera', 'Chimera', 'SRD', 'srd-extracted/chimera.json', '6', 6, 2300, 'Grande', 'mostruosità', 'caotico malvagio', '{"slug":"chimera","general":{"name":"Chimera","challengeRating":{"fraction":"6","decimal":6,"display":"6","xp":2300},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":114,"formula":"12d10 + 48"},"speed":{"walk":"9 m","fly":"18 m"}},"abilities":{"strength":19,"dexterity":11,"constitution":19,"intelligence":3,"wisdom":14,"charisma":10},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":8}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 18"}],"languages":[{"name":"comprende il Draconico ma non può parlare"}],"proficiencyBonus":3},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"La chimera effettua tre attacchi: uno con il morso, uno con le corna e uno con gli artigli. Quando il soffio infuocato è disponibile, può usare il soffio al posto del morso o delle corna."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni taglienti."},{"name":"Corna","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (1d12 + 4) danni contundenti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +7 a colpire, portata 1,5 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni perforanti."},{"name":"Soffio Infuocato","usage":"Ricarica 5-6","description":"La testa di drago esala fuoco in un cono di 4,5 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 15 e subire 31 (7d8) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Chimera\nGrande mostruosità, caotico malvagio\nFORZA 19 (+4)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 19 (+4)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 14 (+2)\nCARISMA 10 (+0)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 114 (12d10 + 48)\nVelocità 9 m, volo 18 m\nAbilità Percezione +8\nSensi scurovisione 18 m, Percezione passiva 18\nLinguaggi comprende il Draconico ma non può parlare\nSfida 6 (2.300 PE)\nAzioni\nMultiattacco. La chimera effettua tre attacchi: uno con il morso,\nuno con le corna e uno con gli artigli. Quando il soffio infuocato\nè disponibile, può usare il soffio al posto del morso o delle corna.\nArtigli. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni taglienti.\nCorna. Attacco con arma da mischia: +7 a colpire, portata 1,5 m,\nun bersaglio.\nColpisce: 10 (1d12 + 4) danni contundenti.\nMorso. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 11 (2d6 + 4) danni perforanti.\nSoffio Infuocato (Ricarica 5-6). La testa di drago esala fuoco in\nun cono di 4,5 metri. Ogni creatura in quell''area deve effettuare\nun tiro salvezza di Destrezza CD 15 e subire 31 (7d8) danni da\nfuoco se fallisce il tiro salvezza, o la metà di questi danni se lo\nriesce."}}', '2026-03-30T16:00:32.240Z', '2026-03-30T16:00:32.240Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jaHV1bC5qc29u', 'chuul', 'Chuul', 'SRD', 'srd-extracted/chuul.json', '4', 4, 1100, 'Grande', 'aberrazione', 'caotico malvagio', '{"slug":"chuul","general":{"name":"Chuul","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1100},"size":"Grande","creatureType":"aberrazione","subtype":"","typeLabel":"aberrazione","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura naturale"},"hitPoints":{"average":93,"formula":"11d10 + 33"},"speed":{"walk":"9 m","swim":"9 m"}},"abilities":{"strength":19,"dexterity":10,"constitution":16,"intelligence":5,"wisdom":11,"charisma":5},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 14"}],"languages":[{"name":"comprende la Parlata delle Profondità ma non può"}],"proficiencyBonus":2},"traits":[{"name":"Anfibio","usage":null,"description":"Il chuul può respirare aria e acqua."},{"name":"Senso della Magia","usage":null,"description":"Il chuul percepisce la magia entro 36 metri da sé. Questo tratto funziona come l''incantesimo individuazione del magico ma di per sé non è magico."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il chuul effettua due attacchi con le chele. Se il chuul sta afferrando una creatura, può anche usare i suoi tentacoli una volta."},{"name":"Chele","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 3 m, un bersaglio. Colpisce: 11 (2d6 + 4) danni contundenti. Un bersaglio è afferrato (CD 14 per fuggire) se è di taglia Grande o inferiore e il chuul non sta già afferrando altre due creature."},{"name":"Tentacoli","usage":null,"description":"Una creatura afferrata dal chuul deve riuscire un tiro salvezza di Costituzione CD 13 o restare avvelenata per 1 minuto. Fino al termine dell''avvelenamento, il bersaglio è paralizzato. Il bersaglio può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto per sé in caso di successo."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Chuul\nGrande aberrazione, caotico malvagio\nFORZA 19 (+4)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 11 (+0)\nCARISMA 5 (-3)\nClasse Armatura 16 (armatura naturale)\nPunti Ferita 93 (11d10 + 33)\nVelocità 9 m, nuoto 9 m\nAbilità Percezione +4\nImmunità ai Danni veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 18 m, Percezione passiva 14\nLinguaggi comprende la Parlata delle Profondità ma non può\nparlare\nSfida 4 (1.100 PE)\nAnfibio. Il chuul può respirare aria e acqua.\nSenso della Magia. Il chuul percepisce la magia entro 36 metri\nda sé. Questo tratto funziona come l''incantesimo individuazione\ndel magico ma di per sé non è magico.\nAzioni\nMultiattacco. Il chuul effettua due attacchi con le chele. Se il\nchuul sta afferrando una creatura, può anche usare i suoi\ntentacoli una volta.\nChele. Attacco con arma da mischia: +6 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 11 (2d6 + 4) danni contundenti. Un bersaglio è\nafferrato (CD 14 per fuggire) se è di taglia Grande o inferiore e il\nchuul non sta già afferrando altre due creature.\nTentacoli. Una creatura afferrata dal chuul deve riuscire un tiro\nsalvezza di Costituzione CD 13 o restare avvelenata per 1\nminuto. Fino al termine dell''avvelenamento, il bersaglio è\nparalizzato. Il bersaglio può ripetere il tiro salvezza al termine di\nciascun suo turno, terminando l''effetto per sé in caso di successo."}}', '2026-03-30T16:00:32.240Z', '2026-03-30T16:00:32.240Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jaW5naGlhbGUtZ2lnYW50ZS5qc29u', 'cinghiale-gigante', 'Cinghiale Gigante', 'SRD', 'srd-extracted/cinghiale-gigante.json', '2', 2, 450, 'Grande', 'bestia', 'disallineato', '{"slug":"cinghiale-gigante","general":{"name":"Cinghiale Gigante","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":42,"formula":"5d10 + 15"},"speed":{"walk":"12 m"}},"abilities":{"strength":17,"dexterity":10,"constitution":16,"intelligence":2,"wisdom":7,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 8"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":null,"description":"Se il cinghiale si muove di almeno 6 metri diretto verso il bersaglio e colpisce con un attacco di zanna durante lo stesso turno, il bersaglio subisce 7 (2d6) danni taglienti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 13 o cadere prono."},{"name":"Implacabile","usage":"Ricarica dopo un Riposo Breve o Lungo","description":"Se il cinghiale subisce 10 danni o meno che lo ridurrebbero a 0 punti ferita, scende invece a 1 punto ferita."}],"actions":[{"name":"Zanna","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cinghiale Gigante\nGrande bestia, disallineato\nFORZA 17 (+3)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 7 (-2)\nCARISMA 5 (-3)\nClasse Armatura 12 (armatura naturale)\nPunti Ferita 42 (5d10 + 15)\nVelocità 12 m\nSensi Percezione passiva 8\nLingue -\nSfida 2 (450 PE)\nCarica. Se il cinghiale si muove di almeno 6 metri diretto verso\nil bersaglio e colpisce con un attacco di zanna durante lo stesso\nturno, il bersaglio subisce 7 (2d6) danni taglienti aggiuntivi. Se il\nbersaglio è una creatura, deve riuscire un tiro salvezza di Forza\nCD 13 o cadere prono.\nImplacabile (Ricarica dopo un Riposo Breve o Lungo). Se il\ncinghiale subisce 10 danni o meno che lo ridurrebbero a 0 punti\nferita, scende invece a 1 punto ferita.\nAzioni\nZanna. Attacco con Arma da Mischia: +5 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d6 + 3) danni taglienti."}}', '2026-03-30T16:00:32.423Z', '2026-03-30T16:00:32.423Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9jaW5naGlhbGUtbWFubmFyby5qc29u', 'cinghiale-mannaro', 'Cinghiale Mannaro', 'SRD', 'srd-extracted/cinghiale-mannaro.json', '4', 4, 1100, 'Media', 'umanoide (umano', 'mutaforma), neutrale malvagio', '{"slug":"cinghiale-mannaro","general":{"name":"Cinghiale Mannaro","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1100},"size":"Media","creatureType":"umanoide (umano","subtype":"","typeLabel":"umanoide (umano","alignment":"mutaforma), neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":0,"note":""},"hitPoints":{"average":78,"formula":"12d8 + 24"},"speed":{"walk":"9 m (12 m in forma di cinghiale)"}},"abilities":{"strength":17,"dexterity":10,"constitution":15,"intelligence":10,"wisdom":11,"charisma":8},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["contundente","perforante e tagliente di"],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 12"}],"languages":[{"name":"Comune (non può parlare in forma di cinghiale)"}],"proficiencyBonus":2},"traits":[{"name":"Carica","usage":"Solo Forma di Cinghiale o Ibrida","description":"Se il cinghiale mannaro si muove in linea retta di almeno 4,5 metri verso un bersaglio e poi lo colpisce con le zanne durante lo stesso turno, il bersaglio subisce 7 (2d6) danni taglienti aggiuntivi. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 13 o cadere prono."},{"name":"Implacabile","usage":"Ricarica dopo un Riposo Breve o Lungo","description":"Se il cinghiale mannaro subisce 14 danni o meno che lo ridurrebbero a 0 punti ferita, scende invece a 1 punto ferita."},{"name":"Mutaforma","usage":null,"description":"Il cinghiale mannaro può usare la sua azione per trasformarsi in un ibrido cinghiale-umanoide o in un cinghiale, o per tornare alla sua vera forma, che è umanoide. Le sue statistiche, a parte la CA, sono le stesse in tutte le forme. Qualsiasi equipaggiamento stia indossando o trasportando non viene trasformato. Alla morte ritorna alla sua vera forma."}],"actions":[{"name":"Multiattacco","usage":"Solo in Forma Umanoide o Ibrida","description":"Il cinghiale mannaro effettua due attacchi, di cui solo uno può essere con le zanne."},{"name":"Maglio","usage":"Soltanto in Forma Umanoide o Ibrida","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni contundenti."},{"name":"Zanne","usage":"Soltanto in Forma di Cinghiale o Ibrida","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d6 + 3) danni taglienti. Se il bersaglio è un umanoide, deve riuscire un tiro salvezza di Costituzione CD 12 o venire maledetto dalla licantropia del cinghiale mannaro."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Cinghiale Mannaro\nMedia umanoide (umano, mutaforma), neutrale malvagio\nFORZA 17 (+3)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 8 (-1)\nClasse Armatura 10 in forma umanoide, 11 (armatura naturale)\nin forma di cinghiale o ibrida\nPunti Ferita 78 (12d8 + 24)\nVelocità 9 m (12 m in forma di cinghiale)\nAbilità Percezione +2\nImmunità al Danno contundente, perforante e tagliente di\nattacchi non magici che non siano argentati\nSensi Percezione passiva 12\nLinguaggi Comune (non può parlare in forma di cinghiale)\nSfida 4 (1.100 PE)\nCarica (Solo Forma di Cinghiale o Ibrida). Se il cinghiale\nmannaro si muove in linea retta di almeno 4,5 metri verso un\nbersaglio e poi lo colpisce con le zanne durante lo stesso turno, il\nbersaglio subisce 7 (2d6) danni taglienti aggiuntivi. Se il\nbersaglio è una creatura, deve riuscire un tiro salvezza di Forza\nCD 13 o cadere prono.\nImplacabile (Ricarica dopo un Riposo Breve o Lungo). Se il\ncinghiale mannaro subisce 14 danni o meno che lo ridurrebbero a\n0 punti ferita, scende invece a 1 punto ferita.\nMutaforma. Il cinghiale mannaro può usare la sua azione per\ntrasformarsi in un ibrido cinghiale-umanoide o in un cinghiale, o\nper tornare alla sua vera forma, che è umanoide. Le sue\nstatistiche, a parte la CA, sono le stesse in tutte le forme.\nQualsiasi equipaggiamento stia indossando o trasportando non\nviene trasformato. Alla morte ritorna alla sua vera forma.\nAzioni\nMultiattacco (Solo in Forma Umanoide o Ibrida). Il cinghiale\nmannaro effettua due attacchi, di cui solo uno può essere con le\nzanne.\nMaglio (Soltanto in Forma Umanoide o Ibrida). Attacco con\narma da mischia: +5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 10 (2d6 + 3) danni contundenti.\nZanne (Soltanto in Forma di Cinghiale o Ibrida). Attacco con\narma da mischia: +5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 10 (2d6 + 3) danni taglienti. Se il bersaglio è un\numanoide, deve riuscire un tiro salvezza di Costituzione CD 12 o\nvenire maledetto dalla licantropia del cinghiale mannaro."}}', '2026-03-30T15:54:05.397Z', '2026-03-30T16:00:32.340Z');
