INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmFnby1uZXJvLWFkdWx0by5qc29u', 'drago-nero-adulto', 'Drago Nero Adulto', 'SRD', 'srd-extracted/drago-nero-adulto.json', '17', 17, 18000, 'Enorme', 'drago', 'caotico malvagio', '{"slug":"drago-nero-adulto","general":{"name":"Drago Nero Adulto","challengeRating":{"fraction":"17","decimal":17,"display":"17","xp":18000},"size":"Enorme","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":195,"formula":"17d12 + 85"},"speed":{"walk":"12 m","climb":"12 m","fly":"24 m"}},"abilities":{"strength":23,"dexterity":14,"constitution":21,"intelligence":14,"wisdom":13,"charisma":17},"details":{"savingThrows":[{"ability":"Destrezza","bonus":7},{"ability":"Costituzione","bonus":10},{"ability":"Saggezza","bonus":6}],"skills":[{"name":"Furtività","bonus":7},{"name":"Percezione","bonus":11}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["acido"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"vista cieca","value":"18 m"},{"name":"Percezione passiva 21"}],"languages":[{"name":"Comune"},{"name":"Draconico"}],"proficiencyBonus":6},"traits":[{"name":"Anfibio","usage":null,"description":"Il drago può respirare aria e acqua."},{"name":"Resistenza Leggendaria","usage":"3/Giorno","description":"Se il drago fallisce un tiro salvezza, può scegliere invece di riuscire."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il drago può usare la sua Presenza Spaventosa. Poi effettuare tre attacchi: uno con il morso e due con gli artigli."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +11 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d6 + 6) danni taglienti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +11 a colpire, portata 4,5 m, un bersaglio. Colpisce: 15 (2d8 + 6) danni contundenti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +11 a colpire, portata 3 m, un bersaglio. Colpisce: 17 (2d10 + 6) danni perforanti più 4 (1d8) danni da acido."},{"name":"Presenza Spaventosa","usage":null,"description":"Ogni creatura scelta dal drago, che si trovi entro 36 metri da esso e consapevole della sua presenza, deve riuscire un tiro salvezza di Saggezza CD 16 o restare spaventata per 1 minuto. Una creatura può ripetere il tiro salvezza al termine di ciascun suo turno, terminando l''effetto se lo riesce. Se il tiro salvezza della creatura ha successo o l''effetto ha termine per essa, la creatura è immune alla Presenza Spaventosa del drago per le successive 24 ore."},{"name":"Soffio Acido","usage":"Ricarica 5-6","description":"Il drago esala acido in una linea di 18 metri larga 1,5 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Destrezza CD 18 e subire 54 (12d8) danni da acido se fallisce il tiro salvezza, o la metà di questi danni se lo riesce."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"Il drago può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. Il drago recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Attacco di Ala","description":"Il drago batte le ali. Ogni creatura entro 3 metri dal drago deve riuscire un tiro salvezza di Destrezza CD 19 o subire 13 (2d6 + 6) danni contundenti e venir gettato prono. Il drago può poi volare fino a metà della sua velocità di volo.","cost":2},{"name":"Attacco di Coda","description":"Il drago effettua un attacco di coda.","cost":1},{"name":"Individuare","description":"Il drago effettua una prova di Saggezza (Percezione).","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Drago Nero Adulto\nEnorme drago, caotico malvagio\nFORZA 23 (+6)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 21 (+5)\nINTELLIGENZA 14 (+2)\nSAGGEZZA 13 (+1)\nCARISMA 17 (+3)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 195 (17d12 + 85)\nVelocità 12 m, scalata 12 m, volo 24 m\nTiri Salvezza Destrezza +7, Costituzione +10, Saggezza +6,\nCarisma +8\nAbilità Furtività +7, Percezione +11\nImmunità al Danno acido\nSensi scurovisione 36 m, vista cieca 18 m, Percezione passiva 21\nLinguaggi Comune, Draconico\nSfida 17 (18.000 PE)\nAnfibio. Il drago può respirare aria e acqua.\nResistenza Leggendaria (3/Giorno). Se il drago fallisce un tiro\nsalvezza, può scegliere invece di riuscire.\nAzioni\nMultiattacco. Il drago può usare la sua Presenza Spaventosa. Poi\neffettuare tre attacchi: uno con il morso e due con gli artigli.\nArtiglio. Attacco con arma da mischia: +11 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d6 + 6) danni taglienti.\nCoda. Attacco con arma da mischia: +11 a colpire, portata 4,5\nm, un bersaglio.\nColpisce: 15 (2d8 + 6) danni contundenti.\nMorso. Attacco con arma da mischia: +11 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 17 (2d10 + 6) danni perforanti più 4 (1d8) danni da\nacido.\nPresenza Spaventosa. Ogni creatura scelta dal drago, che si trovi\nentro 36 metri da esso e consapevole della sua presenza, deve\nriuscire un tiro salvezza di Saggezza CD 16 o restare spaventata\nper 1 minuto. Una creatura può ripetere il tiro salvezza al termine\ndi ciascun suo turno, terminando l''effetto se lo riesce. Se il tiro\nsalvezza della creatura ha successo o l''effetto ha termine per\nessa, la creatura è immune alla Presenza Spaventosa del drago\nper le successive 24 ore.\nSoffio Acido (Ricarica 5-6). Il drago esala acido in una linea di\n18 metri larga 1,5 metri. Ogni creatura in quell''area deve\neffettuare un tiro salvezza di Destrezza CD 18 e subire 54 (12d8)\ndanni da acido se fallisce il tiro salvezza, o la metà di questi\ndanni se lo riesce.\nAzioni Leggendarie\nIl drago può effettuare 3 azioni leggendarie, scelte tra le opzioni\nseguenti. Può usare solo un''opzione leggendaria alla volta e solo\nal termine del turno di un''altra creatura. Il drago recupera le\nazioni leggendarie spese all''inizio del proprio turno.\nAttacco di Ala (Costa 2 Azioni). Il drago batte le ali. Ogni\ncreatura entro 3 metri dal drago deve riuscire un tiro salvezza di\nDestrezza CD 19 o subire 13 (2d6 + 6) danni contundenti e venir\ngettato prono. Il drago può poi volare fino a metà della sua\nvelocità di volo.\nAttacco di Coda. Il drago effettua un attacco di coda.\nIndividuare. Il drago effettua una prova di Saggezza\n(Percezione)."}}', '2026-03-30T15:54:05.320Z', '2026-03-30T16:00:32.275Z');
