INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmV0Y2guanNvbg', 'dretch', 'Dretch', 'SRD', 'srd-extracted/dretch.json', '1/4', 0.25, 50, 'Piccola', 'immondo', 'caotico malvagio', '{"slug":"dretch","general":{"name":"Dretch","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Piccola","creatureType":"immondo","subtype":"demone","typeLabel":"immondo (demone)","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":11,"note":"armatura naturale"},"hitPoints":{"average":18,"formula":"4d6 + 4"},"speed":{"walk":"6 m"}},"abilities":{"strength":11,"dexterity":11,"constitution":12,"intelligence":5,"wisdom":8,"charisma":3},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo","fulmine","fuoco"],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[{"name":"Abissale"},{"name":"telepatia 18 m (funziona solo con le"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Multiattacco","usage":null,"description":"Il demone effettua due attacchi: uno con il morso e uno con gli artigli."},{"name":"Artigli","usage":null,"description":"Attacco con arma da mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (2d4) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 3 (1d6) danni perforanti."},{"name":"Nube Fetida","usage":"1/Giorno","description":"Un disgustoso gas verde si estende in un raggio di 3 metri dal demone. Il gas si propaga intorno agli angoli, e la sua area è oscurata leggermente. Rimane per 1 minuto o finché non viene disperso da un forte vento. Qualsiasi creatura che inizi il proprio turno in quell''area deve riuscire un tiro salvezza di Costituzione CD 11 o restare avvelenata fino all''inizio del suo prossimo turno. Mentre è avvelenato in questo modo, il bersaglio, durante il suo turno, può effettuare solo un''azione o un''azione bonus, ma non entrambe, e non può effettuare reazioni."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Dretch\nPiccola immondo (demone), caotico malvagio\nFORZA 11 (+0)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 8 (-1)\nCARISMA 3 (-4)\nClasse Armatura 11 (armatura naturale)\nPunti Ferita 18 (4d6 + 4)\nVelocità 6 m\nResistenze al Danno freddo, fulmine, fuoco\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato\nSensi scurovisione 18 m, Percezione passiva 9\nLinguaggi Abissale, telepatia 18 m (funziona solo con le\ncreature che comprendono l''Abissale)\nSfida 1/4 (50 PE)\nAzioni\nMultiattacco. Il demone effettua due attacchi: uno con il morso e\nuno con gli artigli.\nArtigli. Attacco con arma da mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 5 (2d4) danni taglienti.\nMorso. Attacco con arma da mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 3 (1d6) danni perforanti.\nNube Fetida (1/Giorno). Un disgustoso gas verde si estende in\nun raggio di 3 metri dal demone. Il gas si propaga intorno agli\nangoli, e la sua area è oscurata leggermente. Rimane per 1\nminuto o finché non viene disperso da un forte vento. Qualsiasi\ncreatura che inizi il proprio turno in quell''area deve riuscire un\ntiro salvezza di Costituzione CD 11 o restare avvelenata fino\nall''inizio del suo prossimo turno. Mentre è avvelenato in questo\nmodo, il bersaglio, durante il suo turno, può effettuare solo\nun''azione o un''azione bonus, ma non entrambe, e non può\neffettuare reazioni."}}', '2026-03-30T15:54:05.285Z', '2026-03-30T16:00:32.245Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmlhZGUuanNvbg', 'driade', 'Driade', 'SRD', 'srd-extracted/driade.json', '1', 1, 200, 'Media', 'fatato', 'neutrale', '{"slug":"driade","general":{"name":"Driade","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Media","creatureType":"fatato","subtype":"","typeLabel":"fatato","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":11,"note":"16 con pelle di corteccia"},"hitPoints":{"average":22,"formula":"5d8"},"speed":{"walk":"9 m"}},"abilities":{"strength":10,"dexterity":12,"constitution":11,"intelligence":14,"wisdom":15,"charisma":18},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":5},{"name":"Percezione","bonus":4}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 14"}],"languages":[{"name":"Elfico"},{"name":"Silvano"}],"proficiencyBonus":2},"traits":[{"name":"Camminata Arborea","usage":null,"description":"Uno volta durante il suo turno, la driade può usare 3 metri di movimento per entrare magicamente in un albero vivo a sua portata ed emergere da un altro albero vivo entro 18 metri dal primo albero, ricomparendo in uno spazio non occupato entro 1,5 metri dal secondo albero. Entrambi gli alberi devono essere di taglia Grande o superiore."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato della driade è il Carisma (CD 14 per i tiri salvezza degli incantesimi). La driade può lanciare in maniera innata i seguenti incantesimi, senza aver bisogno di componenti materiali. A volontà: arte del druido 3/giorno ciascuno: bacche benefiche, intralciare 1/giorno: passare senza tracce, pelle coriacea, randello incantato"},{"name":"Parlare con Animali e Piante","usage":null,"description":"La driade può comunicare con bestie e piante come se parlassero la stessa lingua."},{"name":"Resistenza alla Magia","usage":null,"description":"La driade ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Randello","usage":null,"description":"Attacco con arma da mischia: +2 a colpire (+6 a colpire con bastone), portata 1,5 m, un bersaglio. Colpisce: 2 (1d4) danni contundenti, o 8 (1d8 + 4) danni contundenti con bastone"},{"name":"Fascino Fatato","usage":null,"description":"La driade può prendere a bersaglio un umanoide o bestia entro 9 metri da lei e che possa vedere. Se il bersaglio può vedere la driade, deve riuscire un tiro salvezza di Saggezza CD 14 o restare affascinato dalla magia. Le creature affascinate considerano la driade un''amica fidata da ascoltare e proteggere. Sebbene il bersaglio non sia sotto il controllo della driade, interpreterà le richieste o le azioni della driade nel modo più favorevole possibile. Ogni volta che la driade o i suoi alleati arrecano danno al bersaglio, esso può ripetere il tiro salvezza, terminando l''effetto in caso di successo. Altrimenti, l''effetto permane 24 ore o finché la driade muore, si trova su di un piano di esistenza diverso rispetto al bersaglio, o termina l''effetto con un''azione bonus. Se il tiro salvezza del bersaglio riesce, il bersaglio sarà immune al Fascino Fatato della driade per le successive 24 ore. La driade non può tenere affascinati più di un umanoide o tre bestie alla volta."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Driade\nMedia fatato, neutrale\nFORZA 10 (+0)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 14 (+2)\nSAGGEZZA 15 (+2)\nCARISMA 18 (+4)\nClasse Armatura 11 (16 con pelle di corteccia)\nPunti Ferita 22 (5d8)\nVelocità 9 m\nAbilità Furtività +5, Percezione +4\nSensi scurovisione 18 m, Percezione passiva 14\nLinguaggi Elfico, Silvano\nSfida 1 (200 PE)\nCamminata Arborea. Uno volta durante il suo turno, la driade\npuò usare 3 metri di movimento per entrare magicamente in un\nalbero vivo a sua portata ed emergere da un altro albero vivo\nentro 18 metri dal primo albero, ricomparendo in uno spazio non\noccupato entro 1,5 metri dal secondo albero. Entrambi gli alberi\ndevono essere di taglia Grande o superiore.\nIncantesimi Innati. La caratteristica da incantatore innato della\ndriade è il Carisma (CD 14 per i tiri salvezza degli incantesimi).\nLa driade può lanciare in maniera innata i seguenti incantesimi,\nsenza aver bisogno di componenti materiali.\nA volontà: arte del druido\n3/giorno ciascuno: bacche benefiche, intralciare\n1/giorno: passare senza tracce, pelle coriacea, randello\nincantato\nParlare con Animali e Piante. La driade può comunicare con\nbestie e piante come se parlassero la stessa lingua.\nResistenza alla Magia. La driade ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nRandello. Attacco con arma da mischia: +2 a colpire (+6 a\ncolpire con bastone), portata 1,5 m, un bersaglio.\nColpisce: 2 (1d4) danni contundenti, o 8 (1d8 + 4) danni\ncontundenti con bastone\nFascino Fatato. La driade può prendere a bersaglio un umanoide o\nbestia entro 9 metri da lei e che possa vedere. Se il bersaglio può\nvedere la driade, deve riuscire un tiro salvezza di Saggezza CD 14 o\nrestare affascinato dalla magia. Le creature affascinate considerano la\ndriade un''amica fidata da ascoltare e proteggere. Sebbene il bersaglio\nnon sia sotto il controllo della driade, interpreterà le richieste o le\nazioni della driade nel modo più favorevole possibile.\nOgni volta che la driade o i suoi alleati arrecano danno al bersaglio,\nesso può ripetere il tiro salvezza, terminando l''effetto in caso di\nsuccesso. Altrimenti, l''effetto permane 24 ore o finché la driade\nmuore, si trova su di un piano di esistenza diverso rispetto al\nbersaglio, o termina l''effetto con un''azione bonus. Se il tiro salvezza\ndel bersaglio riesce, il bersaglio sarà immune al Fascino Fatato della\ndriade per le successive 24 ore.\nLa driade non può tenere affascinati più di un umanoide o tre bestie\nalla volta."}}', '2026-03-30T15:54:05.354Z', '2026-03-30T16:00:32.303Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kcmlkZXIuanNvbg', 'drider', 'Drider', 'SRD', 'srd-extracted/drider.json', '6', 6, 2300, 'Grande', 'mostruosità', 'caotico malvagio', '{"slug":"drider","general":{"name":"Drider","challengeRating":{"fraction":"6","decimal":6,"display":"6","xp":2300},"size":"Grande","creatureType":"mostruosità","subtype":"","typeLabel":"mostruosità","alignment":"caotico malvagio","environments":[]},"combat":{"armorClass":{"value":19,"note":"armatura naturale"},"hitPoints":{"average":123,"formula":"13d10 + 52"},"speed":{"walk":"9 m","climb":"9 m"}},"abilities":{"strength":16,"dexterity":16,"constitution":18,"intelligence":13,"wisdom":14,"charisma":12},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":9},{"name":"Percezione","bonus":5}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 15"}],"languages":[{"name":"Elfico"},{"name":"Sottocomune"}],"proficiencyBonus":3},"traits":[{"name":"Camminare sulla Tela","usage":null,"description":"Il drider ignora le restrizioni al movimento provocate dalle ragnatele."},{"name":"Discendenza Fatata","usage":null,"description":"Il drider ha vantaggio ai tiri salvezza per non restare affascinato, e la magia non può far addormentare un drider."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del drider è la Saggezza (CD dei tiri salvezza 13). Il drider può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti materiali: A volontà: luci danzanti 1/Giorno: luminescenza, oscurità"},{"name":"Scalare come Ragno","usage":null,"description":"Il drider può scalare superfici difficili, compreso lo stare a testa in giù sul soffitto, senza bisogno di effettuare una prova di abilità."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il drider effettua tre attacchi con la spada lunga o con l''arco lungo. Può rimpiazzare uno di questi attacchi con un attacco di morso."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, una creatura. Colpisce: 2 (1d4) danni perforanti più 9 (2d8) danni da veleno."},{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d8 + 3) danni taglienti, o 8 (1d8 + 3) danni taglienti se usata con due mani."},{"name":"Arco Lungo","usage":null,"description":"Attacco con arma a Distanza: +6 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 7 (1d8 + 3) danni perforanti più 4 (1d8) danni da veleno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Drider\nGrande mostruosità, caotico malvagio\nFORZA 16 (+3)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 13 (+1)\nSAGGEZZA 14 (+2)\nCARISMA 12 (+1)\nClasse Armatura 19 (armatura naturale)\nPunti Ferita 123 (13d10 + 52)\nVelocità 9 m, scalata 9 m\nAbilità Furtività +9, Percezione +5\nSensi scurovisione 36 m, Percezione passiva 15\nLinguaggi Elfico, Sottocomune\nSfida 6 (2.300 PE)\nCamminare sulla Tela. Il drider ignora le restrizioni al\nmovimento provocate dalle ragnatele.\nDiscendenza Fatata. Il drider ha vantaggio ai tiri salvezza per\nnon restare affascinato, e la magia non può far addormentare un\ndrider.\nIncantesimi Innati. La caratteristica da incantatore innato del\ndrider è la Saggezza (CD dei tiri salvezza 13). Il drider può\nlanciare in maniera innata i seguenti incantesimi, senza bisogno\ndi componenti materiali:\nA volontà: luci danzanti\n1/Giorno: luminescenza, oscurità\nScalare come Ragno. Il drider può scalare superfici difficili,\ncompreso lo stare a testa in giù sul soffitto, senza bisogno di\neffettuare una prova di abilità.\nAzioni\nMultiattacco. Il drider effettua tre attacchi con la spada lunga o\ncon l''arco lungo. Può rimpiazzare uno di questi attacchi con un\nattacco di morso.\nMorso. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, una creatura.\nColpisce: 2 (1d4) danni perforanti più 9 (2d8) danni da veleno.\nSpada Lunga. Attacco con arma da mischia: +6 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 7 (1d8 + 3) danni taglienti, o 8 (1d8 + 3) danni\ntaglienti se usata con due mani.\nArco Lungo. Attacco con arma a Distanza: +6 a colpire, gittata\n45/180 m, un bersaglio.\nColpisce: 7 (1d8 + 3) danni perforanti più 4 (1d8) danni da\nveleno."}}', '2026-03-30T15:54:05.353Z', '2026-03-30T16:00:32.303Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9kdWVyZ2FyLmpzb24', 'duergar', 'Duergar', 'SRD', 'srd-extracted/duergar.json', '1', 1, 200, 'Media', 'umanoide', 'legale malvagio', '{"slug":"duergar","general":{"name":"Duergar","challengeRating":{"fraction":"1","decimal":1,"display":"1","xp":200},"size":"Media","creatureType":"umanoide","subtype":"nano","typeLabel":"umanoide (nano)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":16,"note":"armatura di scaglie, scudo"},"hitPoints":{"average":26,"formula":"4d8 + 8"},"speed":{"walk":"5 m"}},"abilities":{"strength":14,"dexterity":11,"constitution":14,"intelligence":11,"wisdom":10,"charisma":9},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["acido; contundente","perforante e tagliente"],"damageImmunities":["veleno"],"conditionImmunities":["afferrato","avvelenato","intralciato"],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Nanico"},{"name":"Sottocomune"}],"proficiencyBonus":2},"traits":[{"name":"Resilienza Duerga","usage":null,"description":"Il duergar ha vantaggio ai tiri salvezza contro veleni, incantesimi e illusioni, oltre al resistere al restare affascinato o paralizzato."},{"name":"Sensibilità alla Luce","usage":null,"description":"Mentre è alla luce del sole, il duergar ha svantaggio ai tiri di attacco, oltre che alle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''elementale effettua due attacchi di schianto."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 1,5 m, un bersaglio. Colpisce: 14 (2d8 + 5) danni contundenti."},{"name":"Turbine","usage":"Ricarica 4-6","description":"Ogni creatura nello spazio dell''elementale deve effettuare un tiro salvezza di Forza CD 13. Se lo fallisce, il bersaglio subisce 15 (3d8 + 2) danni contundenti e viene scagliato a 6 metri di distanza dall''elementale in una direzione casuale e cadere prono. Se un bersaglio lanciato colpisce un oggetto, come un muro o il pavimento, subisce 3 (1d6) danni contundenti per ogni 3 metri per cui è stato lanciato. Se il bersaglio viene lanciato contro un''altra creatura, quella creatura deve riuscire un tiro salvezza di Destrezza CD 13 o subire lo stesso danno e cadere prona. Se il tiro salvezza riesce, il bersaglio subisce la metà del danno contundente e non viene scagliato via né cade prono."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Duergar\nMedia umanoide (nano), legale malvagio\nFORZA 14 (+2)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 10 (+0)\nCARISMA 9 (-1)\nClasse Armatura 16 (armatura di scaglie, scudo)\nPunti Ferita 26 (4d8 + 8)\nVelocità 7,5 m\nResistenza al Danno veleno\nSensi scurovisione 36 m, Percezione passiva 10\nLinguaggi Nanico, Sottocomune\nSfida 1 (200 PE)\nResilienza Duerga. Il duergar ha vantaggio ai tiri salvezza contro\nveleni, incantesimi e illusioni, oltre al resistere al restare\naffascinato o paralizzato.\nSensibilità alla Luce. Mentre è alla luce del sole, il duergar ha\nsvantaggio ai tiri di attacco, oltre che alle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nIngrandire (Ricarica dopo un Riposo Breve o Lungo). Per 1\nminuto, il duergar aumenta magicamente di taglia, insieme a\ntutto ciò che sta trasportando o indossando. Mentre è ingrandito,\nil duergar è di taglia Grande, raddoppia i dadi di danno degli\nattacchi con armi basate sulla Forza (già incluso negli attacchi), e\nha vantaggio alle prove di Forza e ai tiri salvezza di Forza. Se il\nduergar non ha sufficiente spazio per diventare Grande, ottiene la\nmassima taglia concessa dallo spazio a disposizione.\nPiccone da Guerra. Attacco con arma da mischia: +4 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 6 (1d8 + 2) danni perforanti, o 11 (2d8 + 2) danni\nperforanti quando ingrandito.\nGiavellotto. Attacco con arma da mischia o a Distanza: +4 a\ncolpire, portata 1,5 m o gittata 9/36 m, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti o 9 (2d6 + 2) danni\nperforanti quando ingrandito.\nInvisibilità (Ricarica dopo un Riposo Breve o Lungo). Il\nduergar diventa magicamente invisibile al massimo per un''ora\n(come se stesse mantenendo la concentrazione per un\nincantesimo) o finché non attacca, lancia un incantesimo, usa\nIngrandire o la sua concentrazione viene spezzata. Tutto\nl''equipaggiamento che il duergar indossa o trasporta diventa\ninvisibile assieme a lui.\nElementale dell''Acqua\nGrande elementale, neutrale\nFORZA 18 (+4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 10 (+0)\nCARISMA 8 (-1)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 114 (12d10 + 48)\nVelocità 9 m, nuoto 27 m\nResistenze al Danno acido; contundente, perforante e tagliente\ndi attacchi non magici\nImmunità al Danno veleno\nImmunità alle Condizioni afferrato, avvelenato, intralciato,\nparalizzato, pietrificato, privo di sensi, prono, sfinimento\nSensi scurovisione 18 m, Percezione passiva 10\nLinguaggi Aquan\nSfida 5 (1.800 PE)\nCongelamento. Se l''elementale subisce danno da freddo, gela\nparzialmente; la sua velocità è ridotta di 6 metri fino al termine\ndel suo prossimo turno.\nForma d''Acqua. L''elementale può entrare nello spazio di una\ncreatura ostile e fermarsi lì. Può muoversi attraverso uno spazio\nstretto fino a 2,5 centimetri senza doversi stringere.\nNatura Elementale. Un elementale non ha bisogno di aria, cibo,\nbevande o sonno.\nAzioni\nMultiattacco. L''elementale effettua due attacchi di schianto.\nSchianto. Attacco con arma da mischia: +7 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d8 + 4) danni contundenti.\nSommergere (Ricarica 4-6). Ogni creatura nello spazio\ndell''elementale deve effettuare un tiro salvezza di Forza CD 15.\nSe lo fallisce, il bersaglio subisce 13 (2d8 + 4) danni\ncontundenti. Se è di taglia Grande o inferiore, il bersaglio è\nanche afferrato (CD 14 per fuggire). Fino al termine\ndell''afferrare, il bersaglio è intralciato e non può respirare a\nmeno che non sia in grado di respirare acqua. Se il tiro salvezza\nriesce, il bersaglio viene spinto fuori dallo spazio\ndell''elementale.\nL''elementale può afferrare una creatura Grande o fino a due\nMedie o più piccole alla volta. All''inizio di ciascun turno\ndell''elementale, ogni bersaglio afferrato subisce 13 (2d8 + 4)\ndanni contundenti. Una creatura entro 1,5 metri dall''elementale\npuò trascinare fuori da esso una creatura o oggetto, impiegando\nun''azione per tentare di riuscire una prova di Forza CD 14.\n\n-- 53 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nElementale dell''Aria\nGrande elementale, neutrale\nFORZA 14 (+2)\nDESTREZZA 20 (+5)\nCOSTITUZIONE 14 (+2)\nINTELLIGENZA 6 (-2)\nSAGGEZZA 10 (+0)\nCARISMA 6 (-2)\nClasse Armatura 15\nPunti Ferita 90 (12d10 + 24)\nVelocità 0 m, volo 27 m (fluttua)\nResistenze al Danno fulmine, tuono; contundente, perforante e\ntagliente di attacchi non magici\nImmunità al Danno veleno\nImmunità alle Condizioni afferrato, avvelenato, intralciato,\nparalizzato, pietrificato, privo di sensi, prono, sfinimento\nSensi scurovisione 18 m, Percezione passiva 18\nLinguaggi Auran\nSfida 5 (1.800 PE)\nForma d''Aria. L''elementale può entrare nello spazio di una\ncreatura ostile e fermarsi lì. Può muoversi attraverso uno spazio\nstretto fino a 2,5 centimetri senza doversi stringere.\nNatura Elementale. Un elementale non ha bisogno di aria, cibo,\nbevande o sonno.\nAzioni\nMultiattacco. L''elementale effettua due attacchi di schianto.\nSchianto. Attacco con arma da mischia: +8 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 14 (2d8 + 5) danni contundenti.\nTurbine (Ricarica 4-6). Ogni creatura nello spazio\ndell''elementale deve effettuare un tiro salvezza di Forza CD 13.\nSe lo fallisce, il bersaglio subisce 15 (3d8 + 2) danni contundenti\ne viene scagliato a 6 metri di distanza dall''elementale in una\ndirezione casuale e cadere prono. Se un bersaglio lanciato\ncolpisce un oggetto, come un muro o il pavimento, subisce 3\n(1d6) danni contundenti per ogni 3 metri per cui è stato lanciato.\nSe il bersaglio viene lanciato contro un''altra creatura, quella\ncreatura deve riuscire un tiro salvezza di Destrezza CD 13 o\nsubire lo stesso danno e cadere prona.\nSe il tiro salvezza riesce, il bersaglio subisce la metà del danno\ncontundente e non viene scagliato via né cade prono."}}', '2026-03-30T15:54:05.356Z', '2026-03-30T16:00:32.304Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lZnJlZXRpLmpzb24', 'efreeti', 'Efreeti', 'SRD', 'srd-extracted/efreeti.json', '11', 11, 7200, 'Grande', 'elementale', 'legale malvagio', '{"slug":"efreeti","general":{"name":"Efreeti","challengeRating":{"fraction":"11","decimal":11,"display":"11","xp":7200},"size":"Grande","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":200,"formula":"16d10 + 112"},"speed":{"walk":"12 m","fly":"18 m"}},"abilities":{"strength":22,"dexterity":12,"constitution":24,"intelligence":16,"wisdom":15,"charisma":16},"details":{"savingThrows":[{"ability":"Intelligenza","bonus":7},{"ability":"Saggezza","bonus":6},{"ability":"Carisma","bonus":7}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"Ignan"}],"proficiencyBonus":4},"traits":[{"name":"Decesso Elementale","usage":null,"description":"Se l''efreeti muore, il suo corpo si disintegra in un lampo di fuoco e uno sbuffo di fumo, lasciando dietro di sé solo l''equipaggiamento che l''efreeti stava indossando o trasportando."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato dell''efreeti è il Carisma (CD dei tiri salvezza degli incantesimi 15, +7 a colpire con attacchi da incantesimo). Può lanciare in maniera innata i seguenti incantesimi, senza bisogno di componenti materiali: A volontà: individuazione del magico 3/giorno ciascuno: ingrandire/ridurre, linguaggi 1/giorno ciascuno: evoca elementali (solo elementale del fuoco), forma gassosa, immagine maggiore, invisibilità, muro di fuoco, spostamento planare"}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''efreeti effettua due attacchi di scimitarra o usa due volte Scagliare Fiamma."},{"name":"Scimitarra","usage":null,"description":"Attacco con arma da mischia: +10 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d6 + 6) danni taglienti più 7 (2d6) danni da fuoco."},{"name":"Scagliare Fiamma","usage":null,"description":"Attacco con arma a Distanza: +7 a colpire, gittata 36 m, un bersaglio. Colpisce: 17 (5d6) danni da fuoco. ."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Efreeti\nGrande elementale, legale malvagio\nFORZA 22 (+6)\nDESTREZZA 12 (+1)\nCOSTITUZIONE 24 (+7)\nINTELLIGENZA 16 (+3)\nSAGGEZZA 15 (+2)\nCARISMA 16 (+3)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 200 (16d10 + 112)\nVelocità 12 m, volo 18 m\nTiri Salvezza Intelligenza +7, Saggezza +6, Carisma +7\nImmunità al Danno fuoco\nSensi scurovisione 36 m, Percezione passiva 12\nLinguaggi Ignan\nSfida 11 (7.200 PE)\nDecesso Elementale. Se l''efreeti muore, il suo corpo si\ndisintegra in un lampo di fuoco e uno sbuffo di fumo, lasciando\ndietro di sé solo l''equipaggiamento che l''efreeti stava indossando\no trasportando.\nIncantesimi Innati. La caratteristica da incantatore innato\ndell''efreeti è il Carisma (CD dei tiri salvezza degli incantesimi\n15, +7 a colpire con attacchi da incantesimo). Può lanciare in\nmaniera innata i seguenti incantesimi, senza bisogno di\ncomponenti materiali:\nA volontà: individuazione del magico\n3/giorno ciascuno: ingrandire/ridurre, linguaggi\n1/giorno ciascuno: evoca elementali (solo elementale del fuoco),\nforma gassosa, immagine maggiore, invisibilità, muro di fuoco,\nspostamento planare\nAzioni\nMultiattacco. L''efreeti effettua due attacchi di scimitarra o usa\ndue volte Scagliare Fiamma.\nScimitarra. Attacco con arma da mischia: +10 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 13 (2d6 + 6) danni taglienti più 7 (2d6) danni da fuoco.\nScagliare Fiamma. Attacco con arma a Distanza: +7 a colpire,\ngittata 36 m, un bersaglio.\nColpisce: 17 (5d6) danni da fuoco.\n."}}', '2026-03-30T15:54:05.372Z', '2026-03-30T16:00:32.314Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lbGVmYW50ZS5qc29u', 'elefante', 'Elefante', 'SRD', 'srd-extracted/elefante.json', '4', 4, 1000, 'Enorme', 'bestia', 'disallineato', '{"slug":"elefante","general":{"name":"Elefante","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1000},"size":"Enorme","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":76,"formula":"8d12 + 24"},"speed":{"walk":"12 m"}},"abilities":{"strength":22,"dexterity":9,"constitution":17,"intelligence":3,"wisdom":11,"charisma":6},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 10"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Carica Travolgente","usage":null,"description":"Se l''elefante si muove di almeno 6 metri diretto verso una creatura e la colpisce con un attacco di incornata durante lo stesso turno, il bersaglio deve riuscire un tiro salvezza di Forza CD 12 o cadere prono. Se il bersaglio è prono, l''elefante può effettuare un attacco di pestone contro di lui come azione bonus."}],"actions":[{"name":"Incornata","usage":null,"description":"Attacco con Arma da Mischia: +8 a colpire, portata 1,5 m, un bersaglio. Colpisce: 19 (3d8 + 6) danni perforanti."},{"name":"Pestone","usage":null,"description":"Attacco con Arma da Mischia: +8 a colpire, portata 1,5 m, un bersaglio prono. Colpisce: 22 (3d10 + 6) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Elefante\nEnorme bestia, disallineato\nFORZA 22 (+6)\nDESTREZZA 9 (-1)\nCOSTITUZIONE 17 (+3)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 11 (+0)\nCARISMA 6 (-2)\nClasse Armatura 12 (armatura naturale)\nPunti Ferita 76 (8d12 + 24)\nVelocità 12 m\nSensi Percezione passiva 10\nLingue -\nSfida 4 (1.000 PE)\nCarica Travolgente. Se l''elefante si muove di almeno 6 metri\ndiretto verso una creatura e la colpisce con un attacco di\nincornata durante lo stesso turno, il bersaglio deve riuscire un\ntiro salvezza di Forza CD 12 o cadere prono. Se il bersaglio è\nprono, l''elefante può effettuare un attacco di pestone contro di\nlui come azione bonus.\nAzioni\nIncornata. Attacco con Arma da Mischia: +8 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 19 (3d8 + 6) danni perforanti.\nPestone. Attacco con Arma da Mischia: +8 a colpire, portata 1,5\nm, un bersaglio prono.\nColpisce: 22 (3d10 + 6) danni contundenti."}}', '2026-03-30T15:54:05.523Z', '2026-03-30T16:00:32.430Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lbGVtZW50YWxlLWRlbC1mdW9jby5qc29u', 'elementale-del-fuoco', 'Elementale del Fuoco', 'SRD', 'srd-extracted/elementale-del-fuoco.json', '5', 5, 1800, 'Grande', 'elementale', 'neutrale', '{"slug":"elementale-del-fuoco","general":{"name":"Elementale del Fuoco","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":13,"note":""},"hitPoints":{"average":102,"formula":"12d10 + 36"},"speed":{"walk":"15 m"}},"abilities":{"strength":10,"dexterity":17,"constitution":16,"intelligence":6,"wisdom":10,"charisma":7},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":["contundente","perforante e tagliente di"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["afferrato","avvelenato","intralciato"],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"Ignan"}],"proficiencyBonus":3},"traits":[{"name":"Forma di Fuoco","usage":null,"description":"L''elementale può spostarsi attraverso uno spazio fino a 2,5 centimetri di larghezza senza stringersi. Una creatura che entri a contatto o colpisca l''elementale con un attacco da mischia mentre si trova entro 1,5 metri da esso subisce 5 (1d10) danni da fuoco. Inoltre, l''elementale può entrare nello spazio di una creatura ostile e fermarsi lì. La prima volta che entra nello spazio di una creatura in un turno, la creatura subisce 5 (1d10) danni da fuoco e prende fuoco; finché qualcuno non impiega un''azione per spegnere le fiamme, la creatura subirà 5 (1d10) danni da fuoco all''inizio di ciascun proprio turno."},{"name":"Illuminazione","usage":null,"description":"L''elementale emette luce intensa in un raggio di 9 metri e luce fioca per ulteriori 9 metri."},{"name":"Natura Elementale","usage":null,"description":"Un elementale non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Suscettibilità all''Acqua","usage":null,"description":"L''elementale subisce 1 danno da freddo per ogni 1,5 metri che si muove in acqua o per ogni 4 litri d''acqua che gli vengono spruzzati addosso."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''elementale effettua due attacchi di contatto."},{"name":"Contatto","usage":null,"description":"Attacco con arma da mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (2d8 + 5) danni da fuoco. Se il bersaglio è una creatura o un oggetto infiammabile, prende fuoco. Finché una creatura non impiega un''azione per spegnere le fiamme, la creatura subirà 5 (1d10) danni da fuoco all''inizio di ciascun proprio turno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Elementale del Fuoco\nGrande elementale, neutrale\nFORZA 10 (+0)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 6 (-2)\nSAGGEZZA 10 (+0)\nCARISMA 7 (-2)\nClasse Armatura 13\nPunti Ferita 102 (12d10 + 36)\nVelocità 15 m\nResistenze al Danno contundente, perforante e tagliente di\nattacchi non magici\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni afferrato, avvelenato, intralciato,\nparalizzato, pietrificato, prono, privo di sensi, sfinimento\nSensi scurovisione 18 m, Percezione passiva 10\nLinguaggi Ignan\nSfida 5 (1.800 PE)\nForma di Fuoco. L''elementale può spostarsi attraverso uno\nspazio fino a 2,5 centimetri di larghezza senza stringersi. Una\ncreatura che entri a contatto o colpisca l''elementale con un\nattacco da mischia mentre si trova entro 1,5 metri da esso subisce\n5 (1d10) danni da fuoco. Inoltre, l''elementale può entrare nello\nspazio di una creatura ostile e fermarsi lì. La prima volta che\nentra nello spazio di una creatura in un turno, la creatura subisce\n5 (1d10) danni da fuoco e prende fuoco; finché qualcuno non\nimpiega un''azione per spegnere le fiamme, la creatura subirà 5\n(1d10) danni da fuoco all''inizio di ciascun proprio turno.\nIlluminazione. L''elementale emette luce intensa in un raggio di\n9 metri e luce fioca per ulteriori 9 metri.\nNatura Elementale. Un elementale non ha bisogno di aria, cibo,\nbevande o sonno.\nSuscettibilità all''Acqua. L''elementale subisce 1 danno da freddo\nper ogni 1,5 metri che si muove in acqua o per ogni 4 litri\nd''acqua che gli vengono spruzzati addosso.\nAzioni\nMultiattacco. L''elementale effettua due attacchi di contatto.\nContatto. Attacco con arma da mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (2d8 + 5) danni da fuoco. Se il bersaglio è una\ncreatura o un oggetto infiammabile, prende fuoco. Finché una\ncreatura non impiega un''azione per spegnere le fiamme, la\ncreatura subirà 5 (1d10) danni da fuoco all''inizio di ciascun\nproprio turno."}}', '2026-03-30T15:54:05.359Z', '2026-03-30T16:00:32.305Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lbGVtZW50YWxlLWRlbGxhLXRlcnJhLmpzb24', 'elementale-della-terra', 'Elementale della Terra', 'SRD', 'srd-extracted/elementale-della-terra.json', '5', 5, 1800, 'Grande', 'elementale', 'neutrale', '{"slug":"elementale-della-terra","general":{"name":"Elementale della Terra","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"Grande","creatureType":"elementale","subtype":"","typeLabel":"elementale","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":126,"formula":"12d10 + 60"},"speed":{"walk":"9 m","burrow":"9 m"}},"abilities":{"strength":20,"dexterity":8,"constitution":20,"intelligence":5,"wisdom":10,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":["tuono"],"damageResistances":["contundente","perforante e tagliente di"],"damageImmunities":["veleno"],"conditionImmunities":["avvelenato","paralizzato","pietrificato"],"senses":[{"name":"percezione tellurica","value":"18 m"},{"name":"scurovisione","value":"18 m"},{"name":"Percezione"}],"languages":[{"name":"Terran"}],"proficiencyBonus":3},"traits":[{"name":"Mostro d''Assedio","usage":null,"description":"L''elementale infligge danni doppi agli oggetti e le strutture."},{"name":"Natura Elementale","usage":null,"description":"Un elementale non ha bisogno di aria, cibo, bevande o sonno."},{"name":"Planata Terrestre","usage":null,"description":"L''elementale può scavare attraversa la terra e la pietra non magiche e non lavorate. Quando lo fa, l''elementale non disturba il materiale che sposta."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''elementale effettua due attacchi di schianto."},{"name":"Schianto","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 3 m, un bersaglio. Colpisce: 14 (2d8 + 5) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Elementale della Terra\nGrande elementale, neutrale\nFORZA 20 (+5)\nDESTREZZA 8 (-1)\nCOSTITUZIONE 20 (+5)\nINTELLIGENZA 5 (-3)\nSAGGEZZA 10 (+0)\nCARISMA 5 (-3)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 126 (12d10 + 60)\nVelocità 9 m, scavo 9 m\nVulnerabilità al Danno tuono\nResistenze al Danno contundente, perforante e tagliente di\nattacchi non magici\nImmunità al Danno veleno\nImmunità alle Condizioni avvelenato, paralizzato, pietrificato,\nprono, privo di sensi, sfinimento,\nSensi percezione tellurica 18 m, scurovisione 18 m, Percezione\npassiva 10\nLinguaggi Terran\nSfida 5 (1.800 PE)\nMostro d''Assedio. L''elementale infligge danni doppi agli oggetti\ne le strutture.\nNatura Elementale. Un elementale non ha bisogno di aria, cibo,\nbevande o sonno.\nPlanata Terrestre. L''elementale può scavare attraversa la terra e\nla pietra non magiche e non lavorate. Quando lo fa, l''elementale\nnon disturba il materiale che sposta.\nAzioni\nMultiattacco. L''elementale effettua due attacchi di schianto.\nSchianto. Attacco con arma da mischia: +8 a colpire, portata 3\nm, un bersaglio.\nColpisce: 14 (2d8 + 5) danni contundenti."}}', '2026-03-30T15:54:05.359Z', '2026-03-30T16:00:32.306Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lbGZvLWRyb3cuanNvbg', 'elfo-drow', 'Elfo, Drow', 'SRD', 'srd-extracted/elfo-drow.json', '1/4', 0.25, 50, 'Media', 'umanoide', 'neutrale malvagio', '{"slug":"elfo-drow","general":{"name":"Elfo, Drow","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Media","creatureType":"umanoide","subtype":"elfo","typeLabel":"umanoide (elfo)","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"giaco di maglia"},"hitPoints":{"average":13,"formula":"3d8"},"speed":{"walk":"9 m"}},"abilities":{"strength":10,"dexterity":14,"constitution":10,"intelligence":11,"wisdom":11,"charisma":12},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"36 m"},{"name":"Percezione passiva 12"}],"languages":[{"name":"Elfico"},{"name":"Sottocomune"}],"proficiencyBonus":2},"traits":[{"name":"Discendenza Fatata","usage":null,"description":"Il drow ha vantaggio ai tiri salvezza contro l''essere affascinato, e la magia non può mettere a dormire i drow."},{"name":"Incantesimi Innati","usage":null,"description":"La caratteristica da incantatore innato del drow è il Carisma (CD dei tiri salvezza 11). Il drow può lanciare questi incantesimi in maniera innata, senza bisogno di componenti: A volontà: luci danzanti 1/giorno ciascuno: luminescenza, oscurità"},{"name":"Sensibilità alla Luce","usage":null,"description":"Mentre è alla luce del sole, il drow ha svantaggio ai tiri per colpire, oltre che alle prove di Saggezza (Percezione) basate sulla vista."}],"actions":[{"name":"Spada Corta","usage":null,"description":"Attacco con arma da mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti."},{"name":"Balestrino","usage":null,"description":"Attacco con arma a Distanza: +4 a colpire, gittata 9/36 m, un bersaglio. Colpisce: 5 (1d6 + 2) danni perforanti, e il bersaglio deve riuscire un tiro salvezza di Costituzione CD 13 o restare avvelenato per 1 ora. Se il tiro salvezza fallisce di 5 o più, il bersaglio è anche privo di sensi mentre resta avvelenato in questo modo. Il bersaglio si risveglia se subisce danni o un''altra creatura effettua un''azione per risvegliarlo."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Elfo, Drow\nMedia umanoide (elfo), neutrale malvagio\nFORZA 10 (+0)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 11 (+0)\nSAGGEZZA 11 (+0)\nCARISMA 12 (+1)\nClasse Armatura 15 (giaco di maglia)\nPunti Ferita 13 (3d8)\nVelocità 9 m\nAbilità Furtività +4, Percezione +2\nSensi scurovisione 36 m, Percezione passiva 12\nLinguaggi Elfico, Sottocomune\nSfida 1/4 (50 PE)\nDiscendenza Fatata. Il drow ha vantaggio ai tiri salvezza contro\nl''essere affascinato, e la magia non può mettere a dormire i\ndrow.\nIncantesimi Innati. La caratteristica da incantatore innato del\ndrow è il Carisma (CD dei tiri salvezza 11). Il drow può lanciare\nquesti incantesimi in maniera innata, senza bisogno di\ncomponenti:\nA volontà: luci danzanti\n1/giorno ciascuno: luminescenza, oscurità\nSensibilità alla Luce. Mentre è alla luce del sole, il drow ha\nsvantaggio ai tiri per colpire, oltre che alle prove di Saggezza\n(Percezione) basate sulla vista.\nAzioni\nSpada Corta. Attacco con arma da mischia: +4 a colpire, portata\n1,5 m, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti.\nBalestrino. Attacco con arma a Distanza: +4 a colpire, gittata\n9/36 m, un bersaglio.\nColpisce: 5 (1d6 + 2) danni perforanti, e il bersaglio deve\nriuscire un tiro salvezza di Costituzione CD 13 o restare\navvelenato per 1 ora. Se il tiro salvezza fallisce di 5 o più, il\nbersaglio è anche privo di sensi mentre resta avvelenato in questo\nmodo. Il bersaglio si risveglia se subisce danni o un''altra\ncreatura effettua un''azione per risvegliarlo."}}', '2026-03-30T15:54:05.361Z', '2026-03-30T16:00:32.306Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9lcmlubmkuanNvbg', 'erinni', 'Erinni', 'SRD', 'srd-extracted/erinni.json', '12', 12, 8400, 'Media', 'immondo', 'legale malvagio', '{"slug":"erinni","general":{"name":"Erinni","challengeRating":{"fraction":"12","decimal":12,"display":"12","xp":8400},"size":"Media","creatureType":"immondo","subtype":"diavolo","typeLabel":"immondo (diavolo)","alignment":"legale malvagio","environments":[]},"combat":{"armorClass":{"value":18,"note":"armatura di piastre"},"hitPoints":{"average":153,"formula":"18d8 + 72"},"speed":{"walk":"9 m","fly":"18 m"}},"abilities":{"strength":18,"dexterity":16,"constitution":18,"intelligence":14,"wisdom":14,"charisma":18},"details":{"savingThrows":[{"ability":"Destrezza","bonus":7},{"ability":"Costituzione","bonus":8},{"ability":"Saggezza","bonus":6}],"skills":[],"damageVulnerabilities":[],"damageResistances":["freddo; contundente","perforante e tagliente"],"damageImmunities":["fuoco","veleno"],"conditionImmunities":["avvelenato"],"senses":[{"name":"visione del vero","value":"36 m"},{"name":"Percezione passiva 18"}],"languages":[{"name":"Infernale"},{"name":"telepatia","value":"36 m"}],"proficiencyBonus":4},"traits":[{"name":"Armi Diaboliche","usage":null,"description":"Gli attacchi con arma dell''erinni sono magici e infliggono 13 (3d8) danni da veleno aggiuntivi quando colpiscono (già incluso negli attacchi)."},{"name":"Resistenza alla Magia","usage":null,"description":"L''erinni ha vantaggio ai tiri salvezza contro incantesimi e altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"L''erinni effettua tre attacchi."},{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +8 a colpire, portata 1,5 m, un bersaglio. Colpisce: 8 (1d8 + 4) danni taglienti, o 9 (1d10 + 4) danni taglienti se usata con due mani, più 13 (3d8) danni da veleno."},{"name":"Arco Lungo","usage":null,"description":"Attacco con arma a Distanza: +7 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 7 (1d8 + 4) danni perforanti più 13 (3d8) danni da veleno, e il bersaglio deve riuscire un tiro salvezza di"},{"name":"Costituzione CD 14 o restare avvelenato","usage":null,"description":"Il veleno rimane finché non viene rimosso da un incantesimo ristorazione inferiore o simile."}],"bonusActions":[],"reactions":[{"name":"Parata","usage":null,"description":"L''erinni somma 4 alla sua CA contro un attacco da mischia che lo colpirebbe. Per farlo, l''erinni deve poter vedere il suo attaccante e impugnare un''arma da mischia."}],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Erinni\nMedia immondo (diavolo), legale malvagio\nFORZA 18 (+4)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 18 (+4)\nINTELLIGENZA 14 (+2)\nSAGGEZZA 14 (+2)\nCARISMA 18 (+4)\nClasse Armatura 18 (armatura di piastre)\nPunti Ferita 153 (18d8 + 72)\nVelocità 9 m, volo 18 m\nTiri Salvezza Destrezza +7, Costituzione +8, Saggezza +6,\nCarisma +8\nResistenze al Danno freddo; contundente, perforante e tagliente\ndi attacchi non magici che non siano argentati\nImmunità al Danno fuoco, veleno\nImmunità alle Condizioni avvelenato\nSensi visione del vero 36 m, Percezione passiva 18\nLinguaggi Infernale, telepatia 36 m\nSfida 12 (8.400 PE)\nArmi Diaboliche. Gli attacchi con arma dell''erinni sono magici e\ninfliggono 13 (3d8) danni da veleno aggiuntivi quando\ncolpiscono (già incluso negli attacchi).\nResistenza alla Magia. L''erinni ha vantaggio ai tiri salvezza\ncontro incantesimi e altri effetti magici.\nAzioni\nMultiattacco. L''erinni effettua tre attacchi.\nSpada Lunga. Attacco con arma da mischia: +8 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 8 (1d8 + 4) danni taglienti, o 9 (1d10 + 4) danni\ntaglienti se usata con due mani, più 13 (3d8) danni da veleno.\nArco Lungo. Attacco con arma a Distanza: +7 a colpire, gittata\n45/180 m, un bersaglio.\nColpisce: 7 (1d8 + 4) danni perforanti più 13 (3d8) danni da\nveleno, e il bersaglio deve riuscire un tiro salvezza di\nCostituzione CD 14 o restare avvelenato. Il veleno rimane finché\nnon viene rimosso da un incantesimo ristorazione inferiore o\nsimile.\nReazioni\nParata. L''erinni somma 4 alla sua CA contro un attacco da\nmischia che lo colpirebbe. Per farlo, l''erinni deve poter vedere il\nsuo attaccante e impugnare un''arma da mischia."}}', '2026-03-30T15:54:05.301Z', '2026-03-30T16:00:32.257Z');
