INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zZXJwZW50ZS12b2xhbnRlLmpzb24', 'serpente-volante', 'Serpente Volante', 'SRD', 'srd-extracted/serpente-volante.json', '1/8', 0.125, 25, NULL, NULL, NULL, '{"slug":"serpente-volante","general":{"name":"Serpente Volante","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":14,"note":""},"hitPoints":{"average":5,"formula":"2d4"},"speed":{"walk":"9 m","swim":"9 m","fly":"18 m"}},"abilities":{"strength":4,"dexterity":18,"constitution":11,"intelligence":2,"wisdom":12,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"3 m"},{"name":"Percezione passiva 11"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Sorvolare","usage":null,"description":"Il serpente non provoca attacchi di opportunità quando vola via dalla portata di un nemico."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 1 danno perforante più 7 (3d4) danni da veleno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Serpente Volante\nUn serpente volante è una serpe alata, dai colori\nintensi, rinvenuta in giungle remote.\nMinuscola bestia, disallineato\nFORZA 4 (-3)\nDESTREZZA 18 (+4)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 5 (-3)\nClasse Armatura 14\nPunti Ferita 5 (2d4)\nVelocità 9 m, nuoto 9 m, volo 18 m\nSensi vista cieca 3 m, Percezione passiva 11\nLingue -\nSfida 1/8 (25 PE)\nSorvolare. Il serpente non provoca attacchi di opportunità\nquando vola via dalla portata di un nemico.\nAzioni\nMorso. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 1 danno perforante più 7 (3d4) danni da veleno."}}', '2026-03-30T15:54:05.566Z', '2026-03-30T16:00:32.479Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zcGFkYS12b2xhbnRlLmpzb24', 'spada-volante', 'Spada Volante', 'SRD', 'srd-extracted/spada-volante.json', '1/4', 0.25, 50, 'Piccola', 'costrutto', 'disallineato', '{"slug":"spada-volante","general":{"name":"Spada Volante","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Piccola","creatureType":"costrutto","subtype":"","typeLabel":"costrutto","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":17,"note":"armatura naturale"},"hitPoints":{"average":17,"formula":"5d6"},"speed":{"walk":"0 m","fly":"15 m (fluttua)"}},"abilities":{"strength":12,"dexterity":15,"constitution":11,"intelligence":1,"wisdom":5,"charisma":1},"details":{"savingThrows":[{"ability":"Destrezza","bonus":4}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["psichico","veleno"],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieco oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Falso Aspetto","usage":null,"description":"Mentre l''arma rimane immobile e non sta volando, è indistinguibile da una normale spada."},{"name":"Suscettibilità all''Anti Magia","usage":null,"description":"La spada è inabile se si trova nell''area di un campo anti-magia. Se è bersaglio di dissolvi magie, la spada deve riuscire un tiro salvezza di Costituzione contro la CD del tiro salvezza dell''incantesimo o restare svenuta per 1 minuto."}],"actions":[{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 5 (1d8 + 1) danni taglienti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Spada Volante\nPiccola costrutto, disallineato\nFORZA 12 (+1)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 5 (-3)\nCARISMA 1 (-5)\nClasse Armatura 17 (armatura naturale)\nPunti Ferita 17 (5d6)\nVelocità 0 m, volo 15 m (fluttua)\nTiri Salvezza Destrezza +4\nImmunità al Danno psichico, veleno\nImmunità alle Condizioni accecato, affascinato, assordato,\navvelenato, paralizzato, pietrificato, spaventato\nSensi vista cieca 18 m (cieco oltre questo raggio), Percezione\npassiva 7\nLinguaggi -\nSfida 1/4 (50 PE)\nFalso Aspetto. Mentre l''arma rimane immobile e non sta\nvolando, è indistinguibile da una normale spada.\nSuscettibilità all''Anti Magia. La spada è inabile se si trova\nnell''area di un campo anti-magia. Se è bersaglio di dissolvi\nmagie, la spada deve riuscire un tiro salvezza di Costituzione\ncontro la CD del tiro salvezza dell''incantesimo o restare svenuta\nper 1 minuto.\nAzioni\nSpada Lunga. Attacco con arma da mischia: +3 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 5 (1d8 + 1) danni taglienti."}}', '2026-03-30T15:54:05.439Z', '2026-03-30T16:00:32.363Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zcGlyaXRlbGxvLmpzb24', 'spiritello', 'Spiritello', 'SRD', 'srd-extracted/spiritello.json', '1/4', 0.25, 50, 'Minuscola', 'fatato', 'neutrale buono', '{"slug":"spiritello","general":{"name":"Spiritello","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Minuscola","creatureType":"fatato","subtype":"","typeLabel":"fatato","alignment":"neutrale buono","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura di cuoio"},"hitPoints":{"average":2,"formula":"1d4"},"speed":{"walk":"3 m","fly":"12 m"}},"abilities":{"strength":3,"dexterity":18,"constitution":10,"intelligence":14,"wisdom":13,"charisma":11},"details":{"savingThrows":[],"skills":[{"name":"Furtività +8 (la prova è fatta con svantaggio se lo","bonus":0}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[{"name":"Comune"},{"name":"Elfico"},{"name":"Silvano"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Spada Lunga","usage":null,"description":"Attacco con arma da mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 1 danno tagliente."},{"name":"Arco Corto","usage":null,"description":"Attacco con arma a Distanza: +6 a colpire, gittata 12 m/48 m, un bersaglio. Colpisce: 1 danno perforante. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Costituzione CD 10 o restare avvelenata per 1 minuto. Se il risultato di questo tiro salvezza è 5 o meno, il bersaglio cade privo di sensi per la stessa durata, o finché subisce danni o un''altra creatura usa un''azione per risvegliarlo."},{"name":"Invisibilità","usage":null,"description":"Lo spiritello resta invisibile finché non attacca o termina la sua concentrazione. Qualsiasi cosa che lo spiritello stia trasportando o indossando resta invisibile finché rimane in contatto con lo spiritello."},{"name":"Vista del Cuore","usage":null,"description":"Lo spiritello entra in contatto con una creatura e ne apprende l''attuale stato emotivo. Se il bersaglio fallisce un tiro salvezza di Costituzione CD 10, lo spiritello apprende anche l''allineamento della creatura. Celestiali, immondi e non morti falliscono automaticamente questo tiro salvezza."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Spiritello\nMinuscola fatato, neutrale buono\nFORZA 3 (-4)\nDESTREZZA 18 (+4)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 14 (+2)\nSAGGEZZA 13 (+1)\nCARISMA 11 (+0)\nClasse Armatura 15 (armatura di cuoio)\nPunti Ferita 2 (1d4)\nVelocità 3 m, volo 12 m\nAbilità Furtività +8 (la prova è fatta con svantaggio se lo\nspiritello sta volando), Percezione +3\nSensi Percezione passiva 13\nLinguaggi Comune, Elfico, Silvano\nSfida 1/4 (50 PE)\nAzioni\nSpada Lunga. Attacco con arma da mischia: +2 a colpire,\nportata 1,5 m, un bersaglio.\nColpisce: 1 danno tagliente.\nArco Corto. Attacco con arma a Distanza: +6 a colpire, gittata\n12 m/48 m, un bersaglio.\nColpisce: 1 danno perforante. Se il bersaglio è una creatura, deve\nriuscire un tiro salvezza di Costituzione CD 10 o restare\navvelenata per 1 minuto. Se il risultato di questo tiro salvezza è 5\no meno, il bersaglio cade privo di sensi per la stessa durata, o\nfinché subisce danni o un''altra creatura usa un''azione per\nrisvegliarlo.\nInvisibilità. Lo spiritello resta invisibile finché non attacca o\ntermina la sua concentrazione. Qualsiasi cosa che lo spiritello\nstia trasportando o indossando resta invisibile finché rimane in\ncontatto con lo spiritello.\nVista del Cuore. Lo spiritello entra in contatto con una creatura e\nne apprende l''attuale stato emotivo. Se il bersaglio fallisce un\ntiro salvezza di Costituzione CD 10, lo spiritello apprende anche\nl''allineamento della creatura. Celestiali, immondi e non morti\nfalliscono automaticamente questo tiro salvezza."}}', '2026-03-30T15:54:05.467Z', '2026-03-30T16:00:32.385Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zcXVhbG8tY2FjY2lhdG9yZS5qc29u', 'squalo-cacciatore', 'Squalo Cacciatore', 'SRD', 'srd-extracted/squalo-cacciatore.json', '2', 2, 450, NULL, NULL, NULL, '{"slug":"squalo-cacciatore","general":{"name":"Squalo Cacciatore","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":45,"formula":"6d10 + 12"},"speed":{"walk":"0 m","swim":"12 m"}},"abilities":{"strength":18,"dexterity":13,"constitution":15,"intelligence":1,"wisdom":10,"charisma":4},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"9 m"},{"name":"Percezione passiva 12"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Frenesia Sanguinaria","usage":null,"description":"Lo squalo ha vantaggio ai tiri di attacco in mischia contro qualsiasi creatura che non sia al massimo dei punti ferita."},{"name":"Respirare Acqua","usage":null,"description":"Lo squalo può respirare solo sottacqua."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 13 (2d8 + 4) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Squalo Cacciatore\nUno squalo cacciatore è lungo da 4,5 a 6 metri e di\nsolito caccia in solitario nelle acque più profonde.\nGrande bestia, disallineato\nFORZA 18 (+4)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 10 (+0)\nCARISMA 4 (-3)\nClasse Armatura 12 (armatura naturale)\nPunti Ferita 45 (6d10 + 12)\nVelocità 0 m, nuoto 12 m\nAbilità Percezione +2\nSensi vista cieca 9 m, Percezione passiva 12\nLingue -\nSfida 2 (450 PE)\nFrenesia Sanguinaria. Lo squalo ha vantaggio ai tiri di attacco\nin mischia contro qualsiasi creatura che non sia al massimo dei\npunti ferita.\nRespirare Acqua. Lo squalo può respirare solo sottacqua.\nAzioni\nMorso. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 13 (2d8 + 4) danni perforanti."}}', '2026-03-30T15:54:05.567Z', '2026-03-30T16:00:32.480Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zcXVhbG8tY29yYWxsaW5vLmpzb24', 'squalo-corallino', 'Squalo Corallino', 'SRD', 'srd-extracted/squalo-corallino.json', '1/2', 0.5, 100, NULL, NULL, NULL, '{"slug":"squalo-corallino","general":{"name":"Squalo Corallino","challengeRating":{"fraction":"1/2","decimal":0.5,"display":"1/2","xp":100},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":"armatura naturale"},"hitPoints":{"average":22,"formula":"4d8 + 4"},"speed":{"walk":"0 m","swim":"12 m"}},"abilities":{"strength":14,"dexterity":13,"constitution":13,"intelligence":1,"wisdom":10,"charisma":4},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":2}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"9 m"},{"name":"Percezione passiva 12"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Respirare Acqua","usage":null,"description":"Lo squalo può respirare solo sottacqua."},{"name":"Tattiche di Branco","usage":null,"description":"Lo squalo ha vantaggio al tiro di attacco contro una creatura se almeno uno degli alleati dello squalo si trova entro 1,5 metri dalla creatura e quell''alleato non è inabile."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +4 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Squalo Corallino\nGli squali corallini sono lunghi da 2 a 3 metri e vivono\nnelle acque meno profonde e lungo le barriere coralline.\nMedia bestia, disallineato\nFORZA 14 (+2)\nDESTREZZA 13 (+1)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 10 (+0)\nCARISMA 4 (-3)\nClasse Armatura 12 (armatura naturale)\nPunti Ferita 22 (4d8 + 4)\nVelocità 0 m, nuoto 12 m\nAbilità Percezione +2\nSensi vista cieca 9 m, Percezione passiva 12\nLingue -\nSfida 1/2 (100 PE)\nRespirare Acqua. Lo squalo può respirare solo sottacqua.\nTattiche di Branco. Lo squalo ha vantaggio al tiro di attacco\ncontro una creatura se almeno uno degli alleati dello squalo si\ntrova entro 1,5 metri dalla creatura e quell''alleato non è inabile.\nAzioni\nMorso. Attacco con Arma da Mischia: +4 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (1d8 + 2) danni perforanti."}}', '2026-03-30T15:54:05.569Z', '2026-03-30T16:00:32.480Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zcXVhbG8tZ2lnYW50ZS5qc29u', 'squalo-gigante', 'Squalo Gigante', 'SRD', 'srd-extracted/squalo-gigante.json', '5', 5, 1800, NULL, NULL, NULL, '{"slug":"squalo-gigante","general":{"name":"Squalo Gigante","challengeRating":{"fraction":"5","decimal":5,"display":"5","xp":1800},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":13,"note":"armatura naturale"},"hitPoints":{"average":126,"formula":"11d12 + 55"},"speed":{"walk":"0 m","swim":"15 m"}},"abilities":{"strength":23,"dexterity":11,"constitution":21,"intelligence":1,"wisdom":10,"charisma":5},"details":{"savingThrows":[],"skills":[{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"vista cieca","value":"18 m"},{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":3},"traits":[{"name":"Frenesia Sanguinaria","usage":null,"description":"Lo squalo ha vantaggio ai tiri di attacco in mischia contro qualsiasi creatura che non sia al massimo dei punti ferita."},{"name":"Respirare Acqua","usage":null,"description":"Lo squalo può respirare solo sottacqua."}],"actions":[{"name":"Risucchio di Sangue","usage":null,"description":"Attacco con Arma da Mischia: +5 a colpire, portata 1,5 m, una creatura. Colpisce: 5 (1d4 + 3) danni perforanti e lo strige si attacca al bersaglio. Mentre è attaccato, lo strige non attacca. Invece, all''inizio di ciascun turno dello strige, il bersaglio perde 5 (1d4 + 3) punti ferita a causa della perdita di sangue."},{"name":"Lo strige può staccarsi spendendo 1,5 metri di movimento","usage":null,"description":"Lo fa automaticamente dopo aver risucchiato 10 punti ferita dal bersaglio o alla morte del bersaglio. Una creatura, compreso il bersaglio, può usare la sua azione per staccare lo strige."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Squalo Gigante\nLo squalo gigante è lungo 9 metri e lo si incontra\nnormalmente solo negli oceani più profondi.\nEnorme bestia, disallineato\nFORZA 23 (+6)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 21 (+5)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 10 (+0)\nCARISMA 5 (-3)\nClasse Armatura 13 (armatura naturale)\nPunti Ferita 126 (11d12 + 55)\nVelocità 0 m, nuoto 15 m\nAbilità Percezione +3\nSensi vista cieca 18 m, Percezione passiva 13\nLingue -\nSfida 5 (1.800 PE)\nFrenesia Sanguinaria. Lo squalo ha vantaggio ai tiri di attacco\nin mischia contro qualsiasi creatura che non sia al massimo dei\npunti ferita.\nRespirare Acqua. Lo squalo può respirare solo sottacqua.\nAzioni\nMorso. Attacco con Arma da Mischia: +9 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 22 (3d10 + 6) danni perforanti.\n\n-- 137 of 151 --\n\nSRD Italia 5a Edizione - Compendio dei Mostri\nStrige\nQuesto orrendo mostro sembra un incrocio tra un\ngrosso pipistrello e una zanzara sovradimensionata. Le\nsue zampe terminano in lunghe pinze, e la sua lunga\nproboscide, simile ad un ago, fende l''aria mentre cerca\ndi nutrirsi del sangue delle creature viventi.\nMinuscola bestia, disallineato\nFORZA 4 (-3)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 8 (-1)\nCARISMA 6 (-2)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 2 (1d4)\nVelocità 3 m, volo 12 m\nSensi visione al buio 18 m, Percezione passiva 9\nLingue -\nSfida 1/8 (25 PE)\nAzioni\nRisucchio di Sangue. Attacco con Arma da Mischia: +5 a\ncolpire, portata 1,5 m, una creatura.\nColpisce: 5 (1d4 + 3) danni perforanti e lo strige si attacca al\nbersaglio. Mentre è attaccato, lo strige non attacca. Invece,\nall''inizio di ciascun turno dello strige, il bersaglio perde 5 (1d4 +\n3) punti ferita a causa della perdita di sangue.\nLo strige può staccarsi spendendo 1,5 metri di movimento. Lo fa\nautomaticamente dopo aver risucchiato 10 punti ferita dal\nbersaglio o alla morte del bersaglio. Una creatura, compreso il\nbersaglio, può usare la sua azione per staccare lo strige."}}', '2026-03-30T15:54:05.570Z', '2026-03-30T16:00:32.481Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zdHJpZ2UtdWNjZWxsby1zdGlnZW8uanNvbg', 'strige-uccello-stigeo', 'Strige (Uccello Stigeo)', 'SRD', 'srd-extracted/strige-uccello-stigeo.json', '1/8', 0.125, 25, 'Minuscola', 'bestia', 'disallineato', '{"slug":"strige-uccello-stigeo","general":{"name":"Strige (Uccello Stigeo)","challengeRating":{"fraction":"1/8","decimal":0.125,"display":"1/8","xp":25},"size":"Minuscola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":14,"note":"armatura naturale"},"hitPoints":{"average":2,"formula":"1d4"},"speed":{"walk":"3 m","fly":"12 m"}},"abilities":{"strength":4,"dexterity":16,"constitution":11,"intelligence":2,"wisdom":8,"charisma":6},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 9"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[],"actions":[{"name":"Risucchio di Sangue","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, una creatura. Colpisce: 5 (1d4 + 3) danni perforanti e lo strige si attacca al bersaglio. Mentre è attaccato, lo strige non attacca. Invece, all''inizio di ciascun turno dello strige, il bersaglio perde 5 (1d4 + 3) punti ferita a causa della perdita di sangue."},{"name":"Lo strige può staccarsi spendendo 1,5 metri di movimento","usage":null,"description":"Lo fa automaticamente dopo aver risucchiato 10 punti ferita dal bersaglio o alla morte del bersaglio. Una creatura, compreso il bersaglio, può usare la sua azione per staccare lo strige."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Strige (Uccello Stigeo)\nMinuscola bestia, disallineato\nFORZA 4 (-3)\nDESTREZZA 16 (+3)\nCOSTITUZIONE 11 (+0)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 8 (-1)\nCARISMA 6 (-2)\nClasse Armatura 14 (armatura naturale)\nPunti Ferita 2 (1d4)\nVelocità 3 m, volo 12 m\nSensi scurovisione 18 m, Percezione passiva 9\nLinguaggi -\nSfida 1/8 (25 PE)\nAzioni\nRisucchio di Sangue. Attacco con arma da mischia: +5 a\ncolpire, portata 1,5 m, una creatura.\nColpisce: 5 (1d4 + 3) danni perforanti e lo strige si attacca al\nbersaglio. Mentre è attaccato, lo strige non attacca. Invece,\nall''inizio di ciascun turno dello strige, il bersaglio perde 5 (1d4 +\n3) punti ferita a causa della perdita di sangue.\nLo strige può staccarsi spendendo 1,5 metri di movimento. Lo fa\nautomaticamente dopo aver risucchiato 10 punti ferita dal\nbersaglio o alla morte del bersaglio. Una creatura, compreso il\nbersaglio, può usare la sua azione per staccare lo strige."}}', '2026-03-30T15:54:05.469Z', '2026-03-30T16:00:32.386Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC9zdWNjdWJlLWluY3Viby5qc29u', 'succube-incubo', 'Succube/Incubo', 'SRD', 'srd-extracted/succube-incubo.json', '4', 4, 1100, 'Media', 'immondo', 'neutrale malvagio', '{"slug":"succube-incubo","general":{"name":"Succube/Incubo","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":1100},"size":"Media","creatureType":"immondo","subtype":"mutaforma","typeLabel":"immondo (mutaforma)","alignment":"neutrale malvagio","environments":[]},"combat":{"armorClass":{"value":15,"note":"armatura naturale"},"hitPoints":{"average":66,"formula":"12d8 + 12"},"speed":{"walk":"9 m","fly":"18 m"}},"abilities":{"strength":8,"dexterity":17,"constitution":13,"intelligence":15,"wisdom":12,"charisma":20},"details":{"savingThrows":[],"skills":[{"name":"Furtività 5","bonus":0},{"name":"Intuizione","bonus":5},{"name":"Percezione","bonus":5},{"name":"Persuasione","bonus":0}],"damageVulnerabilities":[],"damageResistances":["freddo","fulmine","fuoco","veleno;"],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 15"}],"languages":[{"name":"Abissale"},{"name":"Comune"},{"name":"Infernale"},{"name":"telepatia","value":"18 m"}],"proficiencyBonus":2},"traits":[{"name":"Legame Telepatico","usage":null,"description":"L''immondo ignora le restrizioni di raggio di azione della sua telepatia quando comunica con una creatura che ha affascinato. I due non sono neppure costretti a trovarsi sullo stesso piano di esistenza."},{"name":"Mutaforma","usage":null,"description":"L''immondo può usare la sua azione per trasformarsi in un umanoide di taglia Piccola o Media, o per tornare alla sua vera forma. Senza le ali, l''immondo perde la velocità di volo. A parte la taglia e la velocità, le sue statistiche sono le stesse in tutte le forme. Qualsiasi equipaggiamento stia indossando o trasportando non viene trasformato. Alla morte ritorna alla sua vera forma."}],"actions":[{"name":"Artiglio","usage":"Solo Forma Immonda","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni taglienti."},{"name":"Affascinare","usage":null,"description":"Un umanoide visibile all''immondo entro 9 metri da esso deve riuscire un tiro salvezza di Saggezza CD 15 o restare magicamente affascinato per 1 giorno. Il bersaglio affascinato obbedisce ai comandi verbali o telepatici dell''immondo. Se il bersaglio subisce danni o riceve un comando suicida, può ripetere il tiro salvezza, terminando l''effetto se lo riesce. Se il bersaglio riesce il tiro salvezza contro l''effetto, o se l''effetto termina, il bersaglio è immune all''Affascinare dell''immondo per le successive 24 ore."},{"name":"L''immondo può tenere affascinato solo un bersaglio alla volta","usage":null,"description":"Se ne affascina un altro, l''effetto sul bersaglio precedente termina."},{"name":"Bacio Risucchiante","usage":null,"description":"L''immondo bacia una creatura affascinata o una creatura consenziente. Il bersaglio deve effettuare un tiro salvezza di Costituzione CD 15 contro questa magia, subendo 32 (5d10 + 5) danni psichici se lo fallisce, o la metà di questi danni se lo riesce. I punti ferita massimi del bersaglio vengono ridotti di un ammontare pari ai danni subiti. Questa riduzione perdura finché il bersaglio non termina un riposo lungo. Il bersaglio muore se questo effetto riduce i suoi punti ferita massimi a 0."},{"name":"Forma Eterea","usage":null,"description":"L''immondo entra magicamente nel Piano Etereo dal Piano Materiale, e viceversa."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Succube/Incubo\nMedia immondo (mutaforma), neutrale malvagio\nFORZA 8 (-1)\nDESTREZZA 17 (+3)\nCOSTITUZIONE 13 (+1)\nINTELLIGENZA 15 (+2)\nSAGGEZZA 12 (+1)\nCARISMA 20 (+5)\nClasse Armatura 15 (armatura naturale)\nPunti Ferita 66 (12d8 + 12)\nVelocità 9 m, volo 18 m\nAbilità Furtività 5, Intuizione +5, Percezione +5, Persuasione\n+9, Raggirare +9\nResistenze al Danno freddo, fulmine, fuoco, veleno;\ncontundente, perforante e tagliente di attacchi non magici\nSensi scurovisione 18 m, Percezione passiva 15\nLinguaggi Abissale, Comune, Infernale, telepatia 18 m\nSfida 4 (1.100 PE)\nLegame Telepatico. L''immondo ignora le restrizioni di raggio di\nazione della sua telepatia quando comunica con una creatura che\nha affascinato. I due non sono neppure costretti a trovarsi sullo\nstesso piano di esistenza.\nMutaforma. L''immondo può usare la sua azione per trasformarsi\nin un umanoide di taglia Piccola o Media, o per tornare alla sua\nvera forma. Senza le ali, l''immondo perde la velocità di volo. A\nparte la taglia e la velocità, le sue statistiche sono le stesse in\ntutte le forme. Qualsiasi equipaggiamento stia indossando o\ntrasportando non viene trasformato. Alla morte ritorna alla sua\nvera forma.\nAzioni\nArtiglio (Solo Forma Immonda). Attacco con arma da mischia:\n+5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni taglienti.\nAffascinare. Un umanoide visibile all''immondo entro 9 metri da\nesso deve riuscire un tiro salvezza di Saggezza CD 15 o restare\nmagicamente affascinato per 1 giorno. Il bersaglio affascinato\nobbedisce ai comandi verbali o telepatici dell''immondo. Se il\nbersaglio subisce danni o riceve un comando suicida, può\nripetere il tiro salvezza, terminando l''effetto se lo riesce. Se il\nbersaglio riesce il tiro salvezza contro l''effetto, o se l''effetto\ntermina, il bersaglio è immune all''Affascinare dell''immondo per\nle successive 24 ore.\nL''immondo può tenere affascinato solo un bersaglio alla volta.\nSe ne affascina un altro, l''effetto sul bersaglio precedente\ntermina.\nBacio Risucchiante. L''immondo bacia una creatura affascinata o\nuna creatura consenziente. Il bersaglio deve effettuare un tiro\nsalvezza di Costituzione CD 15 contro questa magia, subendo 32\n(5d10 + 5) danni psichici se lo fallisce, o la metà di questi danni\nse lo riesce. I punti ferita massimi del bersaglio vengono ridotti\ndi un ammontare pari ai danni subiti. Questa riduzione perdura\nfinché il bersaglio non termina un riposo lungo. Il bersaglio\nmuore se questo effetto riduce i suoi punti ferita massimi a 0.\nForma Eterea. L''immondo entra magicamente nel Piano Etereo\ndal Piano Materiale, e viceversa."}}', '2026-03-30T15:54:05.470Z', '2026-03-30T16:00:32.387Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90YXBwZXRvLWRlbC1zb2Zmb2NhbWVudG8uanNvbg', 'tappeto-del-soffocamento', 'Tappeto del Soffocamento', 'SRD', 'srd-extracted/tappeto-del-soffocamento.json', '2', 2, 450, 'Grande', 'costrutto', 'disallineato', '{"slug":"tappeto-del-soffocamento","general":{"name":"Tappeto del Soffocamento","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"Grande","creatureType":"costrutto","subtype":"","typeLabel":"costrutto","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":33,"formula":"6d10"},"speed":{"walk":"3 m"}},"abilities":{"strength":17,"dexterity":14,"constitution":10,"intelligence":1,"wisdom":3,"charisma":1},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["psichico","veleno"],"conditionImmunities":["accecato","affascinato","assordato"],"senses":[{"name":"vista cieca 18 m (cieco oltre questo raggio)"},{"name":"Percezione"}],"languages":[{"name":"-"}],"proficiencyBonus":2},"traits":[{"name":"Falso Aspetto","usage":null,"description":"Mentre il tappeto resta immobile, è indistinguibile da un normale tappeto."},{"name":"Suscettibilità all''Anti Magia","usage":null,"description":"Il tappeto è inabile mentre si trova nell''area di un campo anti-magia. Se è il bersaglio di dissolvi magie, il tappeto deve riuscire un tiro salvezza di Costituzione contro la CD del tiro salvezza dell''incantatore o cadere privo di sensi per 1 minuto."},{"name":"Trasferimento di Danno","usage":null,"description":"Mentre afferra una creatura, il tappeto subisce solo la metà dei danni che gli sono inferti, e la creatura afferrata dal tappeto subisce l''altra metà."}],"actions":[{"name":"Soffocare","usage":null,"description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, una creatura di taglia Media o inferiore. Colpisce: La creatura è afferrata (CD 13 per fuggire). Fino al termine dell''afferrare, il bersaglio è intralciato, accecato e rischia di soffocare, ma il tappeto non può soffocare un altro bersaglio. Inoltre, all''inizio di ciascun turno del bersaglio, il bersaglio subisce 10 (2d6 + 3) danni contundenti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tappeto del Soffocamento\nGrande costrutto, disallineato\nFORZA 17 (+3)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 10 (+0)\nINTELLIGENZA 1 (-5)\nSAGGEZZA 3 (-4)\nCARISMA 1 (-5)\nClasse Armatura 12\nPunti Ferita 33 (6d10)\nVelocità 3 m\nImmunità al Danno psichico, veleno\nImmunità alle Condizioni accecato, affascinato, assordato,\navvelenato, paralizzato, pietrificato, spaventato\nSensi vista cieca 18 m (cieco oltre questo raggio), Percezione\npassiva 6\nLinguaggi -\nSfida 2 (450 PE)\nFalso Aspetto. Mentre il tappeto resta immobile, è indistinguibile\nda un normale tappeto.\nSuscettibilità all''Anti Magia. Il tappeto è inabile mentre si trova\nnell''area di un campo anti-magia. Se è il bersaglio di dissolvi\nmagie, il tappeto deve riuscire un tiro salvezza di Costituzione\ncontro la CD del tiro salvezza dell''incantatore o cadere privo di\nsensi per 1 minuto.\nTrasferimento di Danno. Mentre afferra una creatura, il tappeto\nsubisce solo la metà dei danni che gli sono inferti, e la creatura\nafferrata dal tappeto subisce l''altra metà.\nAzioni\nSoffocare. Attacco con arma da mischia: +5 a colpire, portata\n1,5 m, una creatura di taglia Media o inferiore.\nColpisce: La creatura è afferrata (CD 13 per fuggire). Fino al\ntermine dell''afferrare, il bersaglio è intralciato, accecato e rischia\ndi soffocare, ma il tappeto non può soffocare un altro bersaglio.\nInoltre, all''inizio di ciascun turno del bersaglio, il bersaglio\nsubisce 10 (2d6 + 3) danni contundenti."}}', '2026-03-30T15:54:05.440Z', '2026-03-30T16:00:32.364Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90YXJyYXNxdWUuanNvbg', 'tarrasque', 'Tarrasque', 'SRD', 'srd-extracted/tarrasque.json', '30', 30, 155000, 'Mastodontica', 'mostruosità', 'disallineato', '{"slug":"tarrasque","general":{"name":"Tarrasque","challengeRating":{"fraction":"30","decimal":30,"display":"30","xp":155000},"size":"Mastodontica","creatureType":"mostruosità","subtype":"titano","typeLabel":"mostruosità (titano)","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":25,"note":"armatura naturale"},"hitPoints":{"average":676,"formula":"33d20 + 330"},"speed":{"walk":"12 m"}},"abilities":{"strength":30,"dexterity":11,"constitution":30,"intelligence":3,"wisdom":11,"charisma":11},"details":{"savingThrows":[{"ability":"Intelligenza","bonus":5},{"ability":"Saggezza","bonus":9},{"ability":"Carisma","bonus":9}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["fuoco","veleno; contundente","perforante e"],"conditionImmunities":["affascinato","avvelenato","paralizzato"],"senses":[{"name":"vista cieca","value":"36 m"},{"name":"Percezione passiva 10"}],"languages":[{"name":"-"}],"proficiencyBonus":9},"traits":[{"name":"Carapace Riflettente","usage":null,"description":"Ogni volta che il tarrasque è il bersaglio di un incantesimo dardo incantato, un incantesimo a linea, o un incantesimo che richiede un tiro di attacco a gittata, tira un d6."},{"name":"Da 1 a 5, il tarrasque lo ignora","usage":null,"description":"Con 6, il tarrasque lo ignora, e l''effetto viene riflesso contro l''incantatore come se fosse originato dal tarrasque, trasformando l''incantatore nel bersaglio."},{"name":"Mostro d''Assedio","usage":null,"description":"Il tarrasque infligge danni doppi agli oggetti e le strutture."},{"name":"Resistenza Leggendaria","usage":"3/Giorno","description":"Se il tarrasque fallisce un tiro salvezza, può scegliere invece di riuscire."},{"name":"Resistenza alla Magia","usage":null,"description":"Il tarrasque ha vantaggio ai tiri salvezza contro incantesimi o altri effetti magici."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il tarrasque può usare la sua Presenza Spaventosa. Poi effettua cinque attacchi: uno con il morso, due con gli artigli, uno con le corna, e uno con la coda. Al posto del morso può usare Inghiottire."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +19 a colpire, portata 4,5 m, un bersaglio. Colpisce: 28 (4d8 + 10) danni taglienti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +19 a colpire, portata 6 m, un bersaglio. Colpisce: 24 (4d6 + 10) danni contundenti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 20 o cadere prona."},{"name":"Corna","usage":null,"description":"Attacco con arma da mischia: +19 a colpire, portata 3 m, un bersaglio. Colpisce: 32 (4d10 + 10) danni perforanti."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +19 a colpire, portata 3 m, un bersaglio. Colpisce: 36 (4d12 + 10) danni perforanti. Se il bersaglio è una creatura, è afferrata (CD 20 per fuggire). Fino al termine dell''afferrare, il bersaglio è intralciato, e il tarrasque non può usare il morso contro un altro bersaglio."},{"name":"Inghiottire","usage":null,"description":"Il tarrasque effettua una attacco di morso contro un bersaglio di taglia Grande o inferiore che sta afferrando. Se l''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha termine. Il bersaglio inghiottito è accecato e intralciato, ha copertura totale contro gli attacchi e altri effetti all''esterno del tarrasque, e subisce 56 (16d6) danni da acido all''inizio di ciascun turno del tarrasque. Se il tarrasque subisce 60 o più danni in un singolo turno da una creatura al suo interno, il tarrasque deve riuscire un tiro salvezza di Costituzione CD 30 al termine di quel turno o vomitare tutte le creature inghiottite, che cadono prone in uno spazio entro 3 metri dal tarrasque. Se il tarrasque muore, una creatura inghiottita non è più intralciata da esso e può uscire dal cadavere utilizzando 9 metri di movimento, uscendo prona."},{"name":"Presenza Spaventosa","usage":null,"description":"Ogni creatura scelta dal tarrasque, che si trovi entro 36 metri da esso e consapevole della sua presenza, deve riuscire un tiro salvezza di Saggezza CD 17 o restare spaventata per 1 minuto. Una creatura può ripetere il tiro salvezza al termine di ciascun suo turno, con svantaggio se il tarrasque è in linea di visuale, terminando l''effetto per sé, se lo riesce. Se il tiro salvezza della creatura ha successo o l''effetto ha termine per essa, la creatura è immune alla Presenza Spaventosa del tarrasque per le successive 24 ore."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"Il tarrasque può effettuare 3 azioni leggendarie, scelte tra le opzioni seguenti. Può usare solo un''opzione leggendaria alla volta e solo al termine del turno di un''altra creatura. Il tarrasque recupera le azioni leggendarie spese all''inizio del proprio turno.","actions":[{"name":"Attacco","description":"Il tarrasque effettua un attacco di artiglio o di coda.","cost":1},{"name":"Masticare","description":"Il tarrasque effettua un attacco di morso o usa Inghiottire.","cost":2},{"name":"Muoversi","description":"Il tarrasque si muove fino a metà della sua velocità.","cost":1}]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tarrasque\nMastodontica mostruosità (titano), disallineato\nFORZA 30 (+10)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 30 (+10)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 11 (+0)\nCARISMA 11 (+0)\nClasse Armatura 25 (armatura naturale)\nPunti Ferita 676 (33d20 + 330)\nVelocità 12 m\nTiri Salvezza Intelligenza +5, Saggezza +9, Carisma +9\nImmunità al Danno fuoco, veleno; contundente, perforante e\ntagliente di attacchi non magici\nImmunità alle Condizioni affascinato, avvelenato, paralizzato,\nspaventato\nSensi vista cieca 36 m, Percezione passiva 10\nLinguaggi -\nSfida 30 (155.000 PE)\nCarapace Riflettente. Ogni volta che il tarrasque è il bersaglio di\nun incantesimo dardo incantato, un incantesimo a linea, o un\nincantesimo che richiede un tiro di attacco a gittata, tira un d6.\nDa 1 a 5, il tarrasque lo ignora. Con 6, il tarrasque lo ignora, e\nl''effetto viene riflesso contro l''incantatore come se fosse\noriginato dal tarrasque, trasformando l''incantatore nel bersaglio.\nMostro d''Assedio. Il tarrasque infligge danni doppi agli oggetti e\nle strutture.\nResistenza Leggendaria (3/Giorno). Se il tarrasque fallisce un\ntiro salvezza, può scegliere invece di riuscire.\nResistenza alla Magia. Il tarrasque ha vantaggio ai tiri salvezza\ncontro incantesimi o altri effetti magici.\nAzioni\nMultiattacco. Il tarrasque può usare la sua Presenza Spaventosa.\nPoi effettua cinque attacchi: uno con il morso, due con gli artigli,\nuno con le corna, e uno con la coda. Al posto del morso può\nusare Inghiottire.\nArtiglio. Attacco con arma da mischia: +19 a colpire, portata 4,5\nm, un bersaglio.\nColpisce: 28 (4d8 + 10) danni taglienti.\nCoda. Attacco con arma da mischia: +19 a colpire, portata 6 m,\nun bersaglio.\nColpisce: 24 (4d6 + 10) danni contundenti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Forza CD 20 o cadere\nprona.\nCorna. Attacco con arma da mischia: +19 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 32 (4d10 + 10) danni perforanti.\nMorso. Attacco con arma da mischia: +19 a colpire, portata 3 m,\nun bersaglio.\nColpisce: 36 (4d12 + 10) danni perforanti. Se il bersaglio è una\ncreatura, è afferrata (CD 20 per fuggire). Fino al termine\ndell''afferrare, il bersaglio è intralciato, e il tarrasque non può\nusare il morso contro un altro bersaglio.\nInghiottire. Il tarrasque effettua una attacco di morso contro un\nbersaglio di taglia Grande o inferiore che sta afferrando. Se\nl''attacco colpisce, il bersaglio è inghiottito, e l''afferrare ha\ntermine. Il bersaglio inghiottito è accecato e intralciato, ha\ncopertura totale contro gli attacchi e altri effetti all''esterno del\ntarrasque, e subisce 56 (16d6) danni da acido all''inizio di ciascun\nturno del tarrasque.\nSe il tarrasque subisce 60 o più danni in un singolo turno da una\ncreatura al suo interno, il tarrasque deve riuscire un tiro salvezza\ndi Costituzione CD 30 al termine di quel turno o vomitare tutte le\ncreature inghiottite, che cadono prone in uno spazio entro 3 metri\ndal tarrasque. Se il tarrasque muore, una creatura inghiottita non\nè più intralciata da esso e può uscire dal cadavere utilizzando 9\nmetri di movimento, uscendo prona.\nPresenza Spaventosa. Ogni creatura scelta dal tarrasque, che si\ntrovi entro 36 metri da esso e consapevole della sua presenza,\ndeve riuscire un tiro salvezza di Saggezza CD 17 o restare\nspaventata per 1 minuto. Una creatura può ripetere il tiro\nsalvezza al termine di ciascun suo turno, con svantaggio se il\ntarrasque è in linea di visuale, terminando l''effetto per sé, se lo\nriesce. Se il tiro salvezza della creatura ha successo o l''effetto ha\ntermine per essa, la creatura è immune alla Presenza Spaventosa\ndel tarrasque per le successive 24 ore.\nAzioni Leggendarie\nIl tarrasque può effettuare 3 azioni leggendarie, scelte tra le\nopzioni seguenti. Può usare solo un''opzione leggendaria alla\nvolta e solo al termine del turno di un''altra creatura. Il tarrasque\nrecupera le azioni leggendarie spese all''inizio del proprio turno.\nAttacco. Il tarrasque effettua un attacco di artiglio o di coda.\nMasticare (Costa 2 Azioni). Il tarrasque effettua un attacco di\nmorso o usa Inghiottire.\nMuoversi. Il tarrasque si muove fino a metà della sua velocità."}}', '2026-03-30T15:54:05.471Z', '2026-03-30T16:00:32.388Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90YXNzby1naWdhbnRlLmpzb24', 'tasso-gigante', 'Tasso Gigante', 'SRD', 'srd-extracted/tasso-gigante.json', '1/4', 0.25, 50, 'Media', 'bestia', 'disallineato', '{"slug":"tasso-gigante","general":{"name":"Tasso Gigante","challengeRating":{"fraction":"1/4","decimal":0.25,"display":"1/4","xp":50},"size":"Media","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":13,"formula":"2d8 + 4"},"speed":{"walk":"9 m","burrow":"3 m"}},"abilities":{"strength":13,"dexterity":10,"constitution":15,"intelligence":2,"wisdom":12,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"9 m"},{"name":"Percezione passiva 11"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Olfatto Affinato","usage":null,"description":"Il tasso ha vantaggio alle prove di Saggezza (Percezione) basate sull''olfatto."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il tasso effettua due attacchi: uno con il morso e uno con gli artigli."},{"name":"Artigli","usage":null,"description":"Attacco con Arma da Mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (2d4 + 1) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +3 a colpire, portata 1,5 m, un bersaglio. Colpisce: 4 (1d6 + 1) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tasso Gigante\nMedia bestia, disallineato\nFORZA 13 (+1)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 5 (-3)\nClasse Armatura 10\nPunti Ferita 13 (2d8 + 4)\nVelocità 9 m, scavo 3 m\nSensi visione al buio 9 m, Percezione passiva 11\nLingue -\nSfida 1/4 (50 PE)\nOlfatto Affinato. Il tasso ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''olfatto.\nAzioni\nMultiattacco. Il tasso effettua due attacchi: uno con il morso e\nuno con gli artigli.\nArtigli. Attacco con Arma da Mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 6 (2d4 + 1) danni taglienti.\nMorso. Attacco con Arma da Mischia: +3 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 4 (1d6 + 1) danni perforanti."}}', '2026-03-30T15:54:05.572Z', '2026-03-30T16:00:32.482Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90YXNzby5qc29u', 'tasso', 'Tasso', 'SRD', 'srd-extracted/tasso.json', '0', 0, 10, 'Minuscola', 'bestia', 'disallineato', '{"slug":"tasso","general":{"name":"Tasso","challengeRating":{"fraction":"0","decimal":0,"display":"0","xp":10},"size":"Minuscola","creatureType":"bestia","subtype":"","typeLabel":"bestia","alignment":"disallineato","environments":[]},"combat":{"armorClass":{"value":10,"note":""},"hitPoints":{"average":3,"formula":"1d4 + 1"},"speed":{"walk":"5 m","burrow":"1"}},"abilities":{"strength":4,"dexterity":11,"constitution":12,"intelligence":2,"wisdom":12,"charisma":5},"details":{"savingThrows":[],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"visione al buio","value":"9 m"},{"name":"Percezione passiva 11"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Olfatto Affinato","usage":null,"description":"Il tasso ha vantaggio alle prove di Saggezza (Percezione) basate sull''olfatto."}],"actions":[{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +2 a colpire, portata 1,5 m, un bersaglio. Colpisce: 1 danno perforante."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tasso\nMinuscola bestia, disallineato\nFORZA 4 (-3)\nDESTREZZA 11 (+0)\nCOSTITUZIONE 12 (+1)\nINTELLIGENZA 2 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 5 (-3)\nClasse Armatura 10\nPunti Ferita 3 (1d4 + 1)\nVelocità 6 m, scavo 1,5 m\nSensi visione al buio 9 m, Percezione passiva 11\nLingue -\nSfida 0 (10 PE)\nOlfatto Affinato. Il tasso ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''olfatto.\nAzioni\nMorso. Attacco con Arma da Mischia: +2 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 1 danno perforante."}}', '2026-03-30T15:54:05.571Z', '2026-03-30T16:00:32.482Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90ZXN0dWdnaW5lLWRyYWdvbmEuanNvbg', 'testuggine-dragona', 'Testuggine Dragona', 'SRD', 'srd-extracted/testuggine-dragona.json', '17', 17, 18000, 'Mastodontica', 'drago', 'neutrale', '{"slug":"testuggine-dragona","general":{"name":"Testuggine Dragona","challengeRating":{"fraction":"17","decimal":17,"display":"17","xp":18000},"size":"Mastodontica","creatureType":"drago","subtype":"","typeLabel":"drago","alignment":"neutrale","environments":[]},"combat":{"armorClass":{"value":20,"note":"armatura naturale"},"hitPoints":{"average":341,"formula":"22d20 + 110"},"speed":{"walk":"6 m","swim":"12 m"}},"abilities":{"strength":25,"dexterity":10,"constitution":20,"intelligence":10,"wisdom":12,"charisma":12},"details":{"savingThrows":[{"ability":"Destrezza","bonus":6},{"ability":"Costituzione","bonus":11},{"ability":"Saggezza","bonus":7}],"skills":[],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 11"}],"languages":[{"name":"Aquan"},{"name":"Draconico"}],"proficiencyBonus":6},"traits":[{"name":"Anfibio","usage":null,"description":"La testuggine dragona può respirare aria e acqua."}],"actions":[{"name":"Multiattacco","usage":null,"description":"Il drago può effettuare tre attacchi: uno con il morso e due con gli artigli. Può effettuare un attacco di coda al posto di due attacchi di artiglio."},{"name":"Artiglio","usage":null,"description":"Attacco con arma da mischia: +13 a colpire, portata 3 m, un bersaglio. Colpisce: 16 (2d8 + 7) danni taglienti."},{"name":"Coda","usage":null,"description":"Attacco con arma da mischia: +13 a colpire, portata 4,5 m, un bersaglio. Colpisce: 26 (3d12 + 7) danni contundenti. Se il bersaglio è una creatura, deve riuscire un tiro salvezza di Forza CD 20 o venire spinta di 3 metri lontano dalla testuggine dragona e cadere prona."},{"name":"Morso","usage":null,"description":"Attacco con arma da mischia: +13 a colpire, portata 4,5 m, un bersaglio. Colpisce: 26 (3d12 + 7) danni perforanti."},{"name":"Soffio di Vapore","usage":"Ricarica 5-6","description":"La testuggine dragona esala un vapore caldo in un cono di 18 metri. Ogni creatura in quell''area deve effettuare un tiro salvezza di Costituzione CD 18 e subire 52 (15d6) danni da fuoco se fallisce il tiro salvezza, o la metà di questi danni se lo riesce. Trovarsi sott''acqua non dà resistenza contro questo tipo di danno."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Testuggine Dragona\nMastodontica drago, neutrale\nFORZA 25 (+7)\nDESTREZZA 10 (+0)\nCOSTITUZIONE 20 (+5)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 12 (+1)\nCARISMA 12 (+1)\nClasse Armatura 20 (armatura naturale)\nPunti Ferita 341 (22d20 + 110)\nVelocità 6 m, nuoto 12 m\nTiri Salvezza Destrezza +6, Costituzione +11, Saggezza +7\nSensi scurovisione 18 m, Percezione passiva 11\nLinguaggi Aquan, Draconico\nSfida 17 (18.000 PE)\nAnfibio. La testuggine dragona può respirare aria e acqua.\nAzioni\nMultiattacco. Il drago può effettuare tre attacchi: uno con il\nmorso e due con gli artigli. Può effettuare un attacco di coda al\nposto di due attacchi di artiglio.\nArtiglio. Attacco con arma da mischia: +13 a colpire, portata 3\nm, un bersaglio.\nColpisce: 16 (2d8 + 7) danni taglienti.\nCoda. Attacco con arma da mischia: +13 a colpire, portata 4,5\nm, un bersaglio.\nColpisce: 26 (3d12 + 7) danni contundenti. Se il bersaglio è una\ncreatura, deve riuscire un tiro salvezza di Forza CD 20 o venire\nspinta di 3 metri lontano dalla testuggine dragona e cadere prona.\nMorso. Attacco con arma da mischia: +13 a colpire, portata 4,5\nm, un bersaglio.\nColpisce: 26 (3d12 + 7) danni perforanti.\nSoffio di Vapore (Ricarica 5-6). La testuggine dragona esala un\nvapore caldo in un cono di 18 metri. Ogni creatura in quell''area\ndeve effettuare un tiro salvezza di Costituzione CD 18 e subire\n52 (15d6) danni da fuoco se fallisce il tiro salvezza, o la metà di\nquesti danni se lo riesce. Trovarsi sott''acqua non dà resistenza\ncontro questo tipo di danno."}}', '2026-03-30T15:54:05.472Z', '2026-03-30T16:00:32.389Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90aWdyZS1kYWktZGVudGktYS1zY2lhYm9sYS5qc29u', 'tigre-dai-denti-a-sciabola', 'Tigre dai Denti a Sciabola', 'SRD', 'srd-extracted/tigre-dai-denti-a-sciabola.json', '2', 2, 450, NULL, NULL, NULL, '{"slug":"tigre-dai-denti-a-sciabola","general":{"name":"Tigre dai Denti a Sciabola","challengeRating":{"fraction":"2","decimal":2,"display":"2","xp":450},"size":"","creatureType":"","subtype":"","typeLabel":"","alignment":"","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":52,"formula":"7d10 + 14"},"speed":{"walk":"12 m"}},"abilities":{"strength":18,"dexterity":14,"constitution":15,"intelligence":3,"wisdom":12,"charisma":8},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":6},{"name":"Percezione","bonus":3}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":[],"conditionImmunities":[],"senses":[{"name":"Percezione passiva 13"}],"languages":[],"proficiencyBonus":2},"traits":[{"name":"Balzo","usage":null,"description":"Se la tigre si muove di almeno 6 metri diretta verso una creatura e la colpisce con un attacco di artiglio durante lo stesso turno, il bersaglio deve riuscire un tiro salvezza di Forza CD 14 o cadere prono. Se il bersaglio è prono, la tigre può effettuare un attacco di morso contro di esso come azione bonus."},{"name":"Olfatto Affinato","usage":null,"description":"La tigre ha vantaggio alle prove di Saggezza (Percezione) basate sull''olfatto."}],"actions":[{"name":"Artiglio","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 12 (2d6 + 5) danni taglienti."},{"name":"Morso","usage":null,"description":"Attacco con Arma da Mischia: +6 a colpire, portata 1,5 m, un bersaglio. Colpisce: 10 (1d10 + 5) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tigre dai Denti a\nSciabola\nGrande bestia, disallineato\nFORZA 18 (+4)\nDESTREZZA 14 (+2)\nCOSTITUZIONE 15 (+2)\nINTELLIGENZA 3 (-4)\nSAGGEZZA 12 (+1)\nCARISMA 8 (-1)\nClasse Armatura 12\nPunti Ferita 52 (7d10 + 14)\nVelocità 12 m\nAbilità Furtività +6, Percezione +3\nSensi Percezione passiva 13\nLingue -\nSfida 2 (450 PE)\nBalzo. Se la tigre si muove di almeno 6 metri diretta verso una\ncreatura e la colpisce con un attacco di artiglio durante lo stesso\nturno, il bersaglio deve riuscire un tiro salvezza di Forza CD 14 o\ncadere prono. Se il bersaglio è prono, la tigre può effettuare un\nattacco di morso contro di esso come azione bonus.\nOlfatto Affinato. La tigre ha vantaggio alle prove di Saggezza\n(Percezione) basate sull''olfatto.\nAzioni\nArtiglio. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 12 (2d6 + 5) danni taglienti.\nMorso. Attacco con Arma da Mischia: +6 a colpire, portata 1,5\nm, un bersaglio.\nColpisce: 10 (1d10 + 5) danni perforanti."}}', '2026-03-30T15:54:05.573Z', '2026-03-30T16:00:32.484Z');
INSERT INTO "Monster" ("id", "slug", "name", "sourceType", "sourceFile", "challengeRatingDisplay", "challengeRatingDecimal", "challengeRatingXp", "size", "creatureType", "alignment", "data", "createdAt", "updatedAt") VALUES ('c3JkLWV4dHJhY3RlZC90aWdyZS1tYW5uYXJhLmpzb24', 'tigre-mannara', 'Tigre Mannara', 'SRD', 'srd-extracted/tigre-mannara.json', '4', 4, 11100, 'Media', 'umanoide (umano', 'mutaforma), neutrale', '{"slug":"tigre-mannara","general":{"name":"Tigre Mannara","challengeRating":{"fraction":"4","decimal":4,"display":"4","xp":11100},"size":"Media","creatureType":"umanoide (umano","subtype":"","typeLabel":"umanoide (umano","alignment":"mutaforma), neutrale","environments":[]},"combat":{"armorClass":{"value":12,"note":""},"hitPoints":{"average":120,"formula":"16d8 + 48"},"speed":{"walk":"9 m (12 m in forma di tigre)"}},"abilities":{"strength":17,"dexterity":15,"constitution":16,"intelligence":10,"wisdom":13,"charisma":11},"details":{"savingThrows":[],"skills":[{"name":"Furtività","bonus":4},{"name":"Percezione","bonus":5}],"damageVulnerabilities":[],"damageResistances":[],"damageImmunities":["contundente","perforante e tagliente di"],"conditionImmunities":[],"senses":[{"name":"scurovisione","value":"18 m"},{"name":"Percezione passiva 15"}],"languages":[{"name":"Comune (non può parlare in forma di tigre)"}],"proficiencyBonus":2},"traits":[{"name":"Balzo","usage":null,"description":"Se la tigre mannara si muove di almeno 4,5 metri in linea retta verso una creatura e la colpisce con un attacco di artiglio durante lo stesso turno, il bersaglio deve riuscire un tiro salvezza di Forza CD 14 o cadere prono. Se il bersaglio è prono, la tigre mannara può effettuare un attacco di morso contro di esso come azione bonus."},{"name":"Mutaforma","usage":null,"description":"La tigre mannara può usare la sua azione per trasformarsi in un ibrido tigre-umanoide o in una tigre, o per tornare alla sua vera forma, che è umanoide. Le sue statistiche, a parte la CA, sono le stesse in tutte le forme. Qualsiasi equipaggiamento stia indossando o trasportando non viene trasformato. Alla morte ritorna alla sua vera forma."},{"name":"Olfatto e Udito Affinato","usage":null,"description":"La tigre mannara ha vantaggio nelle prove di Saggezza (Percezione) basate su olfatto e udito."}],"actions":[{"name":"Multiattacco","usage":"Solo in Forma Umanoide o Ibrida","description":"In forma umanoide, la tigre mannara effettua due attacchi di scimitarra o due attacchi di arco lungo. In forma ibrida, può attaccare come un umanoide o effettuare due attacchi di artiglio."},{"name":"Artiglio","usage":"Soltanto in Forma di Tigre o Ibrida","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 7 (1d8 + 3) danni taglienti."},{"name":"Morso","usage":"Soltanto in Forma di Tigre o Ibrida","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 8 (1d10 + 3) danni perforanti. Se il bersaglio è un umanoide, deve riuscire un tiro salvezza di Costituzione CD 13 o venir maledetto dalla licantropia della tigre mannara."},{"name":"Scimitarra","usage":"Soltanto in Forma Umanoide o Ibrida","description":"Attacco con arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio. Colpisce: 6 (1d6 + 3) danni taglienti."},{"name":"Arco Lungo","usage":"Soltanto in Forma Umanoide o Ibrida","description":"Attacco con arma a Distanza: +4 a colpire, gittata 45/180 m, un bersaglio. Colpisce: 6 (1d8 + 2) danni perforanti."}],"bonusActions":[],"reactions":[],"legendaryActions":{"description":"","actions":[]},"lairActions":[],"regionalEffects":[],"notes":[],"source":{"extractedFrom":"srd05_13_bestiario.pdf","rawText":"Tigre Mannara\nMedia umanoide (umano, mutaforma), neutrale\nFORZA 17 (+3)\nDESTREZZA 15 (+2)\nCOSTITUZIONE 16 (+3)\nINTELLIGENZA 10 (+0)\nSAGGEZZA 13 (+1)\nCARISMA 11 (+0)\nClasse Armatura 12\nPunti Ferita 120 (16d8 + 48)\nVelocità 9 m (12 m in forma di tigre)\nAbilità Furtività +4, Percezione +5\nImmunità al Danno contundente, perforante e tagliente di\nattacchi non magici che non siano argentati\nSensi scurovisione 18 m, Percezione passiva 15\nLinguaggi Comune (non può parlare in forma di tigre)\nSfida 4 (1.1100 PE)\nBalzo. Se la tigre mannara si muove di almeno 4,5 metri in linea\nretta verso una creatura e la colpisce con un attacco di artiglio\ndurante lo stesso turno, il bersaglio deve riuscire un tiro salvezza\ndi Forza CD 14 o cadere prono. Se il bersaglio è prono, la tigre\nmannara può effettuare un attacco di morso contro di esso come\nazione bonus.\nMutaforma. La tigre mannara può usare la sua azione per\ntrasformarsi in un ibrido tigre-umanoide o in una tigre, o per\ntornare alla sua vera forma, che è umanoide. Le sue statistiche, a\nparte la CA, sono le stesse in tutte le forme. Qualsiasi\nequipaggiamento stia indossando o trasportando non viene\ntrasformato. Alla morte ritorna alla sua vera forma.\nOlfatto e Udito Affinato. La tigre mannara ha vantaggio nelle\nprove di Saggezza (Percezione) basate su olfatto e udito.\nAzioni\nMultiattacco (Solo in Forma Umanoide o Ibrida). In forma\numanoide, la tigre mannara effettua due attacchi di scimitarra o\ndue attacchi di arco lungo. In forma ibrida, può attaccare come\nun umanoide o effettuare due attacchi di artiglio.\nArtiglio (Soltanto in Forma di Tigre o Ibrida). Attacco con\narma da mischia: +5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 7 (1d8 + 3) danni taglienti.\nMorso (Soltanto in Forma di Tigre o Ibrida). Attacco con arma\nda mischia: +5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 8 (1d10 + 3) danni perforanti. Se il bersaglio è un\numanoide, deve riuscire un tiro salvezza di Costituzione CD 13 o\nvenir maledetto dalla licantropia della tigre mannara.\nScimitarra (Soltanto in Forma Umanoide o Ibrida). Attacco\ncon arma da mischia: +5 a colpire, portata 1,5 m, un bersaglio.\nColpisce: 6 (1d6 + 3) danni taglienti.\nArco Lungo (Soltanto in Forma Umanoide o Ibrida). Attacco\ncon arma a Distanza: +4 a colpire, gittata 45/180 m, un\nbersaglio.\nColpisce: 6 (1d8 + 2) danni perforanti."}}', '2026-03-30T15:54:05.401Z', '2026-03-30T16:00:32.342Z');
